window.SB_VOCAB26={"words":[{"w":"aback","d":"By surprise; suddenly startled or thrown into confusion, as in 'taken by surprise.'","s":"Sofia was taken aback when her science project won first place, since she had only entered the competition at the last minute.","p":"uh-BAK","o":"Old English","y":3,"bp":46,"m":"abaack","sy":"a.back","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"adverb","r":"Old English on bæc meaning on back","h":"Taken ABACK = knocked BACK by surprise.","t":["wordwords"]},{"w":"abandoned","d":"Left behind or deserted, especially permanently or without intention to return. Can also describe a person or place that has been completely given up.","s":"The explorers stumbled upon an abandoned farmhouse deep in the forest, its broken windows staring out like hollow eyes.","p":"uh-BA-nduhnd","o":"French","y":2,"bp":47,"m":"abondoned","sy":"a.ban.doned","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"verb","r":"Old French abandoner from à bandon meaning at one's discretion","h":"Remember: double-n in abandon stays when you add -ed"},{"w":"abbess","d":"A woman who is the head of a community of nuns in an abbey, holding authority equivalent to that of an abbot over monks.","s":"The abbess rang the bell at dawn, summoning the nuns to morning prayer in the candlelit chapel.","p":"AB-es","o":"Latin","y":3,"bp":51,"m":"abess","sy":"ab.bess","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Late Latin abbatissa, feminine of abbas meaning abbot, from Aramaic abba meaning father","h":"ABBess: double B like the double duties of running an entire abbey","t":["poetry","religion"]},{"w":"abbey","d":"A monastery or convent governed by an abbot or abbess, where monks or nuns live and work. It can also refer to the church or building of such a community.","s":"The ancient abbey on the hillside had stained-glass windows that cast rainbow patterns across the stone floor every morning.","p":"A-bee","o":"French","y":3,"bp":50,"m":"abby","sy":"ab.bey","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old French abeie, from Late Latin abbatia meaning abbot's residence","h":"An ABBEY houses ABBots — both start with ABB","t":["buildings","religion"]},{"w":"abbot","d":"The head or superior of a monastery or abbey of monks, holding authority over the religious community.","s":"The abbot rang the bell at dawn each day to call the monks to morning prayer.","p":"A-buht","o":"Latin","y":3,"bp":50,"m":"abott","sy":"ab.bot","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Late Latin abbas, from Aramaic abba meaning father","h":"An ABBOT leads an ABBEY — both start with ABB","t":["buildings","poetry","religion"]},{"w":"abduct","d":"To take someone away by force or illegally, such as in a kidnapping; also, in anatomy, to move a limb away from the body's midline.","s":"The villain's plot to abduct the young princess was foiled by the brave knights who had been standing guard.","p":"a-BDUHKT","o":"Latin","y":3,"bp":51,"m":"abduckt","sy":"ab.duct","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin abductus, past participle of abducere, from ab- meaning away + ducere meaning to lead","h":"ab- (away) + duct (lead): to lead someone away against their will","t":["body","physics"]},{"w":"abhorrence","d":"A feeling of intense loathing or disgust; extreme repugnance toward something.","s":"She expressed her abhorrence of cruelty to animals by volunteering every weekend at the local animal shelter.","p":"ab-HAWR-uhns","o":"Latin","y":4,"bp":67,"m":"abhorence","sy":"ab.hor.rence","nt":"Senior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin abhorrere meaning to shrink back from, from ab-(away from)+horrere(to bristle, shudder)","h":"AbhorRENCE: remember double R — your body RRrecoils with horRENt disgust.","t":["emotions"]},{"w":"abhorrent","d":"Inspiring disgust and loathing; deeply repugnant or hateful.","s":"The students found the historical practice of child labor abhorrent and wrote passionate essays demanding better protections.","p":"ab-HAWR-uhnt","o":"Latin","y":3,"bp":56,"m":"abhorent","sy":"ab.hor.rent","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin abhorrere meaning to shrink back from, from ab-(away from)+horrere(to bristle, shudder)","h":"AbhorRENT: double R — that horRENT idea is so bad it makes you shudder."},{"w":"abidance","d":"The act of complying with or accepting a rule, decision, or recommendation; the state of continuing to stay in a place.","s":"The principal stressed the importance of abidance with the school's code of conduct during the assembly.","p":"uh-BEYE-dunss","o":"Old English","y":4,"bp":61,"m":"abidance","sy":"a.bid.ance","nt":"Senior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old English abidan meaning to wait or remain","h":"ABIDE + -ANCE: the quality of abiding by the rules","vh":"An act of"},{"w":"abolition","d":"the act of abolishing a system or practice or institution (especially abolishing slavery)","s":"The abolition of capital punishment.","p":"a-buh-LIH-shuhn","o":"Latin","y":3,"bp":34,"m":"abollition","sy":"ae.bah.lih.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin abolitio = destruction, annulment","h":"ABOLITION has one L — the movement to END slavery doesn't double up: a-bo-LI-tion."},{"w":"aborigines","d":"an indigenous person who was born in a particular place","p":"a-ber-IH-juh-neez","o":"Latin","y":3,"bp":37,"m":"aboriginies","sy":"ae.ber.ih.jhah.niy.z","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin ab origine = from the beginning","h":"Aborigines — drop the 'e' from aborigine and add '-es': aboriginal people don't need a silent 'i' sneaking in before the 's.'"},{"w":"abridgment","d":"a shortened form of a book","s":"The teacher assigned an abridgment of the lengthy novel so students could finish it over the weekend.","p":"uh-BRIJ-ment","o":"Latin","y":4,"bp":70,"m":"abridgement","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old French abregier = to shorten","h":"An abridgMENT needs no extra 'e' — it's already been shortened, just like the word!"},{"w":"absorption","d":"(chemistry) a process in which one substance permeates another; a fluid permeates or is dissolved by a liquid or solid","s":"The absorption of photons by atoms or molecules.","p":"uh-BZAW-rpshuhn","o":"Latin","y":3,"bp":34,"m":"absorbtion","sy":"ah.bzao.rpshah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin absorptionem = a swallowing up","h":"AbsorPTion — there's no 'b' before the 't'; the 'b' was absorbed away: a-b-s-o-r-p-t-i-o-n.","t":["chemistry"]},{"w":"abundance","d":"the property of a more than adequate quantity or supply","s":"After the heavy rains, the garden produced an abundance of tomatoes, zucchini, and fresh herbs.","p":"uh-BUH-nduhns","o":"Latin","y":3,"bp":47,"sy":"ah.bah.ndah.ns","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin 'abundantia' = fullness, from 'abundare' = to overflow, from 'ab-' = away + 'unda' = wave","h":"ABUNDANCE — A BUND-ance, like a dam BUND-le overflowing with water"},{"w":"academy","d":"a secondary school (usually private)","s":"She earned a scholarship to attend the prestigious academy known for its rigorous science and mathematics programs.","p":"uh-KA-duh-mee","o":"French","y":3,"bp":74,"m":"accademy","sy":"ah.kae.dah.miy","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek Akademeia = grove near Athens where Plato taught, named for hero Akademos","h":"ACADEMY has one 'c' and one 'a' at the start — Plato's grove had ONE entrance, not two.","vh":"Institution of"},{"w":"accept","d":"to agree to take something offered, or to say yes to it","s":"Maya was proud to accept the first-place medal at the science fair.","p":"ak-SEPT","o":"Latin","y":2,"bp":60,"ps":"verb","r":"Latin 'accipere' (to take to oneself), from ad- + capere (to take).","h":"When you accept a gift, you take it and say yes.","nt":"vocab-NWFinal-2026-Junior"},{"w":"accomplice","d":"a person who joins with another in carrying out some plan, especially an unethical or illegal plan","s":"The police discovered that the thief's accomplice had been waiting in the getaway car around the corner.","p":"uh-KAH-mpluhs","o":"French","y":3,"bp":34,"m":"accomplise","sy":"ac.com.plice","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin complex = partner, confederate, from com- + plicare = to fold","h":"An accomplice COMPLETES the crime with someone"},{"w":"account","d":"a written or spoken report of something that happened","s":"Grandpa gave us a funny account of his first day of school.","p":"uh-KOWNT","o":"French","y":2,"bp":60,"ps":"noun","r":"Old French 'aconter' (to count up, tell), from Latin computare.","h":"An account 'counts up' the details of a story or event.","nt":"vocab-NWFinal-2026-Junior"},{"w":"accumulate","d":"get or gather together; collect or amass over time","s":"Over years of exploring the beach, she managed to accumulate hundreds of unique shells in large glass jars.","p":"uh-KYOO-myuh-layt","o":"Latin","y":3,"bp":35,"m":"accumalate","sy":"ac.cu.mu.late","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin accumulare = to heap up, from cumulus = heap","h":"ACCUMULate — think ACCUMULATE a CUMULUS cloud of stuff","t":["time"]},{"w":"accuracy","d":"the quality of being near to the true value","s":"He was beginning to doubt the accuracy of his compass.","p":"A-kyer-uh-see","o":"Latin","y":3,"bp":33,"m":"accurasy","sy":"ae.kyer.ah.siy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin accuratus = done with care, from cura = care","h":"ACCURacy — it takes CARE (cur) to spell it with double-c and end in -acy, not -asy."},{"w":"acknowledgment","d":"the state or quality of being recognized or acknowledged","p":"a-KNAH-lih-jmuhnt","o":"Latin","y":3,"bp":38,"m":"acknowledgement","sy":"ae.knaa.lih.jhmah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old English oncnawan = to know","h":"American acknowledgment drops the E — Americans are efficient, dropping letters to save time!"},{"w":"acquire","d":"to get or gain something as your own","s":"Over the summer, Ravi worked hard to acquire strong swimming skills.","p":"uh-KWYR","o":"Latin","y":3,"bp":65,"ps":"verb","r":"Latin 'acquirere' (to add to), from ad- + quaerere (to seek).","h":"To acquire is to seek and get something for yourself.","nt":"vocab-NWFinal-2026-Junior"},{"w":"acreage","d":"a quantity of land measured in acres","s":"The farmer bought more acreage so he could plant extra corn.","p":"AY-kur-ij","o":"Old English","y":3,"bp":65,"ps":"noun","r":"Old English 'aecer' (field) plus the amount-suffix -age.","h":"Acre + age = the amount of land in acres.","nt":"vocab-NWFinal-2026-Junior","vh":"A quantity of"},{"w":"acute","d":"sharp or severe; also very quick to notice things","s":"Her acute hearing let her catch the whisper from across the room.","p":"uh-KYOOT","o":"Latin","y":3,"bp":70,"ps":"adjective","r":"Latin 'acutus' (sharpened), from acuere (to sharpen).","h":"Acute means sharp, like a sharply pointed acute angle.","nt":"vocab-NWFinal-2026-Junior"},{"w":"adage","d":"an old familiar saying that expresses a common truth","s":"\"Practice makes perfect\" is an adage our coach repeats before every game.","p":"AD-ij","o":"Latin","y":3,"bp":70,"ps":"noun","r":"Latin 'adagium' (proverb, saying).","h":"An adage is an aged saying everyone knows.","nt":"vocab-NWFinal-2026-Junior"},{"w":"addendum","d":"textual matter that is added onto a publication; usually at the end","s":"The author included an addendum at the back of the book to address new discoveries made after publication.","p":"uh-DEH-nduhm","o":"Latin","y":3,"bp":32,"m":"addendeum","sy":"ah.deh.dah.m","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin addendum = thing that must be added","h":"An ADDENDUM is something you ADD at the end — ADD+END+UM, like saying 'um, I forgot to add this!'"},{"w":"addicted","d":"unable to stop doing or using something","s":"Dad joked that he is addicted to his morning crossword puzzle.","p":"uh-DIK-tid","o":"Latin","y":2,"bp":60,"ps":"adjective","r":"Latin 'addicere' (to give over, devote), from ad- + dicere (to say).","h":"Addicted means hooked so you can't quit.","nt":"vocab-NWFinal-2026-Junior"},{"w":"adept","d":"very skilled or expert at something","s":"Priya is adept at solving Rubik's cubes in under a minute.","p":"uh-DEPT","o":"Latin","y":3,"bp":70,"ps":"adjective","r":"Latin 'adeptus' (having attained), from adipisci (to attain).","h":"An adept person has attained real skill.","nt":"vocab-NWFinal-2026-Junior"},{"w":"admissible","d":"deserving to be admitted","s":"The defense lawyer argued passionately that the recorded conversation was not admissible in court because it had been obtained without the proper legal permission required by state law.","p":"uh-DMIH-suh-buhl","o":"French","y":3,"bp":35,"m":"admissable","sy":"ah.dmih.sah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin admittere = to let in (missus = sent)","h":"Is the evidence adMISSIBLE? It must MISS no rule — spell it with IBLE, not ABLE, in court.","vh":"Having the right to"},{"w":"adoration","d":"a feeling of profound love and admiration","s":"The crowd's adoration for the legendary musician was evident as they cheered and waved throughout the entire concert.","p":"a-der-AY-shuhn","o":"French","y":3,"bp":34,"m":"adorration","sy":"ae.der.ey.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin adoratio = worship, reverence","h":"Adoration has one R — you ADORE with one heart, one R: ador-ation.","t":["emotions"]},{"w":"adulterant","d":"a substance added to something to make it impure or lower quality","s":"The lab tested the milk for any adulterant like added water.","p":"uh-DUL-tur-uhnt","o":"Latin","y":4,"bp":75,"ps":"noun","r":"Latin 'adulterare' (to corrupt, make impure).","h":"An adulterant is the sneaky extra that spoils the pure thing.","nt":"vocab-NWFinal-2026-Junior"},{"w":"aggrieved","d":"feeling hurt, wronged, or treated unfairly","s":"Sam felt aggrieved when the referee missed the foul against him.","p":"uh-GREEVD","o":"French","y":3,"bp":70,"ps":"adjective","r":"Old French 'agrever' (to burden), from Latin gravis (heavy).","h":"Aggrieved people carry a grievance, a heavy hurt feeling.","nt":"vocab-NWFinal-2026-Junior"},{"w":"agile","d":"able to move quickly and easily","s":"The agile gymnast flipped across the mat without a single wobble.","p":"AJ-uhl","o":"Latin","y":2,"bp":65,"ps":"adjective","r":"Latin 'agilis' (nimble), from agere (to move, do).","h":"Agile animals like squirrels dart and leap with ease.","nt":"vocab-NWFinal-2026-Junior"},{"w":"agitate","d":"to shake up, or to make someone upset and disturbed","s":"Please don't agitate the bees' nest with that stick.","p":"AJ-ih-tayt","o":"Latin","y":3,"bp":70,"ps":"verb","r":"Latin 'agitare' (to set in motion), from agere (to drive).","h":"Agitate means to stir things up, like a washing machine.","nt":"vocab-NWFinal-2026-Junior"},{"w":"agnostic","d":"someone who is doubtful or noncommittal about something","s":"My uncle describes himself as an agnostic because he believes it is impossible to know for certain whether any god exists.","p":"a-GNAH-stihk","o":"Greek","y":3,"bp":32,"m":"agknnostic","sy":"ae.gnaa.stih.k","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek agnostos = unknown, from a-(not)+gnostos(known)","h":"An AGNOSTIC is 'a' person who does 'NOT' claim to KNOW — silent 'g' like in 'gnosis.'","t":["character"],"vh":"one who"},{"w":"akin","d":"similar to something, or related by family","s":"Her excitement before the bee was akin to the thrill of a rollercoaster.","p":"uh-KIN","o":"Old English","y":3,"bp":70,"ps":"adjective","r":"From 'of kin' — Old English 'cynn' (family, kind).","h":"Akin means 'of kin' — like family, closely alike.","nt":"vocab-NWFinal-2026-Junior"},{"w":"album","d":"a book for keeping photos or stamps, or a collection of songs","s":"Mom filled a whole album with pictures from our beach trip.","p":"AL-buhm","o":"Latin","y":2,"bp":60,"ps":"noun","r":"Latin 'albus' (white) — originally a blank white tablet for lists.","h":"An album starts as blank white pages you fill with keepsakes.","nt":"vocab-NWFinal-2026-Junior"},{"w":"alcoholism","d":"habitual intoxication; prolonged and excessive intake of alcoholic drinks leading to a breakdown in health and an addiction to alcohol such that abrupt deprivation leads to severe withdrawal symptoms","s":"The counselor explained that alcoholism is a serious illness that requires medical treatment, not just willpower.","p":"A-lkuh-haw-lih-zuhm","o":"Arabic","y":2,"bp":45,"m":"alcaholism","sy":"ae.lkah.hhao.lih.zah.m","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Arabic al-kuhul = distilled spirit + Greek -ismos = condition","h":"ALCOHOLISM contains the full word ALCOHOL — spell that first, then add -ISM.","t":["disease"]},{"w":"alert","d":"watchful and quick to notice; ready for danger","s":"The crossing guard stays alert as students hurry across the street.","p":"uh-LURT","o":"Italian","y":2,"bp":60,"ps":"adjective","r":"Italian 'all'erta' (on the watchtower, on the lookout).","h":"Alert soldiers stood on the watchtower, eyes wide open.","nt":"vocab-NWFinal-2026-Junior"},{"w":"alien","d":"belonging to another country or place; foreign or strange","s":"Snow was completely alien to my cousin who grew up in Chennai.","p":"AY-lee-uhn","o":"Latin","y":2,"bp":65,"ps":"adjective","r":"Latin 'alienus' (belonging to another), from alius (other).","h":"Alien means from another place — foreign and unfamiliar.","nt":"vocab-NWFinal-2026-Junior"},{"w":"alienable","d":"transferable to another owner","s":"The lawyer confirmed that the land was alienable and could be legally sold to anyone.","p":"AY-lee-uh-nuh-bul","o":"Latin","y":3,"bp":34,"m":"alienible","sy":"al.ien.a.ble","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin alienus = belonging to another","h":"ALIENABLE property can be transferred to an ALIEN — ALIEN+ABLE, simply join the two familiar words."},{"w":"alienation","d":"the feeling of being alienated from other people","s":"The power of alienation is an essential ingredient of ownership.","p":"ay-lee-uh-NAY-shuhn","o":"French","y":3,"bp":37,"m":"alieniation","sy":"ey.liy.ah.ney.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin alienus = belonging to another","h":"ALIENation: even an ALIEN feels isolated and estranged.","t":["emotions"]},{"w":"allege","d":"to claim something is true without giving proof yet","s":"The players allege that the other team broke the rules, but no one saw it.","p":"uh-LEJ","o":"French","y":3,"bp":75,"ps":"verb","r":"Old French 'alegier', influenced by Latin 'allegare' (to bring forward).","h":"To allege is to say it happened — proof still needed.","nt":"vocab-NWFinal-2026-Junior"},{"w":"alliance","d":"the state of being allied or confederated","s":"The shifting alliances within a large family.","p":"uh-LEYE-uhns","o":"French","y":2,"bp":44,"m":"allience","sy":"ah.lay.ah.ns","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"French allier = to bind, from Latin alligare = to bind together","h":"An ALLIANCE needs an 'A' team — remember a-l-l-i-ANCE, not 'ience'."},{"w":"allotment","d":"a share set aside for a specific purpose","p":"uh-LAH-tmuhnt","o":"French","y":3,"bp":33,"m":"alotment","sy":"ah.laa.tmah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"French lotir = to divide into lots","h":"ALL OT(her) MENT(ors) got an allotment — remember double-L and double-T."},{"w":"almanac","d":"an annual publication including weather forecasts and other miscellaneous information arranged according to the calendar of a given year","s":"Farmer Greta checked the almanac every January to plan which crops to plant each month.","p":"AH-lmuh-nak","o":"French","y":2,"bp":43,"m":"almanack","sy":"ao.lmah.nae.k","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Arabic al-manakh = the calendar/climate","h":"AL-MA-NAC: 'ALL MAN needs A Calendar' — an almanac tells everyone the dates.","t":["weather","time"]},{"w":"alteration","d":"an event that occurs when something passes from one state or phase to another","p":"aw-lter-AY-shuhn","o":"French","y":3,"bp":35,"m":"alterasion","sy":"ao.lter.ey.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin alteratio = a changing, from alterare = to change","h":"An ALTERATION at the tailor uses ALTER + ATION — the tailor alters your suit with '-ation' precision."},{"w":"alternate","d":"someone who takes the place of another person","s":"When the lead actress fell ill, her alternate stepped onto the stage and delivered a stunning performance.","p":"AW-lter-nuht","o":"Latin","y":3,"bp":33,"m":"alternete","sy":"ao.lter.nah.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin alternatus = done by turns, from alternus = every other","h":"ALTERNATE has an '-ate' ending — the altern-ATE person took turns eating the last slice.","vh":"One chosen"},{"w":"amateur","d":"someone who pursues a study or sport as a pastime","s":"Although he was just an amateur photographer who had only owned his camera for a year, his stunning nature shots won first place at the regional art competition.","p":"A-muh-tur","o":"French","y":2,"bp":43,"m":"amature","sy":"ae.mah.ter","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin amator = lover, from amare = to love","h":"An amateur does it for LOVE — the word ends in -EUR (French for 'one who'), not -URE; think 'amat-EUR' loves it.","t":["sports"]},{"w":"ambitious","d":"having a strong desire and determination to succeed; requiring exceptional effort or ability","s":"Maya was so ambitious that she signed up for three advanced classes, joined the debate team, and started her own tutoring business all in the same semester.","p":"a-MBIH-shuhs","o":"Latin","y":2,"bp":37,"sy":"ae.mbih.shah.s","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin 'ambitiosus' = ambi (around) + ire (to go) — referring to Roman candidates canvassing for votes","h":"amBITious people bite off big goals — BIT is right in the middle"},{"w":"amoral","d":"having no sense of right and wrong","s":"The story's amoral robot followed orders without caring who got hurt.","p":"ay-MOR-uhl","o":"Latin","y":4,"bp":75,"ps":"adjective","r":"Greek prefix a- (without) + Latin 'moralis' (relating to right conduct).","h":"A-moral = without morals, no inner compass at all.","nt":"vocab-NWFinal-2026-Junior"},{"w":"amphibious","d":"relating to or characteristic of animals of the class Amphibia","s":"The amphibious vehicle smoothly transitioned from rolling along the muddy riverbank to gliding across the water's surface, impressing the soldiers who had never before seen a machine capable of handling both terrains so effortlessly.","p":"a-MFIH-bee-uhs","o":"Greek","y":3,"bp":35,"m":"amphibeous","sy":"ae.mfih.biy.ah.s","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Greek amphibios = living a double life, from amphi = both + bios = life","h":"AMPHIBIOUS: 'amphi-bi-ous' — the 'bi' means TWO (like bicycle), because amphibians live in TWO worlds; no 'e' before '-ous'.","t":["animals"]},{"w":"ample","d":"more than enough in size or scope or capacity","s":"Had ample food for the party.","p":"A-mpuhl","o":"French","y":3,"bp":69,"m":"ampel","sy":"ae.mpah.l","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin amplus = large, abundant","h":"AMPLE ends in -PLE like PLENTIFUL — there's PLENTY when something is AMPLE."},{"w":"amputate","d":"remove surgically","s":"When the surgeon explained she might need to amputate the badly infected finger to prevent the infection from spreading further, the patient took a deep breath and asked every question she had.","p":"A-mpyuh-tayt","o":"Latin","y":3,"bp":32,"m":"amputait","sy":"ae.mpyah.tey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin amputare = to cut around, from am-(around)+putare(to prune)","h":"AmPUTATE — you PUT the saw around the limb: am-PUT-ate, cut it clean.","t":["body"]},{"w":"analyst","d":"a person who studies something carefully to understand or explain it","s":"The sports analyst explained why our team keeps winning.","p":"AN-uh-list","o":"Greek","y":3,"bp":70,"ps":"noun","r":"Greek 'analyein' (to break up, loosen apart).","h":"An analyst breaks a problem into pieces to study it.","nt":"vocab-NWFinal-2026-Junior"},{"w":"anglo-saxon","d":"relating to the early Germanic people of England or their old language","s":"Our teacher said many everyday English words come from Anglo-Saxon times.","p":"ang-gloh-SAK-suhn","o":"Latin","y":3,"bp":65,"ps":"adjective","r":"Latin 'Anglo-Saxones' — the Angles and Saxons who settled England.","h":"Angles + Saxons = the tribes who started Old English.","nt":"vocab-NWFinal-2026-Junior"},{"w":"anguish","d":"extreme pain or suffering of body or mind","s":"She cried in anguish when her sandcastle washed away before the judging.","p":"ANG-gwish","o":"French","y":3,"bp":75,"ps":"noun","r":"Old French 'anguisse', from Latin 'angustia' (tightness, distress).","h":"Anguish squeezes you tight with terrible pain or grief.","nt":"vocab-NWFinal-2026-Junior"},{"w":"annotate","d":"add explanatory notes to or supply with critical comments","s":"The scholar annotated the early edition of a famous novel.","p":"A-nuh-tayt","o":"Latin","y":3,"bp":32,"m":"anotate","sy":"ae.nah.tey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin nota = mark, note","h":"ANNOtate has double-n — you add NOTES (nota) again and again, so double the 'n'."},{"w":"antibody","d":"any of a large variety of proteins normally present in the body or produced in response to an antigen which it neutralizes, thus producing an immune response","s":"When you recover from a virus, your immune system creates an antibody that helps protect you from getting sick again.","p":"A-ntih-bah-dee","o":"Greek","y":3,"bp":33,"m":"antibodi","sy":"ae.ntih.baa.diy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek anti = against + Old English bodig = body","h":"ANTI + BODY = antibody — a tiny body sent AGAINST a germ; picture a mini wrestler (body) fighting antigens."},{"w":"antic","d":"a playful, silly, or funny act; a prank","s":"The puppy's latest antic was hiding everyone's socks under the couch.","p":"AN-tik","o":"Italian","y":3,"bp":70,"ps":"noun","r":"Italian 'antico' (ancient) — from odd figures in old Roman art.","h":"Antics are the goofy stunts a class clown pulls.","nt":"vocab-NWFinal-2026-Junior"},{"w":"anticipate","d":"regard something as probable or likely","p":"a-NTIH-suh-payt","o":"Latin","y":3,"bp":35,"m":"anticapate","sy":"ae.ntih.sah.pey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin anticipare = to take before (ante=before + capere=take)","h":"ANTIcipate: the ANTI comes BEFORE the action — just like you anticipate what comes BEFORE it happens."},{"w":"apology","d":"an expression of regret at having caused trouble for someone","s":"Marcus offered a sincere apology to his teammate after accidentally knocking him down during practice.","p":"uh-PAH-luh-jee","o":"French","y":2,"bp":80,"sy":"ah.paa.lah.jhiy","nt":"Primary | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek 'apologia' = a speech in defense, from 'apo-' = away + 'logos' = speech","h":"aPOLogy — say SORRY, it's POLite","vh":"Disclaimer of"},{"w":"appall","d":"to shock someone or fill them with horror and dismay","s":"The mess in the cafeteria seemed to appall the principal.","p":"uh-PAWL","o":"French","y":3,"bp":75,"ps":"verb","r":"Old French 'apalir' (to grow pale).","h":"Something appalling makes your face go pale with shock.","nt":"vocab-NWFinal-2026-Junior"},{"w":"archives","d":"collection of records especially about an institution","s":"The historian spent weeks in the city archives, searching through dusty documents to trace the town's founding.","p":"AH-rkeyevz","o":"Greek","y":3,"bp":46,"sy":"aa.rkay.vz","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek 'archeion' = public records office, from 'arche' = government/beginning","h":"ARCH-ives — old records stored under an arch"},{"w":"arid","d":"extremely dry, getting very little rain","s":"Cactuses thrive in the arid desert where rain almost never falls.","p":"AIR-id","o":"Latin","y":3,"bp":75,"ps":"adjective","r":"Latin 'aridus' (dry), from arere (to be dry).","h":"Arid land is parched — think dusty desert sand.","nt":"vocab-NWFinal-2026-Junior"},{"w":"armory","d":"a place where weapons and military equipment are stored","s":"On the field trip, we saw shining swords in the castle's armory.","p":"AR-muh-ree","o":"French","y":3,"bp":70,"ps":"noun","r":"Old French 'armoierie', from Latin 'arma' (weapons).","h":"An armory is the arms room — where weapons wait.","nt":"vocab-NWFinal-2026-Junior"},{"w":"aromatic","d":"(chemistry) of or relating to or containing one or more benzene rings","s":"An aromatic organic compound.","p":"eh-ruh-MA-tihk","o":"French","y":3,"bp":74,"m":"arromatic","sy":"eh.rah.mae.tih.k","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Greek aromatikos = fragrant, from aroma = spice","h":"AROMATIC contains AROMA — smell the AROMA in AROMATIC, one R only.","t":["chemistry"]},{"w":"arrange","d":"put into a proper or systematic order","p":"er-AYNJ","o":"French","y":2,"bp":32,"sy":"er.ey.njh","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"verb","r":"Old French 'arangier' = to put in a row, from 'a-' (to) + 'rangier' = to put in a line","h":"ARRANGE has double R and double A — two of each to keep things in order"},{"w":"arrangement","d":"the thing arranged or agreed to","s":"They made arrangements to meet in Chicago.","p":"er-AY-njmuhnt","o":"French","y":3,"bp":34,"m":"arrangment","sy":"er.ey.njhmah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old French arangier = to put in a row (rang = rank, row)","h":"ARRANGEMENT — don't forget the 'e' before -ment: arrang-E-ment, because every arrangement needs its place."},{"w":"array","d":"an orderly arrangement or impressive display of things","s":"The bake sale table held an array of cookies, cupcakes, and pies.","p":"uh-RAY","o":"French","y":3,"bp":70,"ps":"noun","r":"Old French 'areer' (to arrange, put in order).","h":"An array is a neat, eye-catching lineup of things.","nt":"vocab-NWFinal-2026-Junior"},{"w":"arrest","d":"to stop something, or to take someone into custody by law","s":"The police officer had to arrest the man who stole the bikes.","p":"uh-REST","o":"French","y":2,"bp":60,"ps":"verb","r":"Old French 'arester' (to stop), from Latin restare (to stay back).","h":"Arrest brings things to a rest — a full stop.","nt":"vocab-NWFinal-2026-Junior"},{"w":"arresting","d":"take into custody","p":"er-EH-stihng","o":"French","y":3,"bp":33,"m":"aresting","sy":"er.eh.stih.ng","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Old French arester = to stop","h":"Something ARRESTING grabs your attention and makes it REST — see REST inside, with double-r in front."},{"w":"arrogance","d":"overbearing pride evidenced by a superior manner toward inferiors","s":"The new student's arrogance quickly made him unpopular, as he constantly bragged about his achievements.","p":"EH-ruh-guhns","o":"Latin","y":3,"bp":33,"m":"arrogence","sy":"eh.rah.gah.ns","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin arrogare = to claim for oneself, from ad+rogare = to ask","h":"Arrogance ends in -ANCE — the arrogant person ANCE-serts themselves with two R's up front."},{"w":"artful","d":"clever or skillful, sometimes in a sly or crafty way","s":"With an artful excuse, the fox in the fable escaped trouble again.","p":"ART-fuhl","o":"English","y":3,"bp":70,"ps":"adjective","r":"English 'art' (skill, from Latin 'ars') + -ful (full of).","h":"Artful means full of clever art — skilled, maybe sneaky.","nt":"vocab-NWFinal-2026-Junior"},{"w":"askew","d":"crooked or tilted; not straight or level","s":"After the windy walk, his cap sat askew on his head.","p":"uh-SKYOO","o":"French","y":3,"bp":75,"ps":"adverb","r":"a- + 'skew', from Old North French 'eskiuer' (to swerve, avoid).","h":"Askew means skewed sideways — like a crooked picture frame.","nt":"vocab-NWFinal-2026-Junior"},{"w":"aspire","d":"to aim for or strongly hope to achieve something great","s":"Anika aspires to win the national vocabulary bee next year.","p":"uh-SPYR","o":"Latin","y":3,"bp":75,"ps":"verb","r":"Latin 'aspirare' (to breathe toward), from ad- + spirare (to breathe).","h":"To aspire is to breathe toward a big dream.","nt":"vocab-NWFinal-2026-Junior"},{"w":"assert","d":"to state something firmly and confidently","s":"Leo raised his hand to assert that his answer was correct.","p":"uh-SURT","o":"Latin","y":3,"bp":70,"ps":"verb","r":"Latin 'asserere' (to claim, declare), from ad- + serere (to join).","h":"Assert means to say it strongly and stand by it.","nt":"vocab-NWFinal-2026-Junior"},{"w":"assertive","d":"confident and bold in expressing opinions or wishes","s":"Being assertive, Nina politely asked the coach for a chance to pitch.","p":"uh-SUR-tiv","o":"Latin","y":3,"bp":70,"ps":"adjective","r":"From Latin 'asserere' (to claim) + -ive (tending to).","h":"Assertive people speak up firmly without being rude.","nt":"vocab-NWFinal-2026-Junior"},{"w":"assignee","d":"(law) the party to whom something is assigned (e.g., someone to whom a right or property is legally transferred)","s":"The assignee of the patent now held the exclusive right to manufacture the invention.","p":"as-ih-NEE","o":"French","y":3,"bp":32,"m":"assignie","sy":"as.sig.nee","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin assignare = to mark out, allot","h":"The -EE ending means the receiver — like an employee, the assignEE gets what's given: assign+ee.","t":["law"]},{"w":"assignment","d":"a duty that you are assigned to perform (especially in the armed forces)","s":"The teacher handed back the history assignment with detailed comments, urging every student to revise their arguments before the final deadline.","p":"uh-SEYE-nmuhnt","o":"French","y":3,"bp":34,"m":"assignement","sy":"ah.say.nmah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin assignare = to mark out, allot","h":"Your ASSIGN-MENT is to spot the SIGN inside — assign+ment, no extra E before -ment.","t":["physics"]},{"w":"associate","d":"a person who joins with others in some activity or endeavor","s":"He had to consult his associate before continuing.","p":"uh-SOH-see-uht","o":"Latin","y":3,"bp":34,"m":"assoicate","sy":"ah.sow.siy.ah.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin associare = to join to (socius = companion)","h":"An ASSOCIATE is a SOCIAL companion — find SOC-I inside, then add -ATE at the end."},{"w":"astray","d":"away from the right path or correct direction","s":"One wrong turn led the hikers astray in the woods.","p":"uh-STRAY","o":"French","y":3,"bp":70,"ps":"adverb","r":"Old French 'estraier' (to wander), root of 'stray'.","h":"Astray means gone a-straying — off the proper path.","nt":"vocab-NWFinal-2026-Junior"},{"w":"athirst","d":"eagerly longing for something; thirsty","s":"The curious students were athirst for facts about the planets.","p":"uh-THURST","o":"Old English","y":4,"bp":75,"ps":"adjective","r":"Old English 'ofthyrsted' (suffering thirst).","h":"Athirst = a-thirst — so thirsty for it you can't wait.","nt":"vocab-NWFinal-2026-Junior"},{"w":"atonement","d":"the act of making up for a wrong or an injury","s":"As atonement for breaking the vase, Jay did extra chores all week.","p":"uh-TOHN-muhnt","o":"English","y":4,"bp":75,"ps":"noun","r":"From English 'at one' — becoming 'at one' again after a wrong.","h":"Atonement makes you 'at one' again with someone you hurt.","nt":"vocab-NWFinal-2026-Junior"},{"w":"attain","d":"to reach or achieve something through effort","s":"After months of practice, Diego attained a black belt in karate.","p":"uh-TAYN","o":"French","y":3,"bp":70,"ps":"verb","r":"Old French 'ataindre', from Latin 'attingere' (to touch, reach).","h":"Attain means to finally reach out and touch your goal.","nt":"vocab-NWFinal-2026-Junior"},{"w":"attendant","d":"someone who waits on or tends to or attends to the needs of another","p":"uh-TEH-nduhnt","o":"Latin","y":3,"bp":33,"m":"attendint","sy":"ah.teh.ndah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin attendere = to stretch toward","h":"An ATTENDANT ends in '-ant' — like the ANT who busily tends to everyone's needs."},{"w":"attest","d":"to declare or serve as proof that something is true","s":"Her shelf of trophies attests to years of hard practice.","p":"uh-TEST","o":"Latin","y":3,"bp":75,"ps":"verb","r":"Latin 'attestari' (to bear witness), from testis (witness).","h":"Attest is to testify — a witness swearing it's true.","nt":"vocab-NWFinal-2026-Junior"},{"w":"attribute","d":"a construct whereby objects or individuals can be distinguished","p":"A-truh-byoot","o":"Latin","y":3,"bp":33,"m":"atribute","sy":"ae.trah.byuw.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin attributum, from ad+tribuere = to assign, bestow","h":"ATTRIBUTE: double-T then TRIBUTE — give a TRIBUTE to someone and you ATTRIBUTE credit to them!"},{"w":"atypical","d":"not representative of a group, class, or type","s":"A group that is atypical of the target audience.","p":"ay-TIH-pih-kuhl","o":"Greek","y":3,"bp":33,"m":"atipical","sy":"ey.tih.pih.kah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Greek a=not + typos=model/type","h":"aTYPical — it's not your TYPICAL spelling; the Y stays right after A."},{"w":"audacity","d":"fearless daring","s":"He had the audacity to question my decision.","p":"ah-DA-suh-tee","o":"Latin","y":3,"bp":33,"m":"audascity","sy":"aa.dae.sah.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin audax = bold, daring","h":"AUDACITy: it takes AUDACI-TY — bold enough to drop an 's' that doesn't belong."},{"w":"audit","d":"an official careful check of records or accounts","s":"The club treasurer welcomed an audit of the fundraiser money.","p":"AW-dit","o":"Latin","y":3,"bp":70,"ps":"noun","r":"Latin 'audire' (to hear) — accounts were once read aloud for checking.","h":"An audit is a careful listen-and-check of the money books.","nt":"vocab-NWFinal-2026-Junior"},{"w":"banish","d":"to force someone to leave a place as punishment","s":"The king chose to banish the traitor from the kingdom forever.","p":"BAN-ish","o":"French","y":3,"bp":70,"ps":"verb","r":"Old French 'banir' (to proclaim an outlaw).","h":"Banish means to ban someone from a place — get out and stay out.","nt":"vocab-NWFinal-2026-Junior"},{"w":"barb","d":"a sharp point sticking backward, or a sharply unkind remark","s":"The fishhook's barb kept the fish from slipping off the line.","p":"BARB","o":"Latin","y":3,"bp":70,"ps":"noun","r":"Latin 'barba' (beard) — for the bristly backward point.","h":"A barb hooks and stings, like barbed wire or a mean comment.","nt":"vocab-NWFinal-2026-Junior"},{"w":"barge","d":"a large flat-bottomed boat used to carry goods on rivers","s":"We watched a barge loaded with coal drift slowly down the river.","p":"BARJ","o":"French","y":2,"bp":60,"ps":"noun","r":"Old French 'barge', from Late Latin 'barca' (boat).","h":"A barge is a big flat boat hauling heavy cargo.","nt":"vocab-NWFinal-2026-Junior"},{"w":"barren","d":"an uninhabited wilderness that is worthless for cultivation","s":"The barrens of central Africa.","p":"BA-ruhn","o":"French","y":3,"bp":70,"m":"baren","sy":"bae.rah.n","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old French brehaigne = sterile, unfruitful","h":"BARREN land has double-R and double-N — nothing grows but letters: b-a-RR-e-NN.","t":["farming"]},{"w":"beacon","d":"a light or signal that guides people or warns of danger","s":"The lighthouse beacon guided the fishing boats safely home.","p":"BEE-kuhn","o":"Old English","y":2,"bp":65,"ps":"noun","r":"Old English 'beacen' (sign, signal fire).","h":"A beacon is a guiding light, like a lighthouse beam.","nt":"vocab-NWFinal-2026-Junior"},{"w":"adverse","d":"unfavorable or harmful; working against you","s":"The soccer match was canceled because of adverse weather.","p":"ad-VURS","o":"Latin","y":3,"bp":75,"ps":"adjective","r":"Latin 'adversus' (turned against), from ad- + vertere (to turn).","h":"Adverse conditions are turned against you, like your adversary.","nt":"vocab-NWFinal-2026-Junior"},{"w":"adversity","d":"a state of misfortune or affliction","s":"Debt-ridden farmers struggling with adversity.","p":"a-DVUR-sih-tee","o":"French","y":3,"bp":34,"m":"adversaty","sy":"ae.dver.sih.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin adversus = turned against","h":"In adversITY, there's a hidden CITY — hard times hit every city, spelled with 'i-t-y'.","t":["disease"]},{"w":"affect","d":"to influence something or produce a change in it","s":"Missing sleep can affect how well you do on a test.","p":"uh-FEKT","o":"Latin","y":2,"bp":65,"ps":"verb","r":"Latin 'afficere' (to act on), from ad- + facere (to do).","h":"To affect something is to act on it and change it.","nt":"vocab-NWFinal-2026-Junior"},{"w":"affinity","d":"(immunology) the attraction between an antigen and an antibody","s":"In anatomical structure prehistoric man shows close affinity with modern humans.","p":"uh-FIH-nuh-tee","o":"French","y":3,"bp":33,"m":"afinity","sy":"ah.fih.nah.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin affinitas = relationship, from affinis = bordering on","h":"Affinity is attraction to what's FINally yours — double 'f,' then 'fin,' then '-ity.'"},{"w":"affliction","d":"a state of great suffering and distress due to adversity","s":"Despite his painful affliction, the elderly man greeted each visitor with a warm and genuine smile.","p":"uh-FLIH-kshuhn","o":"French","y":3,"bp":75,"m":"afliction","sy":"ah.flih.kshah.n","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin affligere = to strike down","h":"An AFFLICTION is a double-f FLICTION — remember two f's carry the weight of suffering."},{"w":"aftermath","d":"the period or the results that follow a bad event","s":"In the aftermath of the storm, neighbors helped clear fallen branches.","p":"AF-tur-math","o":"Old English","y":3,"bp":75,"ps":"noun","r":"after + Old English 'maeth' (a mowing) — the second mowing after harvest.","h":"The aftermath is what comes after — the cleanup after the storm.","nt":"vocab-NWFinal-2026-Junior"},{"w":"aggression","d":"a disposition to behave aggressively","s":"The bully's aggression on the playground made the younger students afraid to go outside for recess.","p":"uh-GREH-shuhn","o":"French","y":3,"bp":34,"m":"agression","sy":"ah.greh.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin aggressio = attack (ad + gradi = to step toward)","h":"AGGression has two G's — like two fists raised in a fight, always paired up.","t":["character"]},{"w":"aggressive","d":"ready to attack or argue; forceful and pushy","s":"The aggressive goose hissed and chased us across the park.","p":"uh-GRES-iv","o":"Latin","y":2,"bp":65,"ps":"adjective","r":"Latin 'aggredi' (to attack, approach), from ad- + gradi (to step).","h":"Aggressive means stepping toward others to attack or push.","nt":"vocab-NWFinal-2026-Junior"},{"w":"appropriate","d":"give or assign a resource to a particular person or cause","p":"uh-PROH-pree-uht","o":"Latin","y":3,"bp":36,"m":"apropriate","sy":"ah.prow.priy.ah.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin appropriare = to make one's own, from proprius = one's own","h":"Two P's are PROPER when you APPROPRIATE: ap-PROPRI-ate — the double-P is part of 'proper' ownership."},{"w":"aquatic","d":"living in water or taking place in water","s":"Dolphins and sea turtles are amazing aquatic animals.","p":"uh-KWAT-ik","o":"Latin","y":2,"bp":65,"ps":"adjective","r":"Latin 'aqua' (water).","h":"Aqua means water — aquatic things live in it, like an aquarium.","nt":"vocab-NWFinal-2026-Junior"},{"w":"arch","d":"a curved structure that spans an opening or supports weight","s":"We walked under the stone arch at the entrance to the garden.","p":"ARCH","o":"Latin","y":2,"bp":60,"ps":"noun","r":"Latin 'arcus' (bow, curve), via Old French 'arche'.","h":"An arch curves like an archer's bow over a doorway.","nt":"vocab-NWFinal-2026-Junior"},{"w":"archaism","d":"the use of an archaic expression","s":"The poet's use of 'thee' and 'thou' was an intentional archaism meant to give the verse an ancient, solemn tone.","p":"AR-kay-iz-um","o":"Greek","y":3,"bp":32,"m":"archaicism","sy":"ar.cha.ism","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek archaios = ancient (arche = beginning)","h":"Archaism = ARCH + AISM — an 'arch' old-fashioned way of saying things."},{"w":"archangel","d":"an angel ranked above the highest rank in the celestial hierarchy","s":"In the painting, the archangel Gabriel appeared before Mary in a burst of golden light.","p":"ah-RKAY-njuhl","o":"Latin","y":3,"bp":33,"m":"archangle","sy":"aa.rkey.njhah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek arkhē = chief + angelos = messenger","h":"An ARCHangel is the ARCH (chief) ANGEL — stack the two words and you've spelled it perfectly.","t":["astronomy"],"vh":"angel"},{"w":"that","d":"used to point out a particular person or thing already mentioned","s":"That book on the top shelf is my favorite mystery.","p":"THAT","o":"Old English","y":2,"bp":55,"ps":"pronoun","r":"Old English 'thaet', a pointing word from ancient Germanic.","h":"'That' points at the one over there — not this one here.","nt":"vocab-NWFinal-2026-Junior"},{"w":"archbishop","d":"a bishop of highest rank","s":"The archbishop led the solemn Easter service before thousands of worshippers gathered in the grand cathedral.","p":"ah-RCHBIH-shuhp","o":"Latin","y":3,"bp":34,"m":"archbisshop","sy":"aa.rchbih.shah.p","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek arkhē = chief + episkopos = overseer","h":"An ARCHBISHOP is the ARCH (top) BISHOP — two familiar words joined, one 's' only, no doubling."},{"w":"archeology","d":"the branch of anthropology that studies prehistoric people and their cultures","s":"Students studying archeology spent the semester learning how to date pottery fragments found at dig sites.","p":"ah-rkee-AH-luh-jee","o":"French","y":3,"bp":37,"m":"archeolgy","sy":"aa.rkiy.aa.lah.jhiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek arkhaios = ancient + logos = study","h":"Archeo-LOGY: the LOGIC of studying ancient things — don't drop the 'o' before 'logy'."},{"w":"beneficial","d":"promoting or enhancing well-being","s":"An arms limitation agreement beneficial to all countries.","p":"beh-nuh-FIH-shuhl","o":"Latin","y":3,"bp":35,"m":"benefitial","sy":"beh.nah.fih.shah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin beneficium = benefit + -alis = relating to","h":"BeneFICIAL has FICI in the middle — no T! Think 'official' help that's officially good."},{"w":"benefit","d":"financial assistance in time of need","s":"For the benefit of all.","p":"BEH-nuh-fiht","o":"Latin","y":3,"bp":72,"m":"benifit","sy":"beh.nah.fih.t","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin bene = well + factum = deed done","h":"BENEfit: think BENE (well) + FIT — a benefit makes you financially FIT, and it's spelled BENE not BENI.","t":["time"]},{"w":"birthright","d":"a right or privilege a person has because of being born","s":"In the story, the crown was the prince's birthright.","p":"BURTH-ryt","o":"English","y":3,"bp":70,"ps":"noun","r":"birth + right — a right that comes with your birth.","h":"A birthright is yours by birth, no earning needed.","nt":"vocab-NWFinal-2026-Junior"},{"w":"blemish","d":"a mark or flaw that spoils the appearance of something (especially on a person's body)","s":"The art restorer worked carefully to remove every blemish from the ancient painting without damaging the original colors.","p":"BLEH-mihsh","o":"French","y":1,"bp":38,"m":"blemich","sy":"blem.ish","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old French blemir/blesmir = to make pale, to damage","h":"a BLEMish BLEM-s (damages) something's appearance"},{"w":"blink","d":"to shut and open the eyes very quickly","s":"Try not to blink during the whole staring contest.","p":"BLINGK","o":"Dutch","y":2,"bp":55,"ps":"verb","r":"Related to Middle Dutch 'blinken' (to shine, glance).","h":"A blink is one quick flutter of your eyelids.","nt":"vocab-NWFinal-2026-Junior"},{"w":"blossom","d":"a flower on a plant; also to bloom or develop well","s":"Every cherry blossom in the yard opened during spring break.","p":"BLAH-suhm","o":"Old English","y":2,"bp":60,"ps":"noun","r":"Old English 'blostm' (flower, bloom).","h":"A blossom is a bloom — trees blossoming are bursting with flowers.","nt":"vocab-NWFinal-2026-Junior"},{"w":"blurt","d":"to say something suddenly without thinking first","s":"Excited, Kiran blurted out the answer before raising his hand.","p":"BLURT","o":"English","y":3,"bp":70,"ps":"verb","r":"English imitative word — sounds like speech bursting out.","h":"Blurt sounds like a burst — words popping out uninvited.","nt":"vocab-NWFinal-2026-Junior","vh":"book value"},{"w":"boom","d":"a deep prolonged loud noise","s":"The demand for testing has created a boom for those unregulated laboratories where boxes of specimen jars are processed like an assembly line.","p":"BOOM","o":"Dutch","y":3,"bp":63,"m":"boom","sy":"buw.m","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Dutch bommen = to hum or buzz","h":"BOOM sounds exactly like what it means — one big, round, booming OO in the middle."},{"w":"bootleg","d":"made, copied, or sold illegally","s":"The officer warned that selling bootleg movie discs is against the law.","p":"BOOT-leg","o":"English","y":3,"bp":75,"ps":"adjective","r":"From smugglers hiding flasks inside the legs of their boots.","h":"Bootleg goods were once smuggled inside boot legs — illegal copies.","nt":"vocab-NWFinal-2026-Junior"},{"w":"breach","d":"the breaking of a law or promise, or a gap broken in something","s":"Sharing the secret was a breach of their friendship pact.","p":"BREECH","o":"French","y":3,"bp":75,"ps":"noun","r":"Old French 'breche' (a break), from a Germanic root meaning break.","h":"A breach is a break — in a wall, a rule, or a promise.","nt":"vocab-NWFinal-2026-Junior"},{"w":"brisk","d":"quick and energetic; also pleasantly cool and refreshing","s":"We took a brisk walk around the block before breakfast.","p":"BRISK","o":"French","y":2,"bp":65,"ps":"adjective","r":"Probably from French 'brusque' (lively, abrupt).","h":"Brisk means peppy and quick, like a chilly morning jog.","nt":"vocab-NWFinal-2026-Junior"},{"w":"bristling","d":"covered with stiff hairs or spikes; showing sudden anger","s":"The bristling porcupine warned the curious dog to back away.","p":"BRIS-ling","o":"Old English","y":3,"bp":70,"ps":"adjective","r":"Old English 'byrst' (bristle, stiff hair).","h":"Bristling means bristles standing up — spiky fur or spiky temper.","nt":"vocab-NWFinal-2026-Junior"},{"w":"brittle","d":"hard but easily broken or snapped","s":"The brittle icicle snapped the moment I touched it.","p":"BRIT-uhl","o":"Old English","y":2,"bp":65,"ps":"adjective","r":"Old English 'breotan' (to break into pieces).","h":"Brittle things break with a snap, like a dry twig.","nt":"vocab-NWFinal-2026-Junior"},{"w":"broadcast","d":"to send out a program by radio or TV; to spread widely","s":"The school will broadcast the spelling bee finals live online.","p":"BRAWD-kast","o":"English","y":2,"bp":60,"ps":"verb","r":"broad + cast — originally scattering seed widely over a field.","h":"Broadcast means to cast broadly — flinging a show to everyone.","nt":"vocab-NWFinal-2026-Junior"},{"w":"brochure","d":"a small booklet or pamphlet giving information","s":"The museum brochure showed a map of all the dinosaur exhibits.","p":"broh-SHUR","o":"French","y":3,"bp":70,"ps":"noun","r":"French 'brocher' (to stitch) — pages stitched into a booklet.","h":"A brochure is a little stitched booklet full of information.","nt":"vocab-NWFinal-2026-Junior"},{"w":"buccaneer","d":"someone who robs at sea or plunders the land from the sea without having a commission from any sovereign nation","s":"The bold buccaneer hoisted his flag and steered his ship toward the merchant vessel on the horizon.","p":"buh-kuh-NEER","o":"French","y":3,"bp":33,"m":"buccanear","sy":"bah.kah.niy.r","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"French boucanier = one who cures meat on a grill","h":"BUCCANeer: two C's like two cannons — a pirate fires TWO Cannons on the high seas, ending in EER not EAR.","t":["nations","waterways"]},{"w":"buffoonery","d":"acting like a clown or buffoon","s":"The class clown's buffoonery earned him detention but also plenty of laughs.","p":"buh-FOON-uh-ree","o":"French","y":2,"bp":91,"m":"bufoonery","sy":"buf.foon.ery","nt":"Junior | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"French bouffon = court jester, clown","h":"A BUFFOON does double-F foolishness — double F, double O: buFFOOnery."},{"w":"bungle","d":"to do something clumsily or badly; to botch","s":"Nervous nerves made him bungle the easy catch in the outfield.","p":"BUNG-guhl","o":"English","y":3,"bp":75,"ps":"verb","r":"Origin uncertain, possibly Scandinavian; means to work clumsily.","h":"Bungle a job and it comes out a clumsy jumble.","nt":"vocab-NWFinal-2026-Junior"},{"w":"buoyant","d":"able to float; also cheerful and lighthearted","s":"The buoyant beach ball bobbed on the waves all afternoon.","p":"BOY-uhnt","o":"Spanish","y":3,"bp":75,"ps":"adjective","r":"From Spanish 'boyar' (to float), related to 'buoy'.","h":"Buoyant like a buoy — it floats, and so can moods.","nt":"vocab-NWFinal-2026-Junior"},{"w":"burn","d":"to be on fire, or to damage something with heat","s":"Be careful not to burn the toast again this morning.","p":"BURN","o":"Old English","y":2,"bp":55,"ps":"verb","r":"Old English 'beornan' (to be on fire).","h":"Burn is fire's work — flames and heat leaving marks.","nt":"vocab-NWFinal-2026-Junior"},{"w":"bustle","d":"to move about busily; noisy, hurried activity","s":"The kitchen bustled as everyone cooked for the family reunion.","p":"BUS-uhl","o":"Norse","y":3,"bp":70,"ps":"verb","r":"Middle English 'bustelen', perhaps from Old Norse 'buask' (to prepare).","h":"Bustle is busy hustle — everyone rushing around at once.","nt":"vocab-NWFinal-2026-Junior"},{"w":"calamity","d":"an event resulting in great loss and misfortune","s":"The whole city was affected by the irremediable calamity.","p":"kuh-LA-muh-tee","o":"Latin","y":3,"bp":33,"m":"calamaty","sy":"kah.lae.mah.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin calamitas = damage, disaster, loss","h":"CALAMITY Jane faced misery — remember the I before TY: calam-I-ty spells trouble."},{"w":"candidate","d":"a politician who is running for public office","s":"Every candidate gave a passionate speech about how they would improve the school if elected class president.","p":"KA-nduh-dayt","o":"Latin","y":3,"bp":33,"m":"candidiate","sy":"kae.ndah.dey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin candidatus = dressed in white (Roman candidates wore white togas)","h":"A CANDIDAte wore white in Rome — spot CANDIDA inside candidate, then just add -TE!","t":["politics"]},{"w":"capillary","d":"a very thin tube that pulls liquid upward through narrow spaces","s":"During the biology lab, students used a tiny capillary tube to observe how water crept upward against gravity — a process called capillary action.","p":"KA-puh-leh-ree","o":"Latin","y":3,"bp":34,"m":"capilliary","sy":"cap.il.lar.y","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin capillaris = of hair, from capillus = hair","h":"A capillary is as thin as a HAIR — the root capill means HAIR in Latin.","t":["numbers"]},{"w":"caption","d":"words printed with a picture that explain it","s":"The caption under the photo named every player on the team.","p":"KAP-shuhn","o":"Latin","y":2,"bp":65,"ps":"noun","r":"Latin 'captio' (a taking), from capere (to take, seize).","h":"A caption captures a picture's meaning in a few words.","nt":"vocab-NWFinal-2026-Junior"},{"w":"carbohydrate","d":"an essential structural component of living cells and source of energy for animals; includes simple sugars with small molecules as well as macromolecular substances; are classified according to the number of monosaccharide groups they contain","s":"Athletes often eat foods high in carbohydrate before a race to give their muscles a quick source of energy.","p":"kah-rboh-HEYE-drayt","o":"Latin","y":3,"bp":37,"m":"carbohydrate","sy":"kaa.rbow.hhay.drey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin carbo = carbon + Greek hydor = water","h":"A carbohydrate is carbon plus water — carbo-HYDRATE, hydrate yourself to remember the water inside.","t":["animals","chemistry","physics","numbers"],"vh":"a"},{"w":"compound","d":"something made by combining two or more parts or ingredients","s":"Water is a compound made of hydrogen and oxygen.","p":"KAHM-pownd","o":"Latin","y":3,"bp":70,"ps":"noun","r":"Latin 'componere' (to put together), from com- + ponere (to place).","h":"A compound is parts put together, like 'sun' + 'flower'.","nt":"vocab-NWFinal-2026-Junior"},{"w":"carnivore","d":"a terrestrial or aquatic flesh-eating mammal","s":"Terrestrial carnivores have four or five clawed digits on each limb.","p":"KAH-rnih-vawr","o":"Latin","y":3,"bp":33,"m":"carnavore","sy":"kaa.rnih.vao.r","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin caro/carnis = flesh + vorare = to devour","h":"A CARNIvore DEVOURS flesh — carni + vore, the I in the middle is the hinge, like a jaw snapping shut.","t":["animals","marine"]},{"w":"carrousel","d":"a conveyer belt that carries luggage to be claimed by air travelers","s":"The children watched in excitement as colorful suitcases spun around the carrousel at the busy airport terminal.","p":"KEH-ruh-sehl","o":"French","y":3,"bp":33,"m":"carousal","sy":"keh.rah.seh.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"French carrousel = tournament, merry-go-round, from Italian carosello","h":"CARROUSEL has double-R spinning round and round — the two Rs go in circles just like the luggage belt."},{"w":"catcall","d":"a loud whistle or shout expressing disapproval","s":"A rude catcall from the stands earned that fan a warning.","p":"KAT-kawl","o":"English","y":3,"bp":70,"ps":"noun","r":"cat + call — a screech like an angry cat, aimed at performers.","h":"A catcall screeches like a cat to boo someone.","nt":"vocab-NWFinal-2026-Junior"},{"w":"category","d":"a collection of things sharing a common attribute","p":"KA-tuh-gaw-ree","o":"French","y":3,"bp":33,"m":"catagory","sy":"kae.tah.gao.riy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek katēgoria = accusation, class, from kata = against + agora = public assembly","h":"CATEGORY: a CAT in a GORE-y story belongs in its own — spell it catEGORY, hiding GORE in the middle."},{"w":"centimeter","d":"a metric unit of length equal to one hundredth of a meter","s":"The surgeon made a precise incision just one centimeter long during the delicate procedure.","p":"SEH-ntuh-mee-ter","o":"French","y":3,"bp":76,"m":"centimetre","sy":"seh.ntah.miy.ter","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin centum = hundred + Greek metron = measure","h":"A centiMETER METERS out one hundredth — a ruler's tiny tick between big numbers.","t":["numbers"]},{"w":"ceramic","d":"an artifact made of hard brittle material produced from nonmetallic minerals by firing at high temperatures","s":"The art student spent weeks carefully shaping and glazing a ceramic vase, learning how the kiln's intense heat would transform the dull, gray clay into a hard, brilliantly colored finished piece of art.","p":"ser-A-mihk","o":"Greek","y":3,"bp":72,"m":"cerammic","sy":"ser.ae.mih.k","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek keramos = potter's clay","h":"CERAMIC has one 'm' — you only need ONE kiln firing, so only ONE 'm.'","t":["minerals","ancient"],"vh":"object made of"},{"w":"charitable","d":"relating to or characterized by charity","p":"CHA-ruh-tuh-buhl","o":"French","y":3,"bp":76,"m":"charitible","sy":"chae.rah.tah.bah.l","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin caritas = love, charity","h":"A CHARITABLE person is CHARITY-ABLE — drop the 'y', add '-able', and give generously.","t":["character"]},{"w":"chastity","d":"abstaining from sexual relations (as because of religious vows)","s":"The young monk took a vow of chastity as part of his commitment to the religious order.","p":"CHA-stuh-tee","o":"Latin","y":3,"bp":32,"m":"chastidy","sy":"chae.stah.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin castitas = purity, from castus = pure","h":"CHASTITY ends in '-ity' like PURITY—both describe a pure state of being.","t":["religion"]},{"w":"choke","d":"to block the breathing passage, or to clog something up","s":"Chew slowly so you don't choke on the popcorn.","p":"CHOHK","o":"Old English","y":2,"bp":55,"ps":"verb","r":"Old English 'aceocian' (to suffocate).","h":"Choke means the throat or pipe gets blocked tight.","nt":"vocab-NWFinal-2026-Junior"},{"w":"cholesterol","d":"an animal sterol that is normally synthesized by the liver; the most abundant steroid in animal tissues","s":"The doctor advised him to eat less fried food to help lower his cholesterol and protect his heart.","p":"kuh-LEH-ster-awl","o":"Greek","y":3,"bp":36,"m":"cholesteral","sy":"kah.leh.ster.ao.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek khole = bile + stereos = solid + ol = alcohol","h":"CHOLESTEROL: bile + solid + ol — remember the END is -ol not -al, like alcohol.","t":["body","animals"]},{"w":"churn","d":"a vessel in which cream is agitated to separate butterfat from buttermilk","s":"The sea was churning in the storm.","p":"CHURN","o":"Old English","y":3,"bp":64,"m":"chirn","sy":"cher.n","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old English cyrin = churn, from Germanic root meaning to stir vigorously","h":"To CHURN butter you TURN cream around and around — CHURN contains TURN inside it.","t":["seafaring"]},{"w":"cite","d":"to quote or mention something as proof or an example","s":"For her report, Zoe had to cite three different books.","p":"SYT","o":"Latin","y":3,"bp":75,"ps":"verb","r":"Latin 'citare' (to summon, call forth).","h":"To cite is to call up a source as your evidence.","nt":"vocab-NWFinal-2026-Junior"},{"w":"classical","d":"of or relating to the traditional genre of Western art music conforming to established forms and appealing to cultivated musical taste; also of ancient Greece or Rome","s":"The concert hall fell silent as the soloist launched into a classical symphony that had moved audiences for two centuries.","p":"KLA-sih-kuhl","o":"Latin","y":3,"bp":33,"m":"clasical","sy":"clas.si.cal","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin classicus = of the highest class, from classis = class","h":"CLASSICAL has a double S — two S's for the two great civilizations, Greece and Rome.","t":["farming","music","festivals","ancient"]},{"w":"climatic","d":"of or relating to a climate","s":"Scientists studying climatic patterns over the past century have found clear evidence that average global temperatures have risen significantly, affecting everything from sea levels to wildlife migration routes around the world.","p":"kleye-MA-tihk","o":"Greek","y":3,"bp":32,"m":"climactic","sy":"klay.mae.tih.k","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Greek klima = slope, zone, region","h":"CLIMATIC relates to CLIMATE — just drop the E and add IC: cli-MAT-ic, all about weather, no extra C.","t":["weather"]},{"w":"clog","d":"to block something up so it cannot flow or move","s":"Wet leaves clogged the gutter after the rainstorm.","p":"KLAHG","o":"English","y":2,"bp":60,"ps":"verb","r":"Middle English 'clogge' (a block of wood).","h":"A clog is a block — like hair stopping up a drain.","nt":"vocab-NWFinal-2026-Junior"},{"w":"clone","d":"an exact copy of a living thing or of something else","s":"The scientist explained how a clone shares all its parent's genes.","p":"KLOHN","o":"Greek","y":3,"bp":70,"ps":"noun","r":"Greek 'klon' (twig) — new plants grown from cuttings.","h":"A clone is a copy grown from one twig of the original.","nt":"vocab-NWFinal-2026-Junior"},{"w":"cluster","d":"a grouping of a number of similar things","s":"A tight cluster of fireflies lit up the summer night, drifting slowly above the tall meadow grass like tiny floating lanterns.","p":"KLUH-ster","o":"Old English","y":3,"bp":67,"m":"clustar","sy":"klah.ster","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old English clyster = bunch, cluster","h":"A CLUSTER ends in -ER like a gathER — things gather together in a clustER.","t":["numbers"]},{"w":"coerce","d":"to force someone to do something by threats or pressure","s":"The bully tried to coerce younger kids into handing over snacks.","p":"koh-URS","o":"Latin","y":4,"bp":80,"ps":"verb","r":"Latin 'coercere' (to shut in, restrain), from co- + arcere (to enclose).","h":"Coerce means to strong-arm someone — force, not choice.","nt":"vocab-NWFinal-2026-Junior"},{"w":"coercion","d":"the act of compelling by force of authority","p":"koh-UR-shuhn","o":"Latin","y":3,"bp":32,"m":"coersion","sy":"kow.er.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin coercio = restraint","h":"COERCION: the C comes before the -ION — co-ERC-ION, not coers-ion; the C stays fierce.","t":["physics","poetry"]},{"w":"cohort","d":"a group of people, or a companion and supporter","s":"My cohort of fourth graders visited the science museum together.","p":"KOH-hort","o":"Latin","y":4,"bp":75,"ps":"noun","r":"Latin 'cohors' — a division of soldiers in a Roman army.","h":"A cohort marches together, like a Roman troop of friends.","nt":"vocab-NWFinal-2026-Junior"},{"w":"coincident","d":"occurring or operating at the same time","s":"A series of coincident events.","p":"koh-IH-nsuh-duhnt","o":"Latin","y":3,"bp":35,"m":"coincedent","sy":"kow.ih.nsah.dah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin co- = together + incidere = to fall upon","h":"COINCIDENT has -IDENT in it — think 'identical timing' to remember the -IDENT ending.","t":["time"]},{"w":"competitive","d":"involving competition or competitiveness","s":"The competitive student studied late every night to make sure she earned the highest grade in the class.","p":"kuh-MPEH-tuh-tihv","o":"Latin","y":1,"bp":44,"m":"competetive","sy":"com.pet.i.tive","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin competere — com (together) + petere (to seek)","h":"COMPETE + ITIVE — someone who always wants to compete","t":["sports"],"vh":"characterized by"},{"w":"compliment","d":"a remark (or act) expressing praise and admiration","s":"He complimented her on her last physics paper.","p":"KAH-mpluh-mehnt","o":"French","y":3,"bp":34,"m":"complement","sy":"kaa.mplah.meh.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"French compliment from Spanish cumplimiento = fulfillment of courtesy","h":"A compliment is something nice said to I — remember 'complIment' has an I, because it's about ME feeling good."},{"w":"composure","d":"steadiness of mind under stress","s":"He accepted their problems with composure and she with equanimity.","p":"kuh-MPOH-zher","o":"French","y":3,"bp":33,"m":"composure — composuer","sy":"kah.mpow.zher","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"French composure = calmness, from Latin componere","h":"COMPOSURE means keeping it together — COM+POS+URE, you PUT yourself together under pressure."},{"w":"comprehension","d":"an ability to understand the meaning or importance of something (or the knowledge acquired as a result)","s":"How you can do that is beyond my comprehension.","p":"kah-mpree-HEH-nshuhn","o":"French","y":3,"bp":37,"m":"comprehenshion","sy":"kaa.mpriy.hheh.nshah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin comprehensio = a grasping","h":"COMPREHENSION is the ACT of grasping — spot HENS in the middle, those chickens grasp every kernel.","t":["logic"]},{"w":"comprehensive","d":"an intensive examination testing a student's proficiency in some special field of knowledge","p":"kah-mpree-HEH-nsihv","o":"Latin","y":3,"bp":37,"m":"comprehencive","sy":"kaa.mpriy.hheh.nsih.v","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin comprehensivus = including all","h":"A COMPREHENSIVE exam covers everything — it GRASPS all topics, ending in -SIVE like an expansive net.","t":["logic"]},{"w":"concede","d":"to admit something is true, or to give in and accept defeat","s":"After the final point, the other team conceded the match.","p":"kuhn-SEED","o":"Latin","y":3,"bp":80,"ps":"verb","r":"Latin 'concedere' (to yield), from con- + cedere (to go, yield).","h":"Concede means to give up ground — okay, you win.","nt":"vocab-NWFinal-2026-Junior"},{"w":"conceit","d":"an excessively favorable opinion of oneself","s":"He could always come up with some inspired off-the-wall conceit.","p":"k-uh-n-s-EE-t","o":"English","y":3,"bp":47,"m":"conseit","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin concipere = to conceive, take in, from con-(together)+capere(to take)","h":"conCEIT — someone full of conceit thinks they're the ELITE"},{"w":"concentrate","d":"the desired mineral that is left after impurities have been removed from mined ore","s":"The orange juice concentrate in the freezer could be mixed with three cans of water to make a full pitcher.","p":"KAH-nsuh-ntrayt","o":"French","y":2,"bp":46,"m":"concetrate","sy":"con.cen.trate","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin concentrare — con (together) + centrum (center)","h":"CON + CENTER + ATE — concentrate your efforts toward the center","t":["minerals"]},{"w":"conch","d":"a large sea animal with a spiral shell, or the shell itself","s":"Hold the conch to your ear and you'll hear the ocean.","p":"KAHNK","o":"Greek","y":3,"bp":70,"ps":"noun","r":"Greek 'konche' (mussel, shell), via Latin 'concha'.","h":"A conch is the big spiral seashell people blow like a horn.","nt":"vocab-NWFinal-2026-Junior"},{"w":"concurrence","d":"agreement of results or opinions","p":"kuh-NKUR-uhns","o":"Latin","y":3,"bp":34,"m":"concurrance","sy":"kah.nker.ah.ns","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin concurrere = to run together","h":"Two Rs RUN together in conCURRence — spell it with -ence, not -ance, at the end."},{"w":"condensation","d":"(psychoanalysis) an unconscious process whereby two ideas or images combine into a single symbol; especially in dreams","p":"kah-nduh-NSAY-shuhn","o":"Latin","y":3,"bp":78,"m":"condenstion","sy":"kaa.ndah.nsey.shah.n","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin condensare = to make dense","h":"ConDENSation on a cold glass is DENSE moisture gathering together — DENS lives inside.","vh":"change from"},{"w":"conditional","d":"qualified by reservations","s":"Conditional acceptance of the terms.","p":"kuh-NDIH-shuh-nuhl","o":"Latin","y":3,"bp":36,"m":"condisional","sy":"kah.ndih.shah.nah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin condicio = agreement, situation","h":"ConDITIONal love has CONDITIONS attached — just add -AL to the end of condition."},{"w":"condolences","d":"an expression of sympathy with another's grief","s":"They sent their condolences.","p":"kuh-NDOH-luh-nsuhz","o":"Latin","y":3,"bp":36,"m":"condolances","sy":"kah.ndow.lah.nsah.z","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin condolere = to suffer together","h":"CONDOLENCES ends in -ENCES: Every NOTE of Condolence Expresses Shared grief.","t":["emotions"]},{"w":"condominium","d":"One apartment-like home that a person owns within a larger shared building.","s":"She saved for years before finally purchasing her first condominium in the heart of the city.","p":"kah-nduh-MIH-nee-uhm","o":"Latin","y":5,"bp":49,"m":"condomineum","sy":"kaa.ndah.mih.niy.ah.m","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin condominium = joint lordship/ownership","h":"A conDOMINIUM — you're all DOMINI (lords) together of your own unit. End it with -IUM like aquarium."},{"w":"confident","d":"characterized by a strong bold belief in oneself and by freedom from fear doubt and worry","s":"After weeks of rehearsal and preparation, Priya walked onto the debate stage feeling calm and confident, ready to defend her position with well-researched facts and a steady voice.","p":"k-AH-n-f-uh-d-uh-n-t","o":"Latin","y":2,"bp":43,"m":"confedent","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin confidere = to trust fully, from con-(fully)+fidere(to trust)","h":"A CONFIDENT person has FIDE-lity in themselves — spot 'fid' (faith/trust) in the middle: con-FID-ent.","t":["character","emotions","logic"]},{"w":"confinement","d":"concluding state of pregnancy; from the onset of contractions to the birth of a child","p":"kuh-NFEYE-nmuhnt","o":"Latin","y":3,"bp":34,"m":"confinment","sy":"kah.nfay.nmah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin confinis = bordering, finis = boundary","h":"CONFINEMENT keeps the E before -ment — even in confinement, that E refuses to leave!","t":["law","kinship"]},{"w":"conjoin","d":"to join together; to unite","s":"The two streams conjoin to form one wide river.","p":"kuhn-JOYN","o":"Latin","y":3,"bp":70,"ps":"verb","r":"Latin 'coniungere' (to yoke together), from con- + iungere (to join).","h":"Con + join = join together as one.","nt":"vocab-NWFinal-2026-Junior"},{"w":"conjure","d":"to make something appear as if by magic","s":"The magician seemed to conjure a rabbit out of thin air.","p":"KAHN-jur","o":"Latin","y":3,"bp":75,"ps":"verb","r":"Latin 'coniurare' (to swear together) — once linked to magic spells.","h":"Conjure means to magic something up — poof, it appears.","nt":"vocab-NWFinal-2026-Junior"},{"w":"conscious","d":"is being aware of one's own existence","s":"A conscious effort to speak more slowly.","p":"k-AH-n-sh-uh-s","o":"Latin","y":3,"bp":53,"m":"concious","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin conscius = aware, knowing together","h":"To be conSCIOUS is to KNOW — keep the SCI in the middle."},{"w":"consonant","d":"a speech sound that is not a vowel","p":"KAH-nsuh-nuhnt","o":"Latin","y":3,"bp":33,"m":"consonent","sy":"kaa.nsah.nah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin consonare = to sound together","h":"A conSONant SOUNDS with a vowel — SON = SOUND, and it ends in -ANT not -ENT.","t":["wordwords"]},{"w":"constrain","d":"to force, limit, or hold something back","s":"The tight budget constrained how many pizzas the club could order.","p":"kuhn-STRAYN","o":"Latin","y":3,"bp":75,"ps":"verb","r":"Latin 'constringere' (to bind tightly), from con- + stringere (to draw tight).","h":"Constrain squeezes you in tight limits, like a seatbelt on choices.","nt":"vocab-NWFinal-2026-Junior"},{"w":"contaminate","d":"To make something impure, unsafe, or unusable by introducing harmful or undesirable substances into it.","p":"kuh-NTA-muh-nayt","o":"Latin","y":3,"bp":36,"m":"contamanate","sy":"kah.ntae.mah.ney.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin contaminare = to defile, pollute","h":"To conTAMInate is to taint — picture a TAMINI (tiny germ) sneaking into the middle to make it impure."},{"w":"contemplate","d":"look at thoughtfully; observe deep in thought","p":"KAH-ntuh-mplayt","o":"Latin","y":3,"bp":34,"m":"contemplait","sy":"kaa.ntah.mpley.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin contemplari = to observe, from templum = sacred space","h":"Ancient priests would CONTEMPLATE in the TEMPLE — spot 'templa' inside the word."},{"w":"contend","d":"to compete or struggle against; also to argue a point","s":"Twelve schools will contend for the district trophy on Saturday.","p":"kuhn-TEND","o":"Latin","y":3,"bp":75,"ps":"verb","r":"Latin 'contendere' (to strive), from con- + tendere (to stretch).","h":"Contenders contend — they stretch and strive to win.","nt":"vocab-NWFinal-2026-Junior"},{"w":"contention","d":"a point asserted as part of an argument","p":"kuh-NTEH-nshuhn","o":"French","y":3,"bp":34,"m":"contension","sy":"kah.nteh.nshah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin contentio = struggle, from contendere = to strive","h":"CONTENTION ends in '-tion' not '-sion' — the argument is TENSE but spelled with a 't'.","t":["logic"]},{"w":"contest","d":"a competition in which people try to win","s":"Amrita entered the poster contest and won second prize.","p":"KAHN-test","o":"Latin","y":2,"bp":60,"ps":"noun","r":"Latin 'contestari' (to call to witness, bring a case).","h":"A contest is a test between rivals — may the best one win.","nt":"vocab-NWFinal-2026-Junior"},{"w":"context","d":"the words or situation around something that help explain its meaning","s":"Use the sentence's context to figure out the tricky word.","p":"KAHN-tekst","o":"Latin","y":3,"bp":75,"ps":"noun","r":"Latin 'contexere' (to weave together), from con- + texere (to weave).","h":"Context is the text woven around a word that reveals its meaning.","nt":"vocab-NWFinal-2026-Junior"},{"w":"contort","d":"to twist out of the normal shape","s":"The gymnast could contort her body into amazing shapes.","p":"kuhn-TORT","o":"Latin","y":3,"bp":75,"ps":"verb","r":"Latin 'contorquere' (to twist), from con- + torquere (to twist).","h":"Contort shares 'tort' (twist) with twisted pretzel shapes.","nt":"vocab-NWFinal-2026-Junior"},{"w":"convergent","d":"tending to come together from different directions","s":"The two rivers followed convergent paths, meeting dramatically at a rocky gorge downstream.","p":"kuh-NVUR-juhnt","o":"Latin","y":3,"bp":34,"m":"convergant","sy":"kah.nver.jhah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin convergens = inclining together","h":"convergENT ends in ENT not ANT — convergENT lines are BENT toward each other.","t":["character"]},{"w":"conversant","d":"(usually followed by `with') well informed about or knowing thoroughly","s":"Conversant with business trends.","p":"kuh-NVUR-suhnt","o":"Latin","y":3,"bp":34,"m":"conversent","sy":"kah.nver.sah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin conversari = to associate with","h":"conversANT ends in ANT — someone conversANT is as busy as an ANT, always turning ideas over in conversation."},{"w":"converse","d":"to talk with another person; to have a conversation","s":"The pen pals finally got to converse face to face.","p":"kuhn-VURS","o":"Latin","y":3,"bp":70,"ps":"verb","r":"Latin 'conversari' (to keep company with).","h":"Converse is what a conversation is — talking back and forth.","nt":"vocab-NWFinal-2026-Junior"},{"w":"corruptible","d":"capable of being corrupted","s":"The ethics professor argued that even the most honest official is corruptible when offered enormous wealth and the promise that no one will ever discover the wrongdoing.","p":"ker-UH-ptih-buhl","o":"Latin","y":3,"bp":36,"m":"corruptable","sy":"ker.ah.ptih.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin corruptus = broken, from rumpere = to break","h":"A CORRUPTIBLE person CAN be broken — use -ible not -able because the Latin root already broke the spelling rules once.","vh":"capable of being"},{"w":"counter","d":"to act or speak in opposition; to respond against","s":"When Jay claimed cats were smarter, Mia countered with facts about dogs.","p":"KOWN-tur","o":"Latin","y":3,"bp":70,"ps":"verb","r":"Latin 'contra' (against), via French 'contre'.","h":"To counter is to push back — a counterattack in an argument.","nt":"vocab-NWFinal-2026-Junior"},{"w":"countercharge","d":"a charge brought by an accused person against the accuser","s":"When the student accused the teacher of unfair grading, the teacher responded with a countercharge of academic dishonesty.","p":"KOW-nter-chahrj","o":"French","y":3,"bp":36,"m":"counterchardge","sy":"kaw.nter.chaa.rjh","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"French contre = against + Old French chargier = to load","h":"A COUNTER-CHARGE fires back — charge has a hard G before the E, like a charging bull.","t":["law"]},{"w":"counterfeit","d":"fake and made to look real in order to trick people","s":"The clerk spotted the counterfeit bill because the ink looked wrong.","p":"KOWN-tur-fit","o":"French","y":3,"bp":80,"ps":"adjective","r":"Old French 'contrefaire' (to imitate), from contre- + faire (to make).","h":"Counterfeit means made against the real thing — a phony copy.","nt":"vocab-NWFinal-2026-Junior"},{"w":"counterpart","d":"a person or thing having the same function or characteristics as another","s":"The American secretary of state met with her counterpart from France to discuss trade.","p":"KOW-nter-pahrt","o":"French","y":3,"bp":34,"m":"counterpaart","sy":"kaw.nter.paa.rt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"French contrepartie = corresponding copy","h":"Your COUNTERPART plays a matching PART — the word PART hides inside counterPART, plain and simple."},{"w":"countryman","d":"a man from your own country","s":"When he met a fellow countryman abroad, they immediately bonded over shared memories of home.","p":"KUH-ntree-muhn","o":"French","y":3,"bp":34,"m":"cuntreyman","sy":"kah.ntriy.mah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin contra = region + Old English mann = person","h":"A COUNTRYMAN is a MAN from your COUNTRY — straightforward compound, just spell each part clearly."},{"w":"courtesy","d":"polite behavior and good manners toward others","s":"As a courtesy, Ben held the door for the teachers.","p":"KUR-tuh-see","o":"French","y":2,"bp":65,"ps":"noun","r":"Old French 'courteis' — fine manners fit for a royal court.","h":"Courtesy is court-style politeness — manners fit for a palace.","nt":"vocab-NWFinal-2026-Junior"},{"w":"craving","d":"a very strong desire for something, especially food","s":"A sudden craving for mango ice cream hit her after practice.","p":"KRAY-ving","o":"Old English","y":2,"bp":65,"ps":"noun","r":"Old English 'crafian' (to demand, beg for).","h":"A craving makes your whole body beg: I must have it now.","nt":"vocab-NWFinal-2026-Junior"},{"w":"creamy","d":"smooth, thick, and rich like cream","s":"The soup was so creamy that everyone asked for seconds.","p":"KREE-mee","o":"French","y":2,"bp":55,"ps":"adjective","r":"Old French 'cresme' (cream) + English -y.","h":"Creamy means cream-like — smooth, soft, and rich.","nt":"vocab-NWFinal-2026-Junior"},{"w":"cyclical","d":"recurring in cycles","s":"The economist explained that recessions are cyclical, meaning the economy naturally rises and falls over time.","p":"SEYE-klih-kuhl","o":"Greek","y":3,"bp":32,"m":"cyclicle","sy":"say.klih.kah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Greek kyklos = circle/wheel","h":"CYCLICAL has two Cs and two Ls — count them in a cycle: C-Y-C-L-I-C-A-L."},{"w":"cyclone","d":"(meteorology) rapid inward circulation of air masses about a low pressure center; circling counterclockwise in the northern hemisphere and clockwise in the southern","s":"The cyclone churned across the ocean, its fierce spiral winds uprooting trees and flooding coastal villages for miles around.","p":"sih-KLOHN","o":"Greek","y":3,"bp":71,"m":"cylcone","sy":"cy.clone","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek kyklon = moving in a circle, from kyklos = circle","h":"A cyclone CYCLES in a circle","t":["astronomy","weather","maps","time"]},{"w":"cynic","d":"one who believes people act only out of selfishness","s":"Don't be a cynic — some kids really do volunteer just to help.","p":"SIN-ik","o":"Greek","y":4,"bp":80,"ps":"noun","r":"Greek 'kynikos' (doglike) — nickname for blunt ancient philosophers.","h":"A cynic snarls doubt at everyone's motives, trusting no kindness.","nt":"vocab-NWFinal-2026-Junior","vh":"one who is"},{"w":"death's-head","d":"a human skull, or a picture of one, as a symbol of death","s":"A death's-head flapped on the pirate flag in the movie.","p":"DETHS-hed","o":"English","y":4,"bp":70,"ps":"noun","r":"English compound: death's + head — a skull emblem.","h":"A death's-head is the skull on a pirate's flag.","nt":"vocab-NWFinal-2026-Junior"},{"w":"decagram","d":"A unit of mass in the metric system equal to ten grams, used primarily in scientific and culinary measurements.","s":"The recipe called for exactly one decagram of salt, which the chef carefully weighed on a precision scale.","p":"DEK-uh-gram","o":"Greek","y":3,"bp":32,"m":"dekagram","sy":"dec.a.gram","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek deka = ten + gramma = small weight","h":"A DECAGRAM is ten GRAMS — DECA always means ten, so just attach it to GRAM and you're done!","t":["culinary","numbers"]},{"w":"decaliter","d":"a metric unit of volume or capacity equal to 10 liters","s":"The chemist measured out a full decaliter of solution for the large-scale experiment.","p":"DEK-uh-lee-ter","o":"Greek","y":3,"bp":34,"m":"decaliter","sy":"dec.a.li.ter","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek deka = ten + French litre = unit of liquid measure","h":"A DECALITER holds ten LITERS — DECA means ten, just attach it to LITER and pour in ten times the fun!","t":["numbers"]},{"w":"decameter","d":"a metric unit of length equal to ten meters","s":"The football field measured approximately ten decameters from one end zone to the other.","p":"DEK-uh-mee-ter","o":"Greek","y":3,"bp":34,"m":"dekameter","sy":"dec.a.me.ter","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek deka = ten + metron = measure","h":"A DECAmeter is ten meters — DECA like a decade is ten years, and METER measures the distance.","t":["numbers"]},{"w":"deceit","d":"the act of lying to or misleading someone; dishonesty","s":"The fox in the fable used deceit to steal the crow's cheese.","p":"dih-SEET","o":"French","y":3,"bp":75,"ps":"noun","r":"Old French 'deceite', from Latin 'decipere' (to trap, deceive).","h":"Deceit is trickery — deceiving with lies and false faces.","nt":"vocab-NWFinal-2026-Junior"},{"w":"deflect","d":"to turn something aside or make it change direction","s":"The goalie deflected the ball just before it reached the net.","p":"dih-FLEKT","o":"Latin","y":3,"bp":75,"ps":"verb","r":"Latin 'deflectere' (to bend away), from de- + flectere (to bend).","h":"Deflect bends the path away, like a shield bouncing a blow.","nt":"vocab-NWFinal-2026-Junior"},{"w":"deity","d":"a god or goddess","s":"In Greek myths, Zeus is the deity who rules the sky.","p":"DEE-ih-tee","o":"Latin","y":3,"bp":75,"ps":"noun","r":"Latin 'deus' (god), via 'deitas' (divine nature).","h":"A deity is a divine being — think Zeus or Athena.","nt":"vocab-NWFinal-2026-Junior"},{"w":"dejection","d":"a state of melancholy depression","s":"After losing the championship game, the team sat in silent dejection in the locker room.","p":"deh-JEK-shun","o":"Latin","y":3,"bp":33,"m":"dejeckion","sy":"de.jec.tion","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin dejectio = a casting down","h":"DEJECTION has JECT in the middle — your spirits are JECTED (thrown) DOWN into depression.","t":["emotions"]},{"w":"deluge","d":"a great flood, or a very heavy rush of rain or things","s":"A deluge of rain flooded the soccer field in minutes.","p":"DEL-yooj","o":"French","y":4,"bp":80,"ps":"noun","r":"Old French 'deluge', from Latin 'diluvium' (flood).","h":"A deluge drowns everything in a downpour — flood-level rain.","nt":"vocab-NWFinal-2026-Junior"},{"w":"demonstrative","d":"a pronoun that points out an intended referent","s":"An affectionate and demonstrative family.","p":"dih-MAH-nstruh-tihv","o":"Latin","y":3,"bp":37,"m":"demonstritive","sy":"dih.maa.nstrah.tih.v","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin demonstrativus = serving to demonstrate","h":"DEMONSTRATIVE ends in '-ative' not '-itive'—it actively shows, so use the 'a' of action."},{"w":"denote","d":"to mean, indicate, or be a sign of something","s":"On the map, a star denotes each state capital.","p":"dih-NOHT","o":"Latin","y":3,"bp":75,"ps":"verb","r":"Latin 'denotare' (to mark out), from de- + notare (to note).","h":"Denote means to note down the meaning — this sign means that.","nt":"vocab-NWFinal-2026-Junior"},{"w":"denounce","d":"to publicly declare that something or someone is wrong or bad","s":"The principal denounced cheating at the school assembly.","p":"dih-NOWNS","o":"Latin","y":3,"bp":80,"ps":"verb","r":"Latin 'denuntiare' (to announce against), from de- + nuntiare (to announce).","h":"Denounce means to announce loudly: this is wrong!","nt":"vocab-NWFinal-2026-Junior"},{"w":"deplete","d":"to use up or greatly reduce the supply of something","s":"The long hike depleted our water bottles by noon.","p":"dih-PLEET","o":"Latin","y":3,"bp":80,"ps":"verb","r":"Latin 'deplere' (to empty out), from de- + plere (to fill).","h":"Deplete un-fills — the tank drains until it's empty.","nt":"vocab-NWFinal-2026-Junior"},{"w":"depopulate","d":"reduce in population","s":"The epidemic depopulated the countryside.","p":"dee-PAH-pyuh-layt","o":"Latin","y":3,"bp":35,"m":"depopualte","sy":"diy.paa.pyah.ley.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin depopulare = to ravage, lay waste","h":"To DEPOPULATE means to remove the PEOPLE—POPUL is right inside, like a crowd you can see."},{"w":"descendant","d":"a person considered as descended from some ancestor or race","s":"Maya discovered through a genealogy website that she was a direct descendant of a celebrated West African queen whose story had been passed down only through oral tradition for centuries.","p":"dih-SEH-nduhnt","o":"Latin","y":3,"bp":34,"m":"descendent","sy":"dih.seh.ndah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin descendere = to climb down","h":"A DESCENDANT of an ancestor — remember ANT: a tiny ANT crawls DOWN from its ancestors.","t":["kinship","sports"],"vh":"one who is"},{"w":"detachment","d":"avoiding emotional involvement","p":"dih-TA-chmuhnt","o":"French","y":3,"bp":75,"m":"detatchment","sy":"dih.tae.chmah.nt","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"French détacher = to unfasten","h":"deTACHMENT: emotional distance is the MENTAL state of removing the TACK — spell it TACH+MENT.","t":["emotions"]},{"w":"detergent","d":"a surface-active chemical widely used in industry and laundering","s":"She added extra detergent to the wash because the soccer uniforms were covered in mud.","p":"dih-TUR-juhnt","o":"Latin","y":3,"bp":33,"m":"deturgent","sy":"dih.ter.jhah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin detergere = to wipe off","h":"deTERGent has TERG in the middle — it TERrifically Gets grime off.","t":["chemistry"]},{"w":"determination","d":"the act of determining the properties of something, usually by research or calculation","s":"The determination of molecular structures.","p":"dih-tur-muh-NAY-shuhn","o":"Latin","y":3,"bp":39,"m":"determintaion","sy":"dih.ter.mah.ney.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin determinare = to set limits","h":"deTERMINATION — spot TERM and NATION: a determined NATION sets its TERMS."},{"w":"detest","d":"to hate something very strongly","s":"My little brother detests broccoli but loves carrots.","p":"dih-TEST","o":"Latin","y":3,"bp":75,"ps":"verb","r":"Latin 'detestari' (to curse while calling the gods to witness).","h":"To detest is to despise it completely — total hate.","nt":"vocab-NWFinal-2026-Junior","vh":"to"},{"w":"detonate","d":"cause to burst with a violent release of energy","p":"DEH-tuh-nayt","o":"Latin","y":3,"bp":32,"m":"detnate","sy":"deh.tah.ney.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin detonare = to thunder down","h":"DETONATE has TONE inside—the loud TONE of thunder crashing down.","t":["physics"]},{"w":"devastate","d":"cause extensive destruction or ruin utterly","p":"DEH-vuh-stayt","o":"Latin","y":3,"bp":33,"m":"devestate","sy":"deh.vah.stey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin devastare = to lay waste, vastus = empty/waste","h":"DEVASTATE contains VAST — destruction leaves a VAST empty wasteland: de-VAST-ate."},{"w":"devise","d":"to invent or think up a clever plan or method","s":"The team devised a secret play for the final quarter.","p":"dih-VYZ","o":"French","y":3,"bp":75,"ps":"verb","r":"Old French 'deviser' (to plan), from Latin 'dividere' (to divide).","h":"Devise means to dream up a device — a clever plan.","nt":"vocab-NWFinal-2026-Junior"},{"w":"diabolical","d":"showing the cunning or ingenuity or wickedness typical of a devil","s":"The villain's diabolical scheme involved tricking every bank in the city simultaneously, exploiting their computer systems with cunning precision while his unsuspecting accomplices created noisy distractions throughout the downtown streets.","p":"deye-uh-BAH-lih-kuhl","o":"Greek","y":3,"bp":37,"m":"diabolicle","sy":"day.ah.baa.lih.kah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Greek diabolos = slanderer, devil","h":"DIABOLICAL evil is dia-BOL-ic-AL — the devil throws ALL his tricks across the room."},{"w":"dialogue","d":"is conversation with two or more people","s":"He has read Plato's Dialogues in the original Greek.","p":"d-AY-uh-l-aw-g","o":"Greek","y":3,"bp":52,"m":"dialoge","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek dia = between + logos = word/speech","h":"A dialogUE always ends politely with a silent UE — the quiet goodbye at the end of a conversation."},{"w":"differentiate","d":"mark as different","p":"dih-fer-EH-nshee-ayt","o":"Latin","y":3,"bp":39,"m":"differenciate","sy":"dih.fer.eh.nshiy.ey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin differentiare = to distinguish","h":"differENTIATE — no C sneaks in; it's different+iate, just attach ATE to tell them apart."},{"w":"diffuse","d":"to spread out widely in every direction","s":"The smell of fresh cookies diffused through the whole house.","p":"dih-FYOOZ","o":"Latin","y":3,"bp":80,"ps":"verb","r":"Latin 'diffundere' (to pour out), from dis- + fundere (to pour).","h":"Diffuse pours out in all directions, like perfume filling a room.","nt":"vocab-NWFinal-2026-Junior"},{"w":"diffusible","d":"able to spread out or be spread in all directions","s":"The dye was so diffusible it colored the whole glass of water.","p":"dih-FYOO-zuh-buhl","o":"Latin","y":4,"bp":70,"ps":"adjective","r":"Latin 'diffundere' (to pour out) + -ible (able to be).","h":"Diffusible = able to diffuse — it can drift and spread everywhere.","nt":"vocab-NWFinal-2026-Junior"},{"w":"diffusion","d":"(physics) the process in which there is movement of a substance from an area of high concentration of that substance to an area of lower concentration","p":"dih-FYOO-zhuhn","o":"Latin","y":3,"bp":33,"m":"difusion","sy":"dih.fyuw.zhah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin diffusio = a spreading out","h":"difFUSION is FUSION in reverse — molecules spread apart; double F starts it.","t":["physics"]},{"w":"digital","d":"using information stored as numbers, as computers do","s":"We swapped the paper calendar for a digital one on the tablet.","p":"DIJ-ih-tuhl","o":"Latin","y":2,"bp":60,"ps":"adjective","r":"Latin 'digitus' (finger) — fingers were used for counting numbers.","h":"Digital comes from counting on your digits — number-based tech.","nt":"vocab-NWFinal-2026-Junior"},{"w":"digress","d":"to wander away from the main topic","s":"Our teacher digressed from fractions to tell a story about her dog.","p":"dy-GRES","o":"Latin","y":4,"bp":80,"ps":"verb","r":"Latin 'digredi' (to step aside), from dis- + gradi (to step).","h":"Digress means to step off-topic — 'anyway, back to the point.'","nt":"vocab-NWFinal-2026-Junior"},{"w":"dilate","d":"to become wider or larger; to expand","s":"Your pupils dilate in a dark room to let in more light.","p":"DY-layt","o":"Latin","y":3,"bp":80,"ps":"verb","r":"Latin 'dilatare' (to spread wide), from dis- + latus (wide).","h":"Dilate means to get wide — eyes widening in the dark.","nt":"vocab-NWFinal-2026-Junior"},{"w":"dilemma","d":"state of uncertainty or perplexity especially as requiring a choice between equally unfavorable options","s":"Maya faced a dilemma: she could study for her math test or attend her best friend's birthday party, but not both.","p":"dih-LEH-muh","o":"Greek","y":1,"bp":39,"m":"dilemna","sy":"di.lem.ma","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek dilemma = double proposition, from di-(two)+lemma(premise)","h":"diLEMMa has double M — you're stuck between two M-choices, just like being stuck in a dilemma."},{"w":"diligent","d":"quietly and steadily persevering especially in detail or exactness","s":"A diligent (or patient) worker.","p":"DIH-lih-juhnt","o":"French","y":3,"bp":32,"m":"dilligent","sy":"dih.lih.jhah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin diligens = to esteem, choose carefully","h":"A DILIgent worker carefully chooses to use only ONE 'l'—no double 'l' needed!"},{"w":"dilute","d":"to make less concentrated to diminish the strength or flavor of something","s":"The art teacher showed students how to dilute the bright acrylic paint with small amounts of water to create softer, more transparent washes of color across their watercolor paper.","p":"d-ay-l-OO-t","o":"Latin","y":2,"bp":39,"m":"delute","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin diluere = to wash away, dilute, from di-(apart)+luere(to wash)","h":"To DILUTE is to 'di-' (two things apart) — the 'i' stays: diLUTE, not deLUTE."},{"w":"diplomatic","d":"relating to or characteristic of diplomacy","s":"The diplomatic ambassador carefully chose her words during the tense negotiation, ensuring that neither country felt disrespected or unfairly treated during the historic summit.","p":"dih-pluh-MA-tihk","o":"Greek","y":3,"bp":35,"m":"diplomattic","sy":"dih.plah.mae.tih.k","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Greek diploma = folded document; relating to official negotiation","h":"diploMATIC has only ONE T — a true diplomat never doubles down aggressively!"},{"w":"disallow","d":"to refuse to allow or accept something","s":"The referee disallowed the goal because a player was offside.","p":"dis-uh-LOW","o":"French","y":3,"bp":70,"ps":"verb","r":"Old French 'desalouer' (to blame, refuse to approve).","h":"Disallow is the opposite of allow — nope, not permitted.","nt":"vocab-NWFinal-2026-Junior"},{"w":"collaborate","d":"work together on a common enterprise of project","p":"kuh-LA-ber-ayt","o":"Latin","y":3,"bp":36,"m":"colaborate","sy":"kah.lae.ber.ey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin collaborare = com(together)+laborare(to work)","h":"To colLABorate you share the LABor — hide LAB in the middle."},{"w":"collapse","d":"an abrupt failure of function or complete physical exhaustion","p":"kuh-LAPS","o":"Latin","y":3,"bp":71,"m":"colapse","sy":"kah.lae.ps","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin collapsus = com(together)+labi(to fall)","h":"A colLAPSE includes a LAPSE — double l then LAPSE, things fall apart."},{"w":"collapsible","d":"capable of collapsing or being collapsed","s":"The camping gear store sold a lightweight collapsible water bottle that could be folded flat and tucked into a jacket pocket when it was completely empty after a hike.","p":"kuh-LA-psuh-buhl","o":"Latin","y":3,"bp":36,"m":"colapsible","sy":"kah.lae.psah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin collapsus = fallen + ibilis = capable of","h":"A colLAPSible chair can LAPSE flat — double l then LAPS+ible."},{"w":"collective","d":"members of a cooperative enterprise","s":"The farmers formed a collective so they could share equipment, pool their resources, and sell their produce together at a higher price than any one of them could achieve alone.","p":"kuh-LEH-ktihv","o":"Latin","y":3,"bp":34,"m":"colective","sy":"kah.leh.ktih.v","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin collectivus = gathered","h":"A COLLECTIVE body acts with double-L force — col+LECTIVE."},{"w":"combat","d":"a fight encounter or contest between individuals or groups","p":"k-AH-m-b-a-t","o":"English","y":2,"bp":35,"m":"kombat","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"noun","r":"French combattre = to fight, from Latin com- + battere = to beat","h":"In comBAT, two fighters BAT each other — the word BAT is hiding right inside comBAT."},{"w":"comical","d":"funny; causing laughter","s":"The clown's comical dance made the whole audience giggle.","p":"KAH-mih-kuhl","o":"Greek","y":2,"bp":60,"ps":"adjective","r":"Greek 'komikos' (of comedy), from komos (merrymaking).","h":"Comical means like a comedy — it makes you laugh.","nt":"vocab-NWFinal-2026-Junior"},{"w":"commitment","d":"the trait of sincere and steadfast fixity of purpose","s":"A man of energy and commitment.","p":"kuh-MIH-tmuhnt","o":"Latin","y":3,"bp":34,"m":"committment","sy":"kah.mih.tmah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin committere = to send together, to entrust","h":"comMITment has only ONE T before -MENT — your MIT team commits without extra baggage."},{"w":"commodity","d":"articles of commerce","s":"Fresh water is such a precious commodity in the desert that villagers travel miles to collect it.","p":"kuh-MAH-duh-tee","o":"Latin","y":3,"bp":34,"m":"commodaty","sy":"kah.maa.dah.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin commoditas = convenience, advantage","h":"A COMMOD-ITY has double-m and ends in -ity, like a utility you trade.","t":["economy"]},{"w":"compact","d":"packed closely together; taking up little space","s":"Her compact backpack still held books, lunch, and a jacket.","p":"kuhm-PAKT","o":"Latin","y":3,"bp":70,"ps":"adjective","r":"Latin 'compingere' (to pack together), from com- + pangere (to fasten).","h":"Compact means packed tight — everything squeezed small and neat.","nt":"vocab-NWFinal-2026-Junior"},{"w":"comparison","d":"the act of examining resemblances","s":"The teacher asked students to write an essay that included a careful comparison of two historical leaders.","p":"kuh-MPEH-ruh-suhn","o":"French","y":3,"bp":35,"m":"comparision","sy":"com.par.i.son","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin comparare — com (together) + parare (to make equal)","h":"COMPARE + ISON — drop the E and add ISON to compare"},{"w":"compatible","d":"able to exist and perform in harmonious or agreeable combination","s":"A compatible married couple.","p":"kuh-MPA-tuh-buhl","o":"French","y":3,"bp":35,"m":"compatable","sy":"kah.mpae.tah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin com- = together + pati = to endure","h":"They were compaTIBLE — remember IBLE not ABLE — they were able to co-exist."},{"w":"crevice","d":"a narrow crack or opening, especially in rock","s":"A tiny lizard darted into a crevice in the stone wall.","p":"KREV-is","o":"French","y":3,"bp":75,"ps":"noun","r":"Old French 'crevace' (crack), from Latin 'crepare' (to crack).","h":"A crevice is a skinny crack where small things hide.","nt":"vocab-NWFinal-2026-Junior"},{"w":"cringe","d":"to shrink back or flinch in fear or embarrassment","s":"I cringe every time Dad sings loudly in the car pool line.","p":"KRINJ","o":"Old English","y":3,"bp":70,"ps":"verb","r":"Old English 'cringan' (to bend, fall in battle).","h":"Cringe means to curl away — ooh, that's embarrassing.","nt":"vocab-NWFinal-2026-Junior"},{"w":"criterion","d":"a basis for comparison; a reference point against which other things can be evaluated","p":"kreye-TIH-ree-uhn","o":"Latin","y":3,"bp":34,"m":"critereon","sy":"kray.tih.riy.ah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek kriterion = means of judging, from krinein = to judge","h":"A CRITERION is a judge's tool—Greek krinein means to judge; remember -ERION not -ERIAN, it ends like 'ion' as in ionize a judgment."},{"w":"crony","d":"a close friend or longtime companion","s":"Grandpa meets his old cronies at the diner every Saturday.","p":"KROH-nee","o":"Greek","y":4,"bp":75,"ps":"noun","r":"Greek 'khronios' (long-lasting) — a friend of long standing.","h":"A crony is a chum from way back — friends across time.","nt":"vocab-NWFinal-2026-Junior"},{"w":"crunch","d":"to chew or crush something with a noisy cracking sound","s":"We crunched dry leaves under our boots on the fall hike.","p":"KRUNCH","o":"English","y":2,"bp":55,"ps":"verb","r":"English imitative word — it sounds like the noise it names.","h":"Crunch sounds exactly like biting a crisp apple.","nt":"vocab-NWFinal-2026-Junior"},{"w":"culprit","d":"the person guilty of a crime or responsible for a problem","s":"The crumbs led straight to the culprit who ate the cookies.","p":"KUL-prit","o":"French","y":3,"bp":80,"ps":"noun","r":"Anglo-French court words 'culpable: prest' (guilty: ready to prove).","h":"The culprit carries the culpa — Latin for blame.","nt":"vocab-NWFinal-2026-Junior"},{"w":"curable","d":"able to be healed or cured","s":"The vet said the puppy's ear infection was easily curable.","p":"KYUR-uh-buhl","o":"Latin","y":2,"bp":60,"ps":"adjective","r":"Latin 'curare' (to care for) + -able (able to be).","h":"Curable = cure + able — a sickness medicine can fix.","nt":"vocab-NWFinal-2026-Junior"},{"w":"curative","d":"a medicine or therapy that cures disease or relieve pain","s":"Curative powers of herbal remedies.","p":"KYUU-ruh-tihv","o":"Latin","y":3,"bp":32,"m":"cureative","sy":"kyuh.rah.tih.v","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin curare = to take care of, to heal","h":"A CURATIVE tends to CURE — drop the E from cure before adding -ative, no double vowel needed.","t":["body","disease","pharmacy"]},{"w":"curfew","d":"a rule that everyone must be indoors by a certain time","s":"After the storm caused power outages across town, the mayor imposed a curfew requiring everyone to be home by nine o'clock.","p":"KUR-fyoo","o":"French","y":3,"bp":70,"m":"curfue","sy":"ker.fyuw","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old French couvrefeu = cover fire (couvrir=cover + feu=fire)","h":"CURFEW ends in F-E-W: at curfew, only a FEW people are still out.","t":["time"]},{"w":"custodian","d":"one having charge of buildings or grounds or animals","s":"The school custodian arrived early every morning to make sure the hallways were clean before students arrived.","p":"kuh-STOH-dee-uhn","o":"Latin","y":3,"bp":34,"m":"custodien","sy":"kah.stow.diy.ah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin custos = guard, keeper","h":"The custodIAN is the person who guards — remember, a person ends in -IAN.","t":["animals","buildings"]},{"w":"cyberspace","d":"the online world of computers and the internet","s":"Her video message zipped through cyberspace to her cousin in India.","p":"SY-bur-spays","o":"English","y":3,"bp":65,"ps":"noun","r":"Coined from Greek 'kybernetes' (steersman) + space.","h":"Cyberspace is the invisible space where the internet lives.","nt":"vocab-NWFinal-2026-Junior"},{"w":"disappoint","d":"fail to meet the hopes or expectations of","p":"dih-suh-POYNT","o":"French","y":3,"bp":34,"m":"dissapoint","sy":"dih.sah.poy.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"French désappointer = to remove from office","h":"Dis-ap-POINT: double P, one S — you need two P's to point a finger at disappointment."},{"w":"disarming","d":"act of reducing or depriving of arms","p":"dih-SAH-rmihng","o":"French","y":3,"bp":33,"m":"desarming","sy":"dih.saa.rmih.ng","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"French arme = weapon","h":"A disARMing smile takes the ARM out of harm — spell it with the word ARM inside."},{"w":"discolor","d":"lose color or turn colorless","p":"dih-SKUH-ler","o":"Latin","y":3,"bp":32,"m":"discolour","sy":"dih.skah.ler","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin dis-(apart/away) + color = color","h":"To disCOLOR is to lose COLOR — dis- steals the color right out of the word!","t":["colors"]},{"w":"discount","d":"an amount taken off the usual price","s":"The bookstore gave students a discount on dictionaries.","p":"DIS-kownt","o":"French","y":2,"bp":60,"ps":"noun","r":"French 'descompte' (a counting off), from Latin computare (to count).","h":"A discount counts some dollars off the price tag.","nt":"vocab-NWFinal-2026-Junior"},{"w":"disfavor","d":"the state of being out of favor","s":"He is in disfavor with the king.","p":"dih-SFAY-ver","o":"French","y":3,"bp":32,"m":"disfavour","sy":"dih.sfey.ver","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin favor = goodwill, support","h":"DIS the FAVOR — no goodwill here; remember, in American spelling it ends in -OR not -OUR."},{"w":"dishearten","d":"to discourage someone; to take away hope or courage","s":"Losing the first round didn't dishearten the young speller.","p":"dis-HAR-tuhn","o":"English","y":3,"bp":75,"ps":"verb","r":"dis- (away) + hearten — to take the heart out of someone.","h":"Dishearten steals the heart right out of your courage.","nt":"vocab-NWFinal-2026-Junior"},{"w":"dislocate","d":"move out of position","s":"The soccer player cried out in pain after a rough tackle caused him to dislocate his shoulder, forcing him to leave the field immediately.","p":"DIH-sloh-kayt","o":"Latin","y":3,"bp":33,"m":"dislocait","sy":"dih.slow.key.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin dis-(apart)+locare=to place, from locus=place","h":"Dislocate has LOCA (place) inside — your joint got moved out of its PLACE."},{"w":"dismantle","d":"tear down so as to make flat with the ground","p":"dih-SMA-ntuhl","o":"French","y":3,"bp":33,"m":"dismantel","sy":"dih.smae.ntah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"French démanteler = to remove a cloak/fortification","h":"To disMAN-TLE is to strip the MANTLE off — end with -TLE like 'little' pieces falling away."},{"w":"dispatch","d":"to send something or someone off quickly to a place or task","s":"The coach dispatched a runner to fetch more water bottles.","p":"dih-SPACH","o":"Italian","y":3,"bp":75,"ps":"verb","r":"Italian 'dispacciare' (to hurry, send off quickly).","h":"Dispatch means send it fast — off it goes, right now.","nt":"vocab-NWFinal-2026-Junior"},{"w":"displace","d":"to force something out of its place, or to take its place","s":"The flood displaced families, who stayed at the school gym.","p":"dis-PLAYS","o":"French","y":3,"bp":75,"ps":"verb","r":"French 'desplacer' — dis- (away) + place.","h":"Displace means to bump something out of its place.","nt":"vocab-NWFinal-2026-Junior"},{"w":"disposed","d":"willing or likely to act or feel a certain way; inclined","s":"After the fun assembly, the class felt disposed to work hard.","p":"dih-SPOHZD","o":"French","y":3,"bp":75,"ps":"adjective","r":"From Latin 'disponere' (to arrange), via French 'disposer'.","h":"If you're disposed to help, you're set up and willing to do it.","nt":"vocab-NWFinal-2026-Junior"},{"w":"dispossess","d":"deprive of the possession of real estate","s":"The landlord tried to dispossess the tenants after they stopped paying rent.","p":"dih-spuh-ZEHS","o":"French","y":3,"bp":34,"m":"dispossses","sy":"dih.spah.zeh.s","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin possidere = to possess","h":"To dispossess is to un-POSSESS — spot POSSESS inside and slap DIS in front; double S twice."},{"w":"disregard","d":"lack of attention and due care","p":"dih-srih-GAHRD","o":"French","y":3,"bp":33,"m":"disreguard","sy":"dih.srih.gaa.rd","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"French dis- = not + regarder = to look at/consider","h":"DISREGARD has REGARD inside — no 'u' after reg; just DIS the REGARD entirely."},{"w":"dissection","d":"cutting so as to separate into pieces","s":"The biology class performed a careful dissection of a frog during lab.","p":"deye-SEH-kshuhn","o":"Latin","y":3,"bp":34,"m":"disection","sy":"day.seh.kshah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin secare = to cut","h":"A disSECTion is a SECTION cut apart — double S signals the double cut of the blade."},{"w":"dissent","d":"Disagreement with an official or widely held opinion.","s":"One judge voiced her dissent when the other judges accepted the answer.","p":"dih-SENT","o":"Latin","y":3,"bp":72,"ps":"noun","r":"Latin dis- (apart) + sentire (to feel) — to feel differently.","h":"DIS-agree + conSENT flipped: you do NOT consent, you dissent.","nt":"vocab-NWFinal-2026-Junior"},{"w":"dissolve","d":"To mix completely into a liquid and seem to disappear.","s":"Watch the sugar dissolve when you stir it into warm lemonade.","p":"dih-ZAHLV","o":"Latin","y":2,"bp":75,"ps":"verb","r":"Latin dis- (apart) + solvere (to loosen) — loosened apart into liquid.","h":"Drop a sugar cube in water and it dissolves — melts away into the liquid.","nt":"vocab-NWFinal-2026-Junior","vh":"to"},{"w":"disused","d":"No longer used; abandoned.","s":"The disused railroad track behind the school is covered with weeds.","p":"dis-YOOZD","o":"French","y":3,"bp":65,"ps":"adjective","r":"Dis- (not) + use, from Old French user, from Latin uti (to use).","h":"DIS + USED: something people stopped using, like an empty old barn.","nt":"vocab-NWFinal-2026-Junior"},{"w":"divergent","d":"Moving or leading in different directions; differing from each other.","s":"The twins had divergent hobbies: one loved chess and the other loved soccer.","p":"dih-VUR-juhnt","o":"Latin","y":3,"bp":70,"ps":"adjective","r":"Latin dis- (apart) + vergere (to bend) — bending apart.","h":"Divergent paths split apart like the arms of the letter Y.","nt":"vocab-NWFinal-2026-Junior"},{"w":"diverse","d":"Made up of many different kinds; showing variety.","s":"Our class is diverse, with students whose families come from many countries.","p":"dih-VURS","o":"Latin","y":2,"bp":78,"ps":"adjective","r":"Latin diversus, 'turned different ways,' from divertere.","h":"A diverse group is like a fruit salad — many different kinds mixed together.","nt":"vocab-NWFinal-2026-Junior"},{"w":"diversity","d":"noticeable heterogeneity","s":"A diversity of possibilities.","p":"dih-VUR-sih-tee","o":"Latin","y":3,"bp":34,"m":"diversety","sy":"dih.ver.sah.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin diversus = turned different ways","h":"DIVERSity holds many DIVERS swimming in different directions — all apart from each other."},{"w":"divertible","d":"Able to be turned aside or sent in a different direction.","s":"The stream is divertible, so farmers can send its water toward their fields.","p":"dih-VUR-tuh-buhl","o":"Latin","y":4,"bp":60,"ps":"adjective","r":"Latin divertere (to turn aside) + -ible (able to be).","h":"DIVERT + IBLE: if traffic is divertible, it CAN be rerouted another way.","nt":"vocab-NWFinal-2026-Junior"},{"w":"divinity","d":"any supernatural being worshipped as controlling some part of the world or some aspect of life or who is the personification of a force","s":"Ancient Egyptians believed in the divinity of the Pharaohs.","p":"dih-VIH-nuh-tee","o":"Latin","y":3,"bp":33,"m":"divinety","sy":"dih.vih.nah.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin divinitas = divine nature","h":"DIVINITY ends in -ITY, not -ETY — the divine IT is in divinity.","t":["physics","religion"],"vh":"quality of being"},{"w":"documentary","d":"a film or TV program presenting the facts about a person or event","s":"After watching the documentary about wolves, Priya became passionate about wildlife conservation and started her own school club.","p":"dah-kyuh-MEH-nter-ee","o":"Latin","y":3,"bp":37,"m":"documentery","sy":"doc.u.men.ta.ry","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin documentum = lesson/proof, from docere = to teach","h":"A DOCUMENTary is based on DOCUMENTS — both start the same way."},{"w":"domesticate","d":"adapt (a wild plant or unclaimed land) to the environment","s":"Ancient farmers worked for countless generations to domesticate wild wheat, selectively breeding plants that produced larger seeds and grew more reliably in cultivated fields near their villages.","p":"duh-MEH-stuh-kayt","o":"Latin","y":3,"bp":36,"m":"domestikate","sy":"dah.meh.stah.key.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin domesticus = of the house","h":"To DOMESTICATE is to make something fit for the HOUSE — spot domus right at the front.","t":["botany","ecology"]},{"w":"donate","d":"To give money, goods, or time to help others.","s":"Our family will donate canned food to the school's holiday drive.","p":"DOH-nayt","o":"Latin","y":2,"bp":80,"ps":"verb","r":"Latin donare (to give), from donum (gift).","h":"A DONor DONates — gives a gift to help, expecting nothing back.","nt":"vocab-NWFinal-2026-Junior"},{"w":"download","d":"To copy data or a file from the internet onto your own device.","s":"Dad let me download the study app onto the tablet before the bee.","p":"DOWN-lohd","o":"English","y":2,"bp":70,"ps":"verb","r":"English down + load — loading data 'down' from a network to your device.","h":"Files come DOWN from the internet and LOAD onto your computer.","nt":"vocab-NWFinal-2026-Junior"},{"w":"dowry","d":"Money or property a bride's family gives at her marriage.","s":"In the folktale, the princess brought a dowry of gold and land.","p":"DOW-ree","o":"French","y":3,"bp":68,"ps":"noun","r":"Old French douaire, from Latin dos (gift, marriage portion).","h":"Think 'endow': a dowry endows the new couple with wedding wealth.","nt":"vocab-NWFinal-2026-Junior"},{"w":"dramatist","d":"One who writes plays.","s":"The dramatist watched nervously as students performed her new play.","p":"DRAM-uh-tist","o":"Greek","y":3,"bp":72,"ps":"noun","r":"Greek drama (action, play) + -ist (one who does).","h":"DRAMA + IST: a person whose job is writing the drama, like Shakespeare.","nt":"vocab-NWFinal-2026-Junior","vh":"one who"},{"w":"drudgery","d":"Hard, dull, tiring work.","s":"Scrubbing every pot after the class party felt like pure drudgery.","p":"DRUH-juh-ree","o":"Old English","y":3,"bp":70,"ps":"noun","r":"From drudge, related to Old English dreogan (to work, endure).","h":"A drudge trudges through boring chores — drudgery is that dreary work.","nt":"vocab-NWFinal-2026-Junior"},{"w":"dub","d":"To give someone or something a name, title, or nickname.","s":"After his winning streak, classmates dubbed him the Word Wizard.","p":"DUHB","o":"Old English","y":3,"bp":68,"ps":"verb","r":"Old English dubbian, to make a knight by tapping with a sword.","h":"A queen taps a knight's shoulder and dubs him 'Sir' — naming with a title.","nt":"vocab-NWFinal-2026-Junior"},{"w":"duet","d":"A musical composition for two performers.","s":"My sister and I practiced a piano duet for the family concert.","p":"doo-ET","o":"Italian","y":2,"bp":75,"ps":"noun","r":"Italian duetto, from duo (two), from Latin duo.","h":"DUO in duet: music for exactly TWO people, like a two-singer song.","nt":"vocab-NWFinal-2026-Junior","vh":"A composition for"},{"w":"dupe","d":"To trick or fool someone.","s":"The fake email tried to dupe people into giving away their passwords.","p":"DOOP","o":"French","y":3,"bp":70,"ps":"verb","r":"French dupe, a fooled person, probably from a word for the hoopoe bird, thought silly.","h":"If you're duped, you've been scooped into a trick — fooled completely.","nt":"vocab-NWFinal-2026-Junior"},{"w":"duplicity","d":"a fraudulent or duplicitous representation","s":"The spy's duplicity was finally exposed when agents discovered he had been working for both sides.","p":"doo-PLIH-sih-tee","o":"Latin","y":3,"bp":34,"m":"duplicaty","sy":"duw.plih.sih.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin duplicitas = doubleness, from duplex = twofold","h":"DUPLICITY ends in -CITY like a city of liars — two-faced people hide in DUPLI-CITY."},{"w":"dutiful","d":"Carefully doing what one is expected to do; obedient and responsible.","s":"The dutiful student finished every practice list her coach assigned.","p":"DOO-tih-fuhl","o":"French","y":2,"bp":72,"ps":"adjective","r":"Duty, from Anglo-French dueté (what is owed), + -ful.","h":"DUTY + FULL: full of duty — always doing your chores and homework.","nt":"vocab-NWFinal-2026-Junior"},{"w":"dynamo","d":"A machine that turns motion into electricity; also a very energetic person.","s":"The bike's dynamo powered its headlight as she pedaled home.","p":"DY-nuh-moh","o":"Greek","y":3,"bp":68,"ps":"noun","r":"Greek dynamis (power), shortened from 'dynamo-electric machine.'","h":"Dynamite and dynamo share 'power': a dynamo generates electric power or human energy.","nt":"vocab-NWFinal-2026-Junior"},{"w":"dysfunctional","d":"impaired in function; especially of a bodily system or organ","p":"dih-SFUH-ngkshuh-nuhl","o":"French","y":3,"bp":37,"m":"disfunctional","sy":"dih.sfah.ngkshah.nah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Greek dys = bad + Latin functio = performance","h":"DYSfunctional = dysfunctional family: dys + functional, the word functional is hiding inside.","t":["music"]},{"w":"earnest","d":"something of value given by one person to another to bind a contract","s":"Both sides were deeply in earnest, even passionate.","p":"UR-nihst","o":"Old English","y":3,"bp":67,"m":"ernest","sy":"er.nih.st","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old English eornost = seriousness, zeal","h":"Be EARNEST — the word has EARN inside it, reminding you that sincerity takes real effort.","t":["law"]},{"w":"earthenware","d":"Dishes, pots, and containers made of baked clay.","s":"Grandma serves curry in earthenware bowls she bought at the craft fair.","p":"UR-thuhn-wair","o":"Old English","y":3,"bp":70,"ps":"noun","r":"Old English eorthe (earth) + waru (goods) — goods made of earth.","h":"EARTH + WARE: 'wares' (goods) made from earth — clay baked into pottery.","nt":"vocab-NWFinal-2026-Junior","vh":"made of"},{"w":"eccentricity","d":"strange and unconventional behavior","s":"A circle is an ellipse with zero eccentricity.","p":"eh-ksuh-NTRIH-suh-tee","o":"French","y":3,"bp":38,"m":"excentricity","sy":"eh.ksah.ntrih.sah.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek ekkentros = out of center","h":"ECCENTRICIty — the word ECCENTRIC is hiding right at the start; just add -ITY."},{"w":"eclipse","d":"To block the light of; to outshine or overshadow.","s":"This year's science fair may eclipse last year's with twice as many projects.","p":"ih-KLIPS","o":"Greek","y":3,"bp":74,"ps":"verb","r":"Greek ekleipsis (abandonment, failing to appear), from ekleipein.","h":"The moon eclipses the sun by covering it — to eclipse is to overshadow.","nt":"vocab-NWFinal-2026-Junior","vh":"to"},{"w":"edible","d":"any substance that can be used as food","s":"The survival guide listed which wild plants were edible and which were poisonous.","p":"EH-duh-buhl","o":"Latin","y":2,"bp":42,"m":"edable","sy":"eh.dah.bah.l","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin edibilis, from edere = to eat","h":"Is it EDIBLE? You can EAT it — E-D-I-B-L-E, note the 'i' before 'ble'."},{"w":"effect","d":"A result; a change that something causes.","s":"Extra sleep before the bee had a great effect on my focus.","p":"ih-FEKT","o":"Latin","y":2,"bp":78,"ps":"noun","r":"Latin effectus, from efficere (to bring about).","h":"Cause and Effect: the effect is what happens BECAUSE of the cause.","nt":"vocab-NWFinal-2026-Junior"},{"w":"efficiency","d":"the ratio of the output to the input of any system","s":"She did the work with great efficiency.","p":"ih-FIH-shuh-nsee","o":"Latin","y":3,"bp":35,"m":"efficency","sy":"ih.fih.shah.nsiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin efficientia = effectiveness","h":"EFFICIENCY: spell out 'ef-FIC-i-ency' — FIC like FICTION, but efficiency is no fiction when it saves time."},{"w":"egocentric","d":"a self-centered person with little regard for others","s":"The egocentric team captain always took credit for victories but blamed teammates for every loss.","p":"ee-goh-SEH-ntrihk","o":"Latin","y":3,"bp":35,"m":"egosentrik","sy":"iy.gow.seh.ntrih.k","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin ego = I + centrum = center","h":"An EGO-CENTRIC person puts their EGO at the CENTER of everything — ego+center+ic."},{"w":"egoist","d":"A self-centered person who thinks mainly about himself or herself.","s":"An egoist grabs all the credit even when the whole team worked together.","p":"EE-goh-ist","o":"Latin","y":3,"bp":68,"ps":"noun","r":"Latin ego (I) + -ist — a person all about 'I.'","h":"EGO means 'I' — an egoist's favorite topic is I, me, and myself.","nt":"vocab-NWFinal-2026-Junior"},{"w":"eject","d":"To push, throw, or force out.","s":"The umpire had to eject the coach who kept yelling at the players.","p":"ih-JEKT","o":"Latin","y":2,"bp":74,"ps":"verb","r":"Latin e- (out) + jacere (to throw) — to throw out.","h":"The DVD player's EJECT button pushes the disc OUT — eject means throw out.","nt":"vocab-NWFinal-2026-Junior"},{"w":"elated","d":"Extremely happy and excited.","s":"She was elated when her name was called for the final round.","p":"ih-LAY-tid","o":"Latin","y":3,"bp":76,"ps":"adjective","r":"Latin elatus (lifted up), from efferre (to carry out or up).","h":"Elated means lifted up with joy — so happy you feel elevated, floating.","nt":"vocab-NWFinal-2026-Junior"},{"w":"element","d":"A basic or essential part of something.","s":"Practice is the most important element of winning any competition.","p":"EL-uh-muhnt","o":"Latin","y":2,"bp":70,"ps":"noun","r":"Latin elementum (first principle, basic part).","h":"Elements are the building blocks — the basic pieces that make up the whole.","nt":"vocab-NWFinal-2026-Junior"},{"w":"elite","d":"the choice or the best of anything","p":"ih-l-EE-t","o":"French","y":3,"bp":50,"m":"ellite","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"French élite = chosen, from élire = to choose","h":"The ELITE are chosen — spell it with one 'l' like a lean, selective group that doesn't need extras."},{"w":"elongate","d":"make long or longer by pulling and stretching","s":"The potter used her skilled hands to carefully elongate the lump of clay on the spinning wheel, shaping it into a tall, graceful vase.","p":"ih-LAW-nggayt","o":"Latin","y":3,"bp":32,"m":"ellogate","sy":"ih.lao.nggey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin elongare = ex+longus = out + long","h":"ELONGATE: spot LONG right in the middle — to elongate is to make something LONG."},{"w":"encore","d":"An extra performance given after the audience calls for more.","s":"The crowd clapped so long that the band played an encore.","p":"AHN-kor","o":"French","y":3,"bp":72,"ps":"noun","r":"French encore, meaning 'again, still more.'","h":"French for 'again!' — fans shout 'Encore!' to hear one more song.","nt":"vocab-NWFinal-2026-Junior"},{"w":"encyclopedia","d":"a reference work (often in several volumes) containing articles on various topics (often arranged in alphabetical order) dealing with the entire range of human knowledge or with some particular specialty","s":"Whenever Jake had a history question, he reached for the heavy encyclopedia on the shelf.","p":"ih-nseye-kluh-PEE-dee-uh","o":"Latin","y":3,"bp":40,"m":"encyclopeida","sy":"ih.nsay.klah.piy.diy.ah","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek enkyklios paideia = general education","h":"An enCYCLOpedia covers knowledge in a full CYCLE — remember the CYCLO in the middle.","t":["logic","wordwords"]},{"w":"endanger","d":"pose a threat to; present a danger to","s":"The pollution is endangering the crops.","p":"eh-NDAY-njer","o":"French","y":3,"bp":32,"m":"indanger","sy":"eh.ndey.njher","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"French danger = power, peril","h":"To endanger is to put something IN DANGER — en-DANGER spells it out exactly."},{"w":"endurance","d":"the power to withstand hardship or stress","s":"The marathon tests a runner's endurance.","p":"EH-nder-uhns","o":"Latin","y":3,"bp":33,"m":"endurence","sy":"eh.nder.ah.ns","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin durare = to last, harden","h":"ENDURANCE ends in ANCE — runners with endurANCE do not quit at the DANCE."},{"w":"engross","d":"To take up someone's whole attention; absorb completely.","s":"The mystery novel would engross him so much he missed the dinner call.","p":"en-GROHS","o":"French","y":3,"bp":70,"ps":"verb","r":"From French en gros (in large amount) — to take up wholly.","h":"Engrossed in a book means the story has grabbed your WHOLE attention.","nt":"vocab-NWFinal-2026-Junior"},{"w":"enlist","d":"To sign up to join, especially the military; to get someone's help.","s":"My uncle decided to enlist in the navy right after high school.","p":"en-LIST","o":"English","y":3,"bp":70,"ps":"verb","r":"En- (in) + list — to put your name on the official list.","h":"To enlist is to get ON THE LIST — signing up to serve or help.","nt":"vocab-NWFinal-2026-Junior"},{"w":"entail","d":"To involve or require as a necessary part.","s":"Joining the swim team entails early morning practices twice a week.","p":"en-TAYL","o":"French","y":3,"bp":70,"ps":"verb","r":"En- + Old French taille (a cut, a set limit) — to fix as a condition.","h":"What a job entails is what comes attached to it — like a tail it drags along.","nt":"vocab-NWFinal-2026-Junior"},{"w":"enthuse","d":"To show great excitement, or to fill someone with eager interest.","s":"The coach enthused about our progress until the whole team felt unstoppable.","p":"en-THOOZ","o":"Greek","y":3,"bp":66,"ps":"verb","r":"Back-formed from enthusiasm, from Greek entheos (inspired, having a god within).","h":"Enthuse is enthusiasm in action — bubbling over with excitement about something.","nt":"vocab-NWFinal-2026-Junior"},{"w":"entirety","d":"the state of being total and complete","s":"He read the article in its entirety.","p":"ih-NTEYE-er-tee","o":"French","y":3,"bp":33,"m":"entireity","sy":"ih.ntay.er.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin integritas = wholeness","h":"ENTIRETY: the ENTIRE word has no extra I — entireTY not entireITY."},{"w":"epic","d":"A long poem or story about heroes and their great deeds.","s":"We read part of an ancient epic about a hero's long sea voyage.","p":"EH-pik","o":"Greek","y":2,"bp":74,"ps":"noun","r":"Greek epos (word, song, poem).","h":"The Odyssey and Ramayana are epics — giant hero tales told in verse.","nt":"vocab-NWFinal-2026-Junior"},{"w":"equate","d":"To consider two things equal or the same.","s":"Don't equate one bad quiz score with being bad at math.","p":"ih-KWAYT","o":"Latin","y":3,"bp":70,"ps":"verb","r":"Latin aequare (to make level), from aequus (equal).","h":"Equate holds an EQUALS sign: saying this thing = that thing.","nt":"vocab-NWFinal-2026-Junior"},{"w":"equinox","d":"A day when daytime and nighttime are equal in length.","s":"Our teacher explained that spring officially begins at the March equinox.","p":"EE-kwuh-nahks","o":"Latin","y":3,"bp":74,"ps":"noun","r":"Latin aequus (equal) + nox (night) — equal night.","h":"EQUI (equal) + NOX (night): the day when night equals day.","nt":"vocab-NWFinal-2026-Junior"},{"w":"equivalent","d":"a person or thing equal to another in value or measure or force or effect or significance","s":"One hour of tutoring was the equivalent of twenty dollars, so helping four students earned him eighty dollars.","p":"ih-KWIH-vuh-luhnt","o":"Latin","y":3,"bp":35,"m":"equivelant","sy":"e.quiv.a.lent","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin aequivalere = to be equal in value, from aequus = equal + valere = to be worth","h":"eQUIVAlent — it's EQUAL in VALUE, just squish those words together","t":["physics","numbers"]},{"w":"essence","d":"The most important quality that makes something what it is.","s":"Kindness is the essence of good sportsmanship, win or lose.","p":"EH-suhns","o":"Latin","y":3,"bp":72,"ps":"noun","r":"Latin essentia, from esse (to be) — the 'being' of a thing.","h":"The essence is the essential heart of something — its true core.","nt":"vocab-NWFinal-2026-Junior"},{"w":"evict","d":"To legally force someone to move out of a home or property.","s":"The landlord threatened to evict the tenants who never paid rent.","p":"ih-VIKT","o":"Latin","y":3,"bp":70,"ps":"verb","r":"Latin evincere (to conquer, recover by law), from e- + vincere (to win).","h":"Evicted means kicked out of the building — E for exit, forced by law.","nt":"vocab-NWFinal-2026-Junior"},{"w":"excise","d":"a tax that is measured by the amount of business done (not on property or income from real estate)","p":"eh-KSEYES","o":"Dutch","y":3,"bp":66,"m":"exsize","sy":"eh.ksay.s","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Dutch excijs = tax","h":"'Excise' tax CUTS into your wallet — both meanings (tax and cut out) share the same spelling with a sharp 'c'.","t":["economy","numbers"]},{"w":"excitable","d":"easily excited","s":"The excitable puppy barked and spun in circles every time someone knocked on the front door.","p":"ih-KSEYE-tuh-buhl","o":"Latin","y":3,"bp":34,"m":"excitible","sy":"ih.ksay.tah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin excitare = to rouse","h":"'Excitable' ends in '-able' not '-ible' — remember: you ARE ABLE to get excited, so use '-able'!"},{"w":"executor","d":"a person appointed by a testator to carry out the terms of the will","s":"As the executor of her grandmother's will, Maria was responsible for making sure every family member received their inheritance.","p":"ih-GZEH-kyuh-ter","o":"Latin","y":3,"bp":33,"m":"executer","sy":"ih.gzeh.kyah.ter","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin executor = one who carries out, from exsequi","h":"An execuTOR carries out a will — tor like a TOWER of legal authority, not -ter."},{"w":"exhaustible","d":"Capable of being completely used up.","s":"Oil is an exhaustible resource, so scientists study wind and solar power.","p":"ig-ZAWS-tuh-buhl","o":"Latin","y":4,"bp":62,"ps":"adjective","r":"Latin exhaurire (to drain out) + -ible (able to be).","h":"EXHAUST + IBLE: like a tired runner, a supply that CAN run out.","nt":"vocab-NWFinal-2026-Junior","vh":"capable of being"},{"w":"exhaustion","d":"extreme fatigue","s":"After swimming fifty laps, Maya collapsed on the bench in complete exhaustion.","p":"ih-GZAW-schuhn","o":"Latin","y":3,"bp":34,"m":"exaustion","sy":"ih.gzao.schah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin exhaurire = to drain out","h":"EXHAUSTION drains everything — don't forget to drain the silent 'h' right after 'ex'."},{"w":"exists","d":"Is real; has actual being.","s":"Scientists debate whether life exists on other planets.","p":"ig-ZISTS","o":"Latin","y":2,"bp":65,"ps":"verb","r":"Latin existere (to come forth, appear), from ex- + sistere (to stand).","h":"If it exists, it's really there — not imaginary, not make-believe.","nt":"vocab-NWFinal-2026-Junior"},{"w":"expand","d":"To grow larger; to spread out.","s":"The balloon began to expand as we pumped more air into it.","p":"ik-SPAND","o":"Latin","y":2,"bp":76,"ps":"verb","r":"Latin ex- (out) + pandere (to spread) — to spread out.","h":"Expand starts with EX (out) — things spread OUT and get bigger.","nt":"vocab-NWFinal-2026-Junior"},{"w":"expect","d":"To believe something will happen or arrive.","s":"We expect the results of the vocabulary bee to be posted tonight.","p":"ik-SPEKT","o":"Latin","y":2,"bp":72,"ps":"verb","r":"Latin exspectare (to look out for), from ex- + spectare (to look).","h":"Expecting means looking ahead for it — you think it's coming.","nt":"vocab-NWFinal-2026-Junior"},{"w":"expend","d":"To use up or spend money, time, or energy.","s":"Don't expend all your energy in the first lap of the race.","p":"ik-SPEND","o":"Latin","y":3,"bp":68,"ps":"verb","r":"Latin expendere (to weigh out, pay), from ex- + pendere (to weigh).","h":"Expend hides SPEND: you spend effort or money until it's used up.","nt":"vocab-NWFinal-2026-Junior"},{"w":"expense","d":"The cost of something; money spent.","s":"New soccer cleats were a big expense, so I took care of them.","p":"ik-SPENS","o":"Latin","y":2,"bp":70,"ps":"noun","r":"Latin expensa (money paid out), from expendere (to pay out).","h":"An expense is what you EXPEND — the money a purchase costs you.","nt":"vocab-NWFinal-2026-Junior"},{"w":"extrapolate","d":"to draw conclusions about an unknown situation by extending or projecting known information","s":"Using the data from three months of rainfall, the scientist was able to extrapolate the annual precipitation for the entire region.","p":"eh-KSTRA-puh-layt","o":"Latin","y":3,"bp":36,"m":"extrapulate","sy":"ex.trap.o.late","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin extra = outside + polire = to polish, smooth; modeled on interpolate","h":"EXTRApolate goes EXTRA beyond the data to predict what comes next","t":["logic"]},{"w":"extraterrestrial","d":"a form of life assumed to exist outside the Earth or its atmosphere","s":"Is there extraterrestrial life?","p":"eh-kstruh-ter-EH-stree-uhl","o":"Latin","y":3,"bp":43,"m":"extraterrestial","sy":"eh.kstrah.ter.eh.striy.ah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin extra = outside + terrestris = of the earth","h":"EXTRATERRESTRIAL hides TERRESTRIAL inside — find TERRA (earth) and add the full suffix -AL."},{"w":"extravagance","d":"the spending of far more money than is needed; lavishness.","s":"We were surprised by the extravagance of his description.","p":"eh-KSTRA-vuh-guhns","o":"French","y":3,"bp":37,"m":"extravagence","sy":"ih.kstrae.vah.gah.ns","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin extra = outside + vagari = to wander","h":"EXTRAVAGANCE ends in -ANCE not -ENCE — a lavish DANCE of excess; remember the A in the dance.","t":["logic"]},{"w":"extravagant","d":"wildly exaggerated often to the point of absurdity","s":"The birthday party was so extravagant, with a live band, an ice sculpture, and a five-tiered cake, that the guests couldn't stop talking about it for the rest of the school year.","p":"ih-k-s-t-r-A-v-uh-g-uh-n-t","o":"English","y":2,"bp":42,"m":"extravagent","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin extravagari = to wander beyond (extra- = beyond + vagari = to wander)","h":"An EXTRAVAGANT spender wanders EXTRA far — end it with -ANT not -ENT, like an extravagant ANT on a shopping spree."},{"w":"facade","d":"the front of a building","s":"The crumbling facade of the old theater hid a beautifully restored interior.","p":"f-uh-s-AH-d","o":"French","y":3,"bp":50,"m":"fasade","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"French façade = front of building, from face = face","h":"A FACADE has a 'c' hiding behind the 'a' — just like a fake front hides the truth.","t":["buildings"]},{"w":"fancier","d":"A person with a special interest in something, especially breeding animals or plants.","s":"The pigeon fancier proudly showed us the birds he raises in his backyard.","p":"FAN-see-ur","o":"Greek","y":4,"bp":62,"ps":"noun","r":"From fancy, shortened from fantasy, ultimately Greek phantasia (imagination).","h":"A dog fancier really FANCIES (loves) dogs — a devoted hobbyist and breeder.","nt":"vocab-NWFinal-2026-Junior"},{"w":"faulty","d":"Having a flaw or defect; not working correctly.","s":"The faulty microphone kept cutting out during the school announcements.","p":"FAWL-tee","o":"French","y":2,"bp":72,"ps":"adjective","r":"From fault, Old French faute (lack, failing), from Latin fallere (to deceive).","h":"FAULT + Y: full of faults — a faulty toy breaks or won't work right.","nt":"vocab-NWFinal-2026-Junior"},{"w":"feminism","d":"a doctrine that advocates equal rights for women","s":"Her grandmother marched in rallies for feminism in the 1970s, fighting for equal pay and opportunities in the workplace.","p":"FEH-mih-nih-zuhm","o":"Latin","y":3,"bp":33,"m":"femenism","sy":"feh.mih.nih.zah.m","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin femina = woman + -ism = doctrine","h":"FEMINISM — the I holds firm in the middle: fem-I-n-ism, like an equal sign.","t":["logic"]},{"w":"ferocious","d":"marked by extreme and violent energy","s":"The ferocious thunderstorm snapped ancient oak trees like twigs and flooded the entire valley overnight.","p":"fer-OH-shuhs","o":"Latin","y":1,"bp":41,"m":"ferocous","sy":"fe.ro.cious","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin ferox = fierce, wild, from ferus = wild beast","h":"FEROCIOUS has a ROAR right in the middle — fer-OC-ious","t":["physics"]},{"w":"fickle","d":"Often changing one's mind or loyalty; not constant.","s":"My fickle friend cheered for a different team every single week.","p":"FIH-kuhl","o":"Old English","y":3,"bp":72,"ps":"adjective","r":"Old English ficol (deceitful, tricky).","h":"Fickle flickers like a candle — feelings that switch back and forth.","nt":"vocab-NWFinal-2026-Junior"},{"w":"fiesta","d":"A festival or lively celebration.","s":"The whole neighborhood came out for the fiesta with music and food stalls.","p":"fee-ES-tuh","o":"Spanish","y":2,"bp":72,"ps":"noun","r":"Spanish fiesta (feast, festival), from Latin festa.","h":"Fiesta sounds like FEAST — a big festive party with food and dancing.","nt":"vocab-NWFinal-2026-Junior"},{"w":"figurative","d":"(used of the meanings of words or text) not literal; using figures of speech","s":"When the coach said the team had a mountain to climb, he was speaking in a figurative sense, not planning an actual hike.","p":"FIH-gyer-uh-tihv","o":"Latin","y":3,"bp":35,"m":"figuritive","sy":"fig.ur.a.tive","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin figura = form, shape, from fingere = to shape","h":"A FIGURE of speech is FIGURAtive language","t":["wordwords"]},{"w":"finite","d":"Having limits; able to be counted or come to an end.","s":"We had a finite amount of time, so we practiced the hardest words first.","p":"FY-nyt","o":"Latin","y":3,"bp":72,"ps":"adjective","r":"Latin finitus (limited), from finis (end, boundary).","h":"Finite has FINISH in its roots — it can be finished; it has an end.","nt":"vocab-NWFinal-2026-Junior"},{"w":"florist","d":"One who sells or arranges flowers.","s":"Mom asked the florist to make a bouquet for Grandma's birthday.","p":"FLOR-ist","o":"Latin","y":2,"bp":76,"ps":"noun","r":"Latin flos, floris (flower) + -ist (one who works with).","h":"FLORal + IST: the flower person — their shop is full of blossoms.","nt":"vocab-NWFinal-2026-Junior","vh":"one who"},{"w":"fragrant","d":"having a sweet smell or pleasing odor","s":"The fragrant roses in Grandma's garden filled the whole yard with a sweet, lovely smell.","p":"f-r-AY-g-r-uh-n-t","o":"Latin","y":2,"bp":41,"m":"flagrant","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin fragrare = to smell sweet","h":"FRAGRANT has a hidden FRAGRANCE in it — both start with F-R-A-G-R; smell the 'gr' at the center twice."},{"w":"fraternal","d":"of or relating to a fraternity or society of usually men","s":"The two brothers shared a deep fraternal bond that had been strengthened over years of playing sports together, solving problems, and supporting each other through difficult times.","p":"fruh-TUR-nuhl","o":"French","y":3,"bp":33,"m":"fraternul","sy":"frah.ter.nah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin fraternus = of a brother, from frater = brother","h":"FRATERNAL ends in -al not -ul — frater+NAL, brothers are NATURAL allies, end with AL."},{"w":"fraud","d":"Dishonest trickery, usually to gain money; also a person who fakes.","s":"The news warned families about an online fraud that steals payment details.","p":"FRAWD","o":"Latin","y":3,"bp":72,"ps":"noun","r":"Latin fraus, fraudis (deceit, injury).","h":"A fraud is a cheat — fake goods or fake people pretending for money.","nt":"vocab-NWFinal-2026-Junior"},{"w":"fraudulent","d":"intended to deceive","s":"The fraudulent website tricked hundreds of shoppers into paying for products that never arrived.","p":"FRAW-juh-luhnt","o":"Latin","y":3,"bp":34,"m":"fraudulant","sy":"frau.du.lent","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin fraus/fraudis = deceit, trick","h":"FRAUDulent people commit FRAUD"},{"w":"frenzy","d":"Wild, uncontrolled excitement or activity.","s":"The classroom broke into a frenzy when the snow day was announced.","p":"FREN-zee","o":"Greek","y":3,"bp":72,"ps":"noun","r":"Greek phrenitis (brain inflammation, madness), from phren (mind).","h":"A frenzy is frantic energy — everyone rushing around wildly at once.","nt":"vocab-NWFinal-2026-Junior"},{"w":"frigid","d":"Extremely cold.","s":"We wore two pairs of gloves in the frigid January wind.","p":"FRIH-jid","o":"Latin","y":3,"bp":74,"ps":"adjective","r":"Latin frigidus, from frigere (to be cold).","h":"Frigid sounds like FRIDGE — freezing cold, like inside a freezer.","nt":"vocab-NWFinal-2026-Junior"},{"w":"functional","d":"designed for or capable of a particular function or use","s":"A style of writing in which every word is functional.","p":"FUH-ngkshuh-nuhl","o":"French","y":3,"bp":34,"m":"funtional","sy":"fah.ngkshah.nah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin functio = performance","h":"FUNCTional things actually FUNCTION — keep the 'c' in place or it stops working."},{"w":"further","d":"To a greater distance or degree; additional.","s":"The coach said we need further practice before the state finals.","p":"FUR-thur","o":"Old English","y":2,"bp":65,"ps":"adverb","r":"Old English furthor, related to forth (forward).","h":"Further pushes FORTH — going more, extra, beyond where you are.","nt":"vocab-NWFinal-2026-Junior"},{"w":"futile","d":"Useless; certain to fail.","s":"Arguing with the referee was futile; the call would not change.","p":"FYOO-tuhl","o":"Latin","y":3,"bp":76,"ps":"adjective","r":"Latin futilis (leaky, worthless) — like a jar that pours everything out.","h":"A futile effort has no future — pointless, like bailing a leaky boat with a fork.","nt":"vocab-NWFinal-2026-Junior"},{"w":"gaily","d":"In a merry, cheerful way.","s":"The children skipped gaily down the hall on the last day of school.","p":"GAY-lee","o":"French","y":3,"bp":66,"ps":"adverb","r":"From French gai (merry, joyful) + -ly.","h":"Done gaily is done gleefully — with smiles, songs, and skipping.","nt":"vocab-NWFinal-2026-Junior"},{"w":"gala","d":"A big festive celebration or special public party.","s":"The school held a gala to celebrate its hundredth anniversary.","p":"GAY-luh","o":"Italian","y":3,"bp":70,"ps":"noun","r":"Italian gala (festive dress, festivity), via French.","h":"A gala is a grand party — fancy clothes, music, and celebration.","nt":"vocab-NWFinal-2026-Junior"},{"w":"garnish","d":"To decorate food with something extra, like herbs.","s":"The chef garnished each plate with a sprig of fresh mint.","p":"GAR-nish","o":"French","y":3,"bp":70,"ps":"verb","r":"Old French garnir (to equip, adorn).","h":"The parsley on the plate is the garnish — a decoration to dress up food.","nt":"vocab-NWFinal-2026-Junior"},{"w":"genetics","d":"the branch of biology that studies heredity and variation in organisms","s":"Her fascination with genetics led her to study how inherited traits are passed from parents to children.","p":"juh-NEH-tihks","o":"Greek","y":3,"bp":32,"m":"genettics","sy":"jhah.neh.tih.ks","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek genesis = origin, birth","h":"GENETICS begins with GENE — because genes are what this science is all about."},{"w":"ghoul","d":"an evil demon a grave-robber","s":"The horror story described a ghoul that lurked in graveyards and fed on the remains of the dead.","p":"g-OO-l","o":"English","y":3,"bp":44,"m":"goul","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Arabic ghūl = evil spirit that robs graves","h":"A GHOUL hides a silent 'h' just like it hides in graveyards — G-H-O-U-L."},{"w":"gigabyte","d":"a unit of information equal to 1000 megabytes or 10^9 (1,000,000,000) bytes","s":"A single gigabyte of storage can hold thousands of photos or several hours of recorded music.","p":"GIH-guh-beyet","o":"Greek","y":3,"bp":32,"m":"gigabite","sy":"gih.gah.bay.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek gigas = giant + English byte = 8 bits","h":"GIGAbYTE — a GIGA giant BYTE bites into your storage; don't lose the Y.","t":["numbers"]},{"w":"gimmick","d":"a clever trick or novel device meant to attract attention or increase appeal","s":"The new phone plan seemed perfect until Marcus discovered the gimmick buried in the fine print—he'd be charged double after six months.","p":"GIH-mihk","y":1,"bp":34,"m":"gimmik","sy":"gim.mick","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"noun","r":"origin uncertain; possibly from magicians' slang","h":"Double the m, double the trick"},{"w":"glacier","d":"A huge mass of ice that moves slowly over land.","s":"On our Alaska trip we watched a glacier crack and drop ice into the sea.","p":"GLAY-shur","o":"French","y":2,"bp":74,"ps":"noun","r":"French glacier, from glace (ice), from Latin glacies.","h":"A glacier is a slow-motion river of ice sliding down a mountain.","nt":"vocab-NWFinal-2026-Junior"},{"w":"globalize","d":"make world-wide in scope or application","s":"Markets are being increasingly globalized.","p":"GLOH-buh-leyez","o":"Latin","y":3,"bp":33,"m":"globalise","sy":"glow.bah.lay.z","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin globus = sphere, ball","h":"To GLOBALIZE is to make things GLOBE-sized — keep the E from globe and add -IZE."},{"w":"glucose","d":"a monosaccharide sugar that has several forms; an important source of physiological energy","s":"After the long cross-country race, the coach handed out orange slices to help the runners replenish their glucose levels quickly.","p":"GLOO-kohs","o":"Greek","y":1,"bp":38,"m":"gluclose","sy":"glu.cose","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek gleukos = sweet wine, must","h":"Glucose gives you glue-like energy to stick to your day","t":["physics"]},{"w":"gratify","d":"To please or satisfy someone.","s":"It gratified Dad to see how hard I studied for the finals.","p":"GRAT-uh-fy","o":"Latin","y":3,"bp":68,"ps":"verb","r":"Latin gratus (pleasing) + facere (to make) — to make pleased.","h":"Gratify shares roots with GRATEFUL — to give pleasure or satisfaction.","nt":"vocab-NWFinal-2026-Junior"},{"w":"grave","d":"Very serious and worrying.","s":"Scientists say the greenhouse effect poses a grave threat to polar ice.","p":"GRAYV","o":"Latin","y":3,"bp":74,"ps":"adjective","r":"Latin gravis (heavy, serious) — a 'weighty' matter.","h":"A grave problem is heavy and serious — grave faces, no joking.","nt":"vocab-NWFinal-2026-Junior","vh":"greenhouse effect"},{"w":"grim","d":"Gloomy, stern, or without hope or cheer.","s":"The team wore grim expressions after losing the championship game.","p":"GRIM","o":"Old English","y":2,"bp":72,"ps":"adjective","r":"Old English grimm (fierce, savage).","h":"A grim face is a frown with zero smiles — dark, stern, and gloomy.","nt":"vocab-NWFinal-2026-Junior"},{"w":"grindstone","d":"A revolving stone wheel used for sharpening or grinding tools.","s":"The blacksmith sharpened the axe on a spinning grindstone.","p":"GRYND-stohn","o":"Old English","y":3,"bp":66,"ps":"noun","r":"Old English grindan (to grind) + stan (stone).","h":"'Nose to the grindstone' — the stone wheel workers bend over to sharpen blades.","nt":"vocab-NWFinal-2026-Junior"},{"w":"guess","d":"To give an answer or opinion without being sure.","s":"If you don't know the meaning, make your best guess and move on.","p":"GES","o":"Norse","y":2,"bp":65,"ps":"verb","r":"Middle English gessen, likely from Old Norse, related to 'get.'","h":"A guess is a try without proof — your brain's best estimate.","nt":"vocab-NWFinal-2026-Junior"},{"w":"guise","d":"An outward appearance that hides what something really is.","s":"In the story, the wolf approached in the guise of a friendly grandmother.","p":"GYZ","o":"French","y":4,"bp":68,"ps":"noun","r":"Old French guise (manner, way), from a Germanic root.","h":"Guise hides in disGUISE — a costume of appearance masking the truth.","nt":"vocab-NWFinal-2026-Junior"},{"w":"gusty","d":"Blowing in sudden, strong bursts of wind.","s":"The gusty weather kept knocking over our badminton net.","p":"GUH-stee","o":"Norse","y":2,"bp":68,"ps":"adjective","r":"From gust, Old Norse gustr (a cold blast of wind).","h":"A gusty day comes in GUSTS — whoosh, calm, then whoosh again.","nt":"vocab-NWFinal-2026-Junior"},{"w":"habitat","d":"the type of environment in which an organism or group normally lives or occurs","s":"The wildlife documentary showed how deforestation was rapidly destroying the natural habitat of orangutans, leaving these intelligent primates with nowhere safe to find food, shelter, or raise their young.","p":"HA-buh-tat","o":"Latin","y":2,"bp":88,"m":"habitatt","sy":"hhae.bah.tae.t","nt":"Junior | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin habitat = it dwells, from habitare = to inhabit","h":"HABITat — where an animal has its HABIT of living, one T at the end like a tiny home.","t":["ecology"]},{"w":"hail","d":"To greet or cheer enthusiastically; to call out to.","s":"The whole town hailed the returning champions with banners and cheers.","p":"HAYL","o":"Norse","y":3,"bp":70,"ps":"verb","r":"Old Norse heill (health, good luck), used as a greeting.","h":"'Hail to the chief!' — to hail is to salute and cheer someone.","nt":"vocab-NWFinal-2026-Junior"},{"w":"hallucination","d":"illusory perception; a common symptom of severe mental disorder","p":"huh-loo-suh-NAY-shuhn","o":"Latin","y":3,"bp":39,"m":"hallucination","sy":"hhah.luw.sah.ney.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin hallucinari = to wander in mind","h":"hallucINATION: the NATION wandered into a HALL and lost its mind — keep that I before NATION.","t":["disease"]},{"w":"harass","d":"is to disturb persistently","p":"h-ur-A-s","o":"French","y":3,"bp":50,"m":"harrass","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"verb","r":"French harasser = to tire out, harry","h":"One R, two S's in haraSS — one Rotten person causes double Stress."},{"w":"hardy","d":"Strong and tough; able to survive difficult conditions.","s":"These hardy plants survived the frost that killed the others.","p":"HAR-dee","o":"French","y":3,"bp":72,"ps":"adjective","r":"Old French hardi (bold, brave), from hardir (to make bold).","h":"Hardy things are HARD to hurt — tough survivors of cold and storms.","nt":"vocab-NWFinal-2026-Junior"},{"w":"hare","d":"A fast, long-eared animal like a large rabbit.","s":"In the fable, the speedy hare loses the race to the steady tortoise.","p":"HAIR","o":"Old English","y":2,"bp":70,"ps":"noun","r":"Old English hara (hare).","h":"The Tortoise and the Hare: the hare is the super-fast rabbit cousin.","nt":"vocab-NWFinal-2026-Junior"},{"w":"hart","d":"An adult male deer, especially a red deer stag.","s":"In the old tale, a hart with great antlers leaped across the stream.","p":"HART","o":"Old English","y":4,"bp":64,"ps":"noun","r":"Old English heorot (stag, male deer).","h":"A HART (not heart) is a he-deer — the stag with big antlers.","nt":"vocab-NWFinal-2026-Junior"},{"w":"haughty","d":"having or showing arrogant superiority to and disdain of those one views as unworthy","p":"h-AW-t-ee","o":"English","y":4,"bp":61,"m":"haughty","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Old French haut = high, from Latin altus = high","h":"The HAUGHTY person walks with his chin HIGH — and the silent GH keeps his nose up."},{"w":"haunt","d":"To visit a place often; to keep returning to one's mind.","s":"That missed final question haunted her until the next competition.","p":"HAWNT","o":"French","y":3,"bp":70,"ps":"verb","r":"Old French hanter (to frequent, visit often).","h":"Like a ghost that won't leave, a haunting thought keeps coming back.","nt":"vocab-NWFinal-2026-Junior"},{"w":"hearsay","d":"Information heard from others that may not be true; rumor.","s":"The story about school closing early was just hearsay, not an announcement.","p":"HEER-say","o":"English","y":3,"bp":70,"ps":"noun","r":"English hear + say — what you 'hear said' by others.","h":"HEAR + SAY: stuff you heard someone say — gossip, not proof.","nt":"vocab-NWFinal-2026-Junior"},{"w":"heartfelt","d":"Deeply and sincerely felt.","s":"She gave a heartfelt thank-you speech to her coaches and parents.","p":"HART-felt","o":"Old English","y":2,"bp":72,"ps":"adjective","r":"Old English heorte (heart) + felt — felt in the heart.","h":"Heartfelt words are FELT in the HEART — totally sincere, not fake.","nt":"vocab-NWFinal-2026-Junior"},{"w":"eloquent","d":"expressing yourself readily, clearly, effectively","p":"EH-luh-kwuhnt","o":"Latin","y":3,"bp":32,"m":"elouquent","sy":"eh.lah.kwah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin eloqui = to speak out","h":"An ELOquent speaker lets words FLOW out beautifully."},{"w":"embody","d":"To be a perfect example of an idea or quality; to give it form.","s":"Our captain embodies teamwork by always helping the newest players.","p":"em-BAH-dee","o":"English","y":3,"bp":70,"ps":"verb","r":"Em- (in) + body — to put an idea 'into a body.'","h":"To embody courage is to BE courage in a BODY — a walking example.","nt":"vocab-NWFinal-2026-Junior"},{"w":"emergent","d":"occurring unexpectedly and requiring urgent action","s":"Emergent repair of an aorta.","p":"ih-MUR-juhnt","o":"Latin","y":3,"bp":32,"m":"imergent","sy":"ih.mer.jhah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin emergere = to rise out","h":"EMERGENT: something EMERGENT is MERGING outward — E + MERG + ENT rising to surface."},{"w":"emigrant","d":"someone who leaves one country to settle in another","s":"The emigrant packed all her belongings into one small trunk as she prepared to start a new life abroad.","p":"EH-muh-gruhnt","o":"Latin","y":3,"bp":32,"m":"emmigrant","sy":"eh.mah.grah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin emigrare = to move away","h":"An EMIGRANT moves out — one M because they pack MINIMALLY for one journey away.","t":["botany"]},{"w":"emigrate","d":"leave one's country of residence for a new one","s":"Many people had to emigrate during the Nazi period.","p":"EH-muh-grayt","o":"Latin","y":3,"bp":32,"m":"emmigrate","sy":"eh.mah.grey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin emigrare = to move away","h":"To EMIGRATE, move the E out front and keep one M — you only move once, one M."},{"w":"eminently","d":"in an eminent manner","s":"Two subjects on which he was eminently qualified to make an original contribution.","p":"EH-muh-nuh-ntlee","o":"Latin","y":3,"bp":34,"m":"eminantly","sy":"eh.mah.nah.ntliy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adverb","r":"Latin eminere = to stand out","h":"EMINENTLY — he is eminENTly qualified: spot the -ENT in the middle, standing out."},{"w":"emission","d":"the act of emitting; causing to flow forth","p":"ih-MIH-shuhn","o":"Latin","y":3,"bp":32,"m":"emmission","sy":"ih.mih.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin emissio = a sending out","h":"EMISSION has one M — gases EMIT with one burst, one M, flowing out."},{"w":"emit","d":"To send out light, sound, heat, or gas.","s":"Fireflies emit tiny flashes of light on summer evenings.","p":"ih-MIT","o":"Latin","y":3,"bp":74,"ps":"verb","r":"Latin e- (out) + mittere (to send) — to send out.","h":"E for exit: whatever is emitted EXITS — light, smoke, or sound going out.","nt":"vocab-NWFinal-2026-Junior"},{"w":"employee","d":"a worker who is hired to perform a job","s":"The dedicated employee stayed late every night to finish the project before the deadline.","p":"eh-MPLOY-ee","o":"French","y":3,"bp":32,"m":"employe","sy":"eh.mploy.iy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"French employé = one who is employed","h":"An employEE has two E's because they need two eyes to watch for their paycheck!","vh":"one who"},{"w":"enact","d":"To make a bill into law; to act out or perform.","s":"Congress voted to enact a law protecting the national parks.","p":"en-AKT","o":"Latin","y":3,"bp":68,"ps":"verb","r":"En- (make) + act, from Latin agere (to do, drive).","h":"EN + ACT: to put an idea into ACTion — a bill enacted becomes law.","nt":"vocab-NWFinal-2026-Junior"},{"w":"enamor","d":"To fill with love or great delight; to charm.","s":"The puppy's floppy ears enamored everyone at the shelter.","p":"en-AM-ur","o":"French","y":3,"bp":66,"ps":"verb","r":"Old French enamourer, from amour (love), from Latin amor.","h":"AMOR means love — to be enamored is to fall in love with something.","nt":"vocab-NWFinal-2026-Junior"},{"w":"flurry","d":"A brief, light snowfall; a sudden short burst of activity.","s":"A flurry of snow dusted the playground just before recess ended.","p":"FLUR-ee","o":"English","y":2,"bp":70,"ps":"noun","r":"English, imitative, blending 'flurr' (to scatter) with hurry.","h":"A flurry is a quick swirl — snowflakes or busy motion in a hurry.","nt":"vocab-NWFinal-2026-Junior"},{"w":"folk-lore","d":"Traditional stories, customs, and beliefs passed down among a people.","s":"Grandpa shared village folk-lore about a clever fox who outsmarted a king.","p":"FOHK-lor","o":"Old English","y":3,"bp":72,"ps":"noun","r":"Old English folc (people) + lar (learning, lore).","h":"FOLK (people) + LORE (knowledge): the people's old stories and traditions.","nt":"vocab-NWFinal-2026-Junior"},{"w":"foolhardy","d":"marked by defiant disregard for danger or consequences","s":"Foolhardy enough to try to seize the gun from the hijacker.","p":"FOO-lhah-rdee","o":"French","y":3,"bp":33,"m":"fullhardy","sy":"fuw.lhhaa.rdiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"French fol = madman + Old English heard = bold, brave","h":"A FOOLHARDY person is both a FOOL and overly HARDY — two words crammed into one reckless act."},{"w":"forcible","d":"impelled by physical force especially against resistance","s":"The detective reported that the burglar had made a forcible entry through the back door, leaving splintered wood and broken hinges scattered across the kitchen floor.","p":"FAW-rsuh-buhl","o":"French","y":3,"bp":32,"m":"forceable","sy":"fao.rsah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin fortia = strength","h":"FORCIBLE drops the E from FORCE before IBLE — force minus E equals forcible.","t":["physics"]},{"w":"forebear","d":"An ancestor.","s":"Her forebears farmed this valley more than two hundred years ago.","p":"FOR-bair","o":"English","y":4,"bp":66,"ps":"noun","r":"Fore- (before) + be-er (one who exists) — one who existed before.","h":"A forebear was BEfore you were — a relative from long-ago generations.","nt":"vocab-NWFinal-2026-Junior"},{"w":"forefather","d":"An ancestor, especially from long ago.","s":"We studied how the nation's forefathers wrote its first laws.","p":"FOR-fah-thur","o":"Old English","y":2,"bp":70,"ps":"noun","r":"Old English fore (before) + faeder (father).","h":"FORE + FATHER: the fathers who came before — your family's ancestors.","nt":"vocab-NWFinal-2026-Junior"},{"w":"forego","d":"To give up or do without something.","s":"I chose to forego dessert so I could finish studying my word list.","p":"for-GOH","o":"Old English","y":3,"bp":70,"ps":"verb","r":"Old English forgan (to pass over, do without); also spelled forgo.","h":"To forego dessert is to let it GO — skipping something you could have had.","nt":"vocab-NWFinal-2026-Junior"},{"w":"foregone","d":"Decided or known in advance; certain before it happens.","s":"With a ten-point lead, our win seemed a foregone conclusion.","p":"FOR-gawn","o":"Old English","y":4,"bp":66,"ps":"adjective","r":"From forego (to go before) — a result that 'went before' the event.","h":"A foregone conclusion was concluded beFORE it happened — already settled.","nt":"vocab-NWFinal-2026-Junior"},{"w":"forte","d":"A person's strong point; what someone does especially well.","s":"Spelling is my forte, but I'm working hard on my math facts too.","p":"FOR-tay","o":"French","y":3,"bp":74,"ps":"noun","r":"French fort (strong), from Latin fortis.","h":"Your forte is your FORT of strength — the skill where you're strongest.","nt":"vocab-NWFinal-2026-Junior"},{"w":"forthright","d":"Direct and honest in speech or behavior.","s":"Be forthright with the coach if you can't make it to practice.","p":"FORTH-ryt","o":"Old English","y":3,"bp":70,"ps":"adjective","r":"Old English forth (forward) + riht (straight) — going straight ahead.","h":"Forthright people speak straight FORTH — no hiding, no beating around the bush.","nt":"vocab-NWFinal-2026-Junior"},{"w":"fortify","d":"To make stronger, especially against attack.","s":"The soldiers worked all night to fortify the walls of the old fort.","p":"FOR-tuh-fy","o":"Latin","y":3,"bp":74,"ps":"verb","r":"Latin fortis (strong) + facere (to make) — to make strong.","h":"FORT + IFY: to turn something into a fort — build up its strength.","nt":"vocab-NWFinal-2026-Junior"},{"w":"fragile","d":"easily broken or damaged or destroyed","s":"The archaeologist handled the fragile pottery shard with two fingers, knowing that a single wrong move could destroy a 3,000-year-old artifact.","p":"FRA-juhl","o":"Latin","y":1,"bp":38,"m":"fragil","sy":"frag.ile","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin fragilis = breakable, from frangere = to break","h":"FRAGILE has FRAG in it—a fragment is a broken piece"},{"w":"heedless","d":"Careless; paying no attention to warnings or danger.","s":"Heedless of the wet-floor sign, he ran down the hall and slipped.","p":"HEED-lis","o":"Old English","y":3,"bp":70,"ps":"adjective","r":"Old English hedan (to care for, pay attention) + -less (without).","h":"HEED means pay attention — heedless means paying NONE at all.","nt":"vocab-NWFinal-2026-Junior"},{"w":"herbicide","d":"a chemical agent that destroys plants or inhibits their growth","s":"The farmer applied herbicide carefully along the field's edge to keep weeds from spreading into the crop rows.","p":"HUR-bih-seyed","o":"Latin","y":3,"bp":33,"m":"herbacide","sy":"hher.bih.say.d","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin herba = plant + caedere = to kill","h":"HERBICIDE KILLS herbs—HER B-I-CIDE: the B-I signals 'by killing' plants.","t":["botany","chemistry"]},{"w":"hereditary","d":"occurring among members of a family usually by heredity","p":"her-EH-duh-teh-ree","o":"Latin","y":3,"bp":37,"m":"heriditary","sy":"hher.eh.dah.teh.riy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin heres = heir + -arius = relating to","h":"HEREDITARY contains HEIR in the middle—traits passed down to the heir.","t":["kinship"]},{"w":"heritage","d":"practices that are handed down from the past by tradition","s":"The town celebrated its Scottish heritage every August with a highland games festival featuring bagpipes and caber tossing.","p":"HEH-ruh-tuhj","o":"French","y":4,"bp":64,"m":"heratage","sy":"her.i.tage","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old French heritage, from hériter = to inherit, from Latin heres = heir","h":"HERItage is what your ancestors left HERE for you.","t":["festivals"]},{"w":"hesitant","d":"lacking decisiveness of character; unable to act or decide quickly or firmly","s":"Elena was hesitant to dive into the cold water, standing at the edge of the pool for several minutes.","p":"HEH-zih-tuhnt","o":"Latin","y":3,"bp":32,"m":"hesitent","sy":"hheh.zih.tah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin haesitare = to stick, hesitate","h":"A hesitANt ant pauses at every crumb — remember the 'a' in -ant, not -ent."},{"w":"hindmost","d":"Farthest to the back; last.","s":"The hindmost runner sprinted hard and still finished the relay strong.","p":"HYND-mohst","o":"Old English","y":3,"bp":64,"ps":"adjective","r":"Old English hinder (behind) + -most (superlative ending).","h":"HIND like a horse's hind legs + MOST: the very rearmost one.","nt":"vocab-NWFinal-2026-Junior"},{"w":"hoard","d":"To gather and store away a large hidden supply.","s":"Squirrels hoard acorns all autumn to eat during the winter.","p":"HORD","o":"Old English","y":3,"bp":74,"ps":"verb","r":"Old English hord (treasure, hidden store).","h":"A dragon hoards gold — piling up treasure and refusing to share.","nt":"vocab-NWFinal-2026-Junior"},{"w":"hoax","d":"is something intended to deceive or defraud","s":"The report of a sea monster in the lake turned out to be an elaborate hoax staged by local teenagers.","p":"h-OH-k-s","o":"English","y":3,"bp":43,"m":"hoacks","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Dutch hoekse or hocus = to cheat/trick","h":"A hoax is a sneaky OAX — imagine an ox wearing a disguise to fool the farmer."},{"w":"hogwash","d":"Nonsense; worthless or untrue talk.","s":"Grandpa laughed and called the alien rumor complete hogwash.","p":"HAWG-wahsh","o":"English","y":3,"bp":68,"ps":"noun","r":"English hog + wash — originally kitchen slop fed to pigs.","h":"Hogwash was slop for hogs — talk so worthless it's pig slop.","nt":"vocab-NWFinal-2026-Junior"},{"w":"hospitality","d":"kindness in welcoming guests or strangers","s":"The family's hospitality was evident as they offered their guests warm soup and fresh bread.","p":"hah-spuh-TA-luh-tee","o":"French","y":2,"bp":49,"m":"hospitallity","sy":"hhaa.spah.tae.lah.tiy","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin hospes = host, guest","h":"A HOSPITAL shows HOSPITALITY — both start with hospit-, h-o-s-p-i-t-a-l-i-t-y."},{"w":"hostage","d":"A person held prisoner until certain demands are met.","s":"In the adventure novel, the pirates held the captain's son as a hostage.","p":"HAHS-tij","o":"French","y":3,"bp":70,"ps":"noun","r":"Old French hostage (pledge, person given as security).","h":"A hostage is a human bargaining chip — kept until demands are paid.","nt":"vocab-NWFinal-2026-Junior"},{"w":"humanize","d":"make more humane","s":"The mayor tried to humanize life in the big city.","p":"HYOO-muh-neyez","o":"French","y":3,"bp":32,"m":"humanise","sy":"hhyuw.mah.nay.z","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin humanus = human + Greek -izein = to make","h":"humanIZE ends in IZE — you use your EYES to recognize humanity in others."},{"w":"humid","d":"Damp; having a lot of moisture in the air.","s":"The gym felt so humid after the storm that the windows fogged up.","p":"HYOO-mid","o":"Latin","y":2,"bp":74,"ps":"adjective","r":"Latin humidus (moist), from humere (to be moist).","h":"Humid air feels like a warm, wet towel — sticky with moisture.","nt":"vocab-NWFinal-2026-Junior"},{"w":"humiliate","d":"is to cause a loss of pride or dignity","s":"He humiliated his colleague by criticising him in front of the boss.","p":"h-y-oo-m-IH-l-ee-ay-t","o":"Latin","y":3,"bp":54,"m":"humiliate","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin humiliare = to humble, from humilis = low/on the ground","h":"To HUMILIATE is to make someone feel low — HUMILI- keeps them close to the ground."},{"w":"hydraulic","d":"is employing water or other liquids in motion","s":"The engineering students marveled at how the hydraulic lift at the auto shop could raise an entire vehicle effortlessly using only the power of pressurized fluid flowing through a compact network of metal tubes.","p":"h-ay-d-r-AW-l-ih-k","o":"English","y":4,"bp":64,"m":"hydralic","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Greek hydor = water + aulos = pipe","h":"HydrAULic pipes HAUL water with powerful force — remember the AU in HAUL."},{"w":"hydromechanics","d":"The science of how liquids move and the forces acting on them.","s":"Engineers use hydromechanics to design dams that control rushing rivers.","p":"hy-droh-muh-KAN-iks","o":"Greek","y":4,"bp":60,"ps":"noun","r":"Greek hydor (water) + mechane (machine) — the mechanics of water.","h":"HYDRO (water) + MECHANICS (forces and motion): the physics of flowing liquids.","nt":"vocab-NWFinal-2026-Junior"},{"w":"hydrophobia","d":"a symptom of rabies in humans consisting of an aversion to swallowing liquids","s":"The doctor explained that hydrophobia in the patient was an alarming sign that the rabies infection had progressed severely.","p":"heye-druh-FOH-bee-uh","o":"Latin","y":3,"bp":37,"m":"hydrophobia","sy":"heye.druh.foh.bee.uh","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek hydro = water + phobos = fear","h":"A HYDROphobic person FEARS water — hydro (water) + phobia (fear) — both Greek roots drip with meaning.","t":["disease"]},{"w":"hydrostatics","d":"The branch of science dealing with liquids at rest and their pressure.","s":"Using hydrostatics, we calculated the water pressure at the bottom of the tank.","p":"hy-droh-STAT-iks","o":"Greek","y":4,"bp":60,"ps":"noun","r":"Greek hydor (water) + statikos (causing to stand still).","h":"HYDRO (water) + STATIC (not moving): the science of still water and its pressure.","nt":"vocab-NWFinal-2026-Junior","vh":"branch of science"},{"w":"about","d":"Concerning; on the subject of; also nearly or approximately.","s":"We read a chapter about volcanoes and how they erupt.","p":"uh-BOWT","o":"Old English","y":2,"bp":58,"ps":"preposition","r":"Old English onbutan (around, on the outside of).","h":"A book ABOUT sharks concerns sharks; 'about ten' means roughly ten.","nt":"vocab-NWFinal-2026-Junior"},{"w":"hypnotism","d":"the act of inducing hypnosis","s":"The magician used hypnotism to make a volunteer from the audience cluck like a chicken.","p":"HIH-pnuh-tih-zuhm","o":"Greek","y":3,"bp":34,"m":"hypnotisim","sy":"hhih.pnah.tih.zah.m","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek hypnos = sleep + -ism = practice","h":"HypnotISM ends in -ISM like magnetism — both pull you in against your will.","vh":"practice of"},{"w":"idiom","d":"A phrase whose meaning is different from its literal words.","s":"The idiom 'piece of cake' means something is easy, not a real dessert.","p":"IH-dee-uhm","o":"Greek","y":3,"bp":76,"ps":"noun","r":"Greek idioma (special phrasing), from idios (one's own).","h":"'Raining cats and dogs' — an idiom says one thing, means another.","nt":"vocab-NWFinal-2026-Junior"},{"w":"ignite","d":"cause to start burning; subject to fire or great heat","s":"Great heat can ignite almost any dry matter.","p":"ih-GNEYET","o":"Latin","y":2,"bp":86,"m":"ignigt","sy":"ih.gnay.t","nt":"Junior | North South Finals, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin ignis = fire","h":"IGNite comes from IGNIS (fire) — IGNore the urge to add extra letters, just spark it with I-G-N-I-T-E."},{"w":"ignoble","d":"completely lacking nobility in character or quality or purpose","s":"The knight was banished from the kingdom for his ignoble act of stealing from the poor villagers.","p":"ih-GNOH-buhl","o":"Latin","y":4,"bp":63,"m":"ignoble","sy":"ig.no.ble","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin ignobilis = not noble; in-(not)+nobilis(famous, noble)","h":"IGNOBle: IGNORE noble behavior.","t":["royalty"]},{"w":"immature","d":"characteristic of a lack of maturity","s":"Although he was nearly fourteen years old, Marcus acted in an immature way during the assembly, giggling at serious moments and throwing crumpled paper at students seated in the rows ahead of him.","p":"ih-muh-TYUUR","o":"Latin","y":3,"bp":73,"m":"imature","sy":"ih.mah.tyuh.r","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin in-(not)+maturus(ripe, mature)","h":"IMMATURE — double M, like a child who insists on doing everything twice before getting it right."},{"w":"immerse","d":"To dip or plunge completely into a liquid; to absorb fully.","s":"Immerse the beans in water overnight before Mom cooks them.","p":"ih-MURS","o":"Latin","y":3,"bp":72,"ps":"verb","r":"Latin immergere, from in- + mergere (to dip, plunge).","h":"Immerse means submerge — dunk it all the way under, like a tea bag.","nt":"vocab-NWFinal-2026-Junior"},{"w":"immigrant","d":"a person who comes to a country where they were not born in order to settle there","s":"As a young immigrant, she worked two jobs while attending night school, determined to build a better life for her family.","p":"IH-muh-gruhnt","o":"Latin","y":3,"bp":33,"m":"imigrant","sy":"ih.mah.grah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin immigrare = to move into","h":"An iMMigrant crosses double barriers — two M's like two border gates to pass through.","vh":"one who"},{"w":"immobile","d":"not capable of movement or of being moved","p":"ih-MOH-buhl","o":"Latin","y":3,"bp":32,"m":"imobile","sy":"ih.mow.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin immobilis = not movable","h":"iMMobile is stuck with two M's — it's so frozen it can't drop even one M."},{"w":"impartial","d":"showing lack of favoritism","s":"The cold neutrality of an impartial judge.","p":"ih-MPAH-rshuhl","o":"Latin","y":3,"bp":33,"m":"impartiel","sy":"ih.mpaa.rshah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin impartialis = not partial","h":"An imPARTIAL judge takes no PART-IAL side — no partial views allowed."},{"w":"impede","d":"is to retard in movement by means of obstacles","p":"ih-m-p-EE-d","o":"Latin","y":3,"bp":50,"m":"impeed","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin impedire = to shackle the feet","h":"To imPEDE is to trip someone's feet (PEDe) — stuck mid-speed."},{"w":"imperialism","d":"a policy of extending your rule over foreign countries","s":"The class debated whether imperialism had brought more destruction than progress to the regions it had touched.","p":"ih-MPIH-ree-uh-lih-zuhm","o":"Latin","y":3,"bp":39,"m":"imperialsim","sy":"ih.mpih.riy.ah.lih.zah.m","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin imperium = command, empire","h":"imPERIALism is the empire's ISM—a belief system built on the emPERor's power.","t":["politics"]},{"w":"impious","d":"Lacking respect for God or religion.","s":"The villagers thought it impious to joke loudly inside the temple.","p":"IM-pee-uhs","o":"Latin","y":4,"bp":64,"ps":"adjective","r":"Latin in- (not) + pius (devout, dutiful).","h":"IM (not) + PIOUS (devout): not respectful toward sacred things.","nt":"vocab-NWFinal-2026-Junior"},{"w":"implicate","d":"bring into intimate and incriminating connection","s":"He is implicated in the scheme to defraud the government.","p":"IH-mplih-kayt","o":"Latin","y":3,"bp":33,"m":"implecate","sy":"ih.mplih.key.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin implicare = to enfold, from in-(in)+plicare(to fold)","h":"To IMPLICATE is to fold someone IN — im-PLIC-ate, where PLIC means fold, like a paper fold of guilt."},{"w":"impoverish","d":"To make someone or something poor, or to reduce in quality, richness, or strength.","s":"Years of drought and crop failure continued to impoverish the farming communities in the region's dry southern plains.","p":"ih-MPAH-vrihsh","o":"French","y":3,"bp":34,"m":"impoversh","sy":"ih.mpaa.vrih.sh","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Old French empovrir = to make poor","h":"ImPOVERish puts POVERTY right inside it — POVER = poor."},{"w":"impregnate","d":"fill, as with a certain quality","p":"ih-MPREH-gnayt","o":"Latin","y":3,"bp":34,"m":"impregnite","sy":"ih.mpreh.gney.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin impraegnare = to make pregnant/fill","h":"ImPREGNATE ends in -ATE — you PREG-nate something to fill it, just ATE its way in."},{"w":"improvise","d":"perform without preparation","p":"IH-mpruh-veyez","o":"Latin","y":3,"bp":33,"m":"improvize","sy":"ih.mprah.vay.z","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin improvisus = unforeseen","h":"ImproVISE ends in '-ise' not '-ize' — you didn't VISE (see) it coming, spelled the French way."},{"w":"impure","d":"Not clean or pure; mixed with something dirty or unwanted.","s":"The stream water was impure, so we filtered it before drinking.","p":"im-PYOOR","o":"Latin","y":2,"bp":68,"ps":"adjective","r":"Latin in- (not) + purus (clean, pure).","h":"IM (not) + PURE: something extra got mixed in that shouldn't be there.","nt":"vocab-NWFinal-2026-Junior"},{"w":"inanimate","d":"belonging to the class of nouns denoting nonliving things","s":"The word `car' is inanimate.","p":"ih-NA-nuh-muht","o":"Latin","y":3,"bp":34,"m":"innanimate","sy":"ih.nae.nah.mah.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin anima = life, soul","h":"Inanimate things have no ANIMA — no soul — spot ANIM inside the word."},{"w":"inapt","d":"Not suitable or fitting; inappropriate.","s":"His joke felt inapt during the serious awards ceremony.","p":"in-APT","o":"Latin","y":4,"bp":62,"ps":"adjective","r":"Latin in- (not) + aptus (fitted, suitable).","h":"IN (not) + APT (fitting): an inapt remark just doesn't fit the moment.","nt":"vocab-NWFinal-2026-Junior"},{"w":"incapacitate","d":"make unable to perform a certain action","p":"ih-nkuh-PA-sih-tayt","o":"Latin","y":3,"bp":38,"m":"incapasitate","sy":"ih.nkah.pae.sih.tey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin capacitas = capacity (from capere = to hold)","h":"To INcapacITATE is to eliminate someone's CAPACITY — IT ATE their ability away."},{"w":"incapacity","d":"lack of intellectual power","s":"His incapacity to solve even basic math problems worried his teacher greatly.","p":"ih-nkuh-PA-suh-tee","o":"Latin","y":3,"bp":37,"m":"incapasity","sy":"ih.nkah.pae.sah.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin capacitas = capacity (from capere = to hold)","h":"INCAPACity — the CAPA is gone, leaving only inability."},{"w":"incident","d":"a single distinct event","s":"The teacher asked each student to write a paragraph describing the most memorable incident from their summer vacation.","p":"IH-nsuh-duhnt","o":"Latin","y":2,"bp":44,"m":"insedent","sy":"in.ci.dent","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin incidere = to fall upon; in-(upon)+cadere(to fall)","h":"An INCIDENT: something that FELL IN (happened) unexpectedly."},{"w":"incite","d":"is to stir encourage or urge on","p":"ih-n-s-AY-t","o":"Latin","y":3,"bp":50,"m":"insight","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin incitare = to urge forward","h":"To incite a crowd, you put them IN motion — in+cite, like citing a reason to act."},{"w":"incoherence","d":"lack of cohesion or clarity or organization","s":"After the exhausted student pulled an all-nighter, the incoherence of his essay made it nearly impossible to grade.","p":"ih-nkoh-HIH-ruhns","o":"Latin","y":3,"bp":36,"m":"incoherance","sy":"ih.nkow.hhih.rah.ns","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin cohaerere = to stick together (co+haerere)","h":"IncoherENCE ends in -ENCE not -ANCE: things that won't stick together make no SENSE — ENCE, ENCE!"},{"w":"incombustible","d":"Unable to be burned.","s":"Firefighters wear suits made of incombustible material for protection.","p":"in-kuhm-BUHS-tuh-buhl","o":"Latin","y":4,"bp":62,"ps":"adjective","r":"Latin in- (not) + comburere (to burn up) + -ible.","h":"IN (not) + COMBUSTIBLE (burnable): fireproof — flames can't catch it.","nt":"vocab-NWFinal-2026-Junior"},{"w":"incomparable","d":"such that comparison is impossible; unsuitable for comparison or lacking features that can be compared","s":"An incomparable week of rest and pleasure.","p":"ih-NKAH-mper-uh-buhl","o":"Latin","y":3,"bp":38,"m":"incomperable","sy":"ih.nkaa.mper.ah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin comparare = to compare (com+parare)","h":"inCOMPARAble: keep COMPAR from compare — drop the E before -able, because nothing can even COMPARE."},{"w":"incomprehensible","d":"incapable of being explained or accounted for","s":"The ancient manuscript was so damaged that its symbols were completely incomprehensible to even the most experienced historians.","p":"ih-ngkah-mpruh-HEH-nsih-buhl","o":"Latin","y":4,"bp":75,"m":"incomprehensable","sy":"in.com.pre.hen.si.ble","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin comprehendere = to grasp or seize","h":"Can you HENS-ibly explain it? If not, it's incompreHENSible!"},{"w":"incompressible","d":"incapable of being compressed; resisting compression","s":"Mounds of incompressible garbage.","p":"ih-nkuh-MPREH-suh-buhl","o":"Latin","y":3,"bp":40,"m":"incompressable","sy":"ih.nkah.mpreh.sah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin comprimere = to press together (com+premere)","h":"incompressIBLE not -able: you can't POSSIBLY press it — IBLE like 'Impossible to squeeze!'"},{"w":"incontestable","d":"Impossible to argue against or deny; unquestionable.","s":"Her perfect score was incontestable proof that she had studied hard.","p":"in-kuhn-TES-tuh-buhl","o":"Latin","y":4,"bp":62,"ps":"adjective","r":"Latin in- (not) + contestari (to call to witness, dispute) + -able.","h":"IN (not) + CONTEST + ABLE: a fact nobody can contest or challenge.","nt":"vocab-NWFinal-2026-Junior"},{"w":"indefensible","d":"(of theories etc) incapable of being defended or justified","s":"The coach admitted that his decision to bench the team's best player during the championship was completely indefensible.","p":"ih-ndih-FEH-nsuh-buhl","o":"Latin","y":3,"bp":38,"m":"indefencible","sy":"ih.ndih.feh.nsah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin defendere = to defend","h":"You cannot build a FENCE around an inDEFENSible position — the 's' in fence stays as 's' in defensible.","t":["logic"]},{"w":"indefinitely","d":"to an indefinite extent; for an indefinite time","s":"This could go on indefinitely.","p":"ih-NDEH-fuh-nuh-tlee","o":"Latin","y":3,"bp":38,"m":"indefinately","sy":"ih.ndeh.fah.nah.tliy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adverb","r":"Latin indefinitus = not defined","h":"InDEFINitely goes on without a FINish — spell it '-itely,' not '-ately.'","t":["time"]},{"w":"indescribable","d":"defying expression or description","p":"ih-ndih-SKREYE-buh-buhl","o":"Latin","y":3,"bp":39,"m":"indescribeable","sy":"ih.ndih.skray.bah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin describere = to write down, de+scribere = to write","h":"InDESCRIBable beauty cannot be SCRIBbled down — no extra 'e' before '-able.'"},{"w":"infinite","d":"the unlimited expanse in which everything is located","p":"IH-nfuh-nuht","o":"Latin","y":3,"bp":32,"m":"infinit","sy":"ih.nfah.nah.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin infinitus = unbounded (in- not + finis end)","h":"INFINITe has no END — just like infinity — and ends with a silent E to remind you it never stops."},{"w":"inflammable","d":"is capable of being set on fire","s":"The chemist placed a large warning label on the bottle because the liquid inside was highly inflammable and could ignite from a small spark.","p":"ih-n-f-l-A-m-uh-b-uh-l","o":"English","y":3,"bp":52,"m":"inflamable","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin inflammare = to set on fire (in- = upon + flamma = flame)","h":"inFLAMmable: full of FLAME — confusingly same meaning as flammable"},{"w":"ingenious","d":"showing inventiveness and skill","s":"Maya devised an ingenious solution to the engineering challenge by using everyday household materials to build a bridge sturdy enough to hold twice the required weight.","p":"ih-NJEE-nyuhs","o":"Latin","y":3,"bp":74,"m":"ingenuous","sy":"ih.njhiy.nyah.s","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin ingeniosus = clever, from ingenium = natural ability","h":"An ingenious GENIUS is full of natural talent — spot GENI inside and remember -OUS, not -UOUS."},{"w":"inglorious","d":"(used of conduct or character) deserving or bringing disgrace or shame; - Rachel Carson","p":"ih-NGLAW-ree-uhs","o":"Latin","y":3,"bp":35,"m":"inglourious","sy":"ih.nglao.riy.ah.s","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin ingloriosus = without glory (in-=not + gloria=glory)","h":"IN-GLORIOUS means NOT glorious — the prefix IN cancels the GLORY, leaving only shame."},{"w":"inhibit","d":"to put down by force or authority","p":"ih-NHIH-buht","o":"Latin","y":2,"bp":43,"m":"inhibbit","sy":"ih.nhhih.bah.t","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin inhibere = to hold back, from in- + habere = to have/hold","h":"To inhibit is to hold something IN — INside, HIBernating, unable to act.","t":["physics","poetry"]},{"w":"inhuman","d":"Extremely cruel; lacking the kindness expected of people.","s":"The story described the inhuman treatment of prisoners in the old dungeon.","p":"in-HYOO-muhn","o":"Latin","y":3,"bp":66,"ps":"adjective","r":"Latin in- (not) + humanus (human, kind).","h":"IN (not) + HUMAN: cruelty so cold it seems to lack human feeling.","nt":"vocab-NWFinal-2026-Junior"},{"w":"initiate","d":"someone new to a field or activity","s":"It is very familiar to the initiate.","p":"ih-NIH-shee-ayt","o":"Latin","y":3,"bp":33,"m":"inishiate","sy":"ih.nih.shiy.ey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin initiare = to begin","h":"To INITIATE is to enter IN — keep the 'ini' clean: I-N-I-T-I-A-T-E."},{"w":"injudicious","d":"lacking or showing lack of judgment or discretion; unwise","p":"ih-njuh-DIH-shuhs","o":"Latin","y":3,"bp":36,"m":"injudiscious","sy":"ih.njhah.dih.shah.s","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin judex = judge","h":"INJUDICIOUS has no JUDICI-AL wisdom — spot the JUDICI in the middle to spell it right."},{"w":"innovative","d":"ahead of the times","p":"IH-nuh-vay-tihv","o":"Latin","y":3,"bp":35,"m":"inovative","sy":"ih.nah.vey.tih.v","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin 'innovare' from 'novus' = new","h":"An innovative thinker brings in NEW ideas — double 'n' like two lightbulbs: in+nov+ative.","t":["time"]},{"w":"inquisitor","d":"a questioner who is excessively harsh","s":"The detective played the role of an inquisitor, firing questions at the suspect for three relentless hours.","p":"ih-NKWIH-zuh-ter","o":"Latin","y":3,"bp":35,"m":"inquisiter","sy":"in.quis.i.tor","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin inquisitor = one who inquires, from inquirere = to seek into","h":"An inquisitor is always on a QUEST for answers."},{"w":"insensible","d":"incapable of physical sensation","s":"After the terrible accident, the injured hiker lay insensible on the rocky trail, completely unaware of the rescue team working frantically around him as they stabilized his injuries and prepared to airlift him to the hospital.","p":"ih-NSEH-nsuh-buhl","o":"Latin","y":3,"bp":35,"m":"insensable","sy":"ih.nseh.nsah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin sensibilis = capable of feeling, from sensus = feeling","h":"INSENSIBLE: NOT SENSIBLE to pain — use 'ible' because you 'can't' feel."},{"w":"insightful","d":"Showing a deep, clear understanding of something.","s":"Her insightful comment helped the whole class understand the poem.","p":"IN-syt-fuhl","o":"English","y":3,"bp":70,"ps":"adjective","r":"English in + sight + -ful — full of 'inner seeing.'","h":"INsight is seeing INside a problem — insightful people see what others miss.","nt":"vocab-NWFinal-2026-Junior"},{"w":"insomnia","d":"an inability to sleep; chronic sleeplessness","s":"Her insomnia was so severe that she lay awake staring at the ceiling until dawn.","p":"ih-NSAH-mnee-uh","o":"Latin","y":3,"bp":74,"m":"insomnia","sy":"ih.nsaa.mniy.ah","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin somnus = sleep","h":"INSOmniA — I Need Sleep Or My Night Is Awful; somnus is sleep, so insomnia means NO sleep.","t":["disease"]},{"w":"inspector","d":"a high ranking police officer","s":"The building inspector climbed every staircase and checked every electrical outlet before approving the new school for students.","p":"ih-NSPEH-kter","o":"Latin","y":2,"bp":45,"m":"inspekter","sy":"in.spec.tor","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin inspicere = to look into (specere = to look)","h":"An inSPECTor inSPECTs—both share SPECT meaning 'to look.'"},{"w":"instigate","d":"provoke or stir up","s":"The mischievous student tried to instigate a food fight in the cafeteria by flicking a pea across the room.","p":"IH-nstuh-gayt","o":"Latin","y":3,"bp":33,"m":"instagiate","sy":"in.sti.gate","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin instigare = to goad, urge on (stinguere = to prick)","h":"To INSTIGate is to STING someone into action."},{"w":"instinctive","d":"unthinking; prompted by (or as if by) instinct","p":"ih-NSTIH-ngktihv","o":"Latin","y":3,"bp":34,"m":"instinctave","sy":"ih.nstih.ngktih.v","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin instinguere = to incite, impel","h":"INSTINCTIVE reactions STING you into action before you think — spot the STING.","vh":"pertaining to"},{"w":"insubordinate","d":"not submissive to authority","s":"A history of insubordinate behavior.","p":"ih-nsuh-BAW-rduh-nayt","o":"Latin","y":3,"bp":39,"m":"insubbordinate","sy":"ih.nsah.bao.rdah.ney.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin sub = under + ordinare = to order, arrange","h":"An inSUBORDINATE refuses to be SUBordinate — 'sub' + 'ordin' (order) + '-ate', one 'b' only.","t":["poetry"]},{"w":"insurgence","d":"an act of rebellion","s":"The government struggled to contain the sudden insurgence that swept through the northern provinces.","p":"in-SUR-junss","o":"Latin","y":4,"bp":70,"m":"insurgance","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin insurgere = to rise up","h":"INSURGENCE ends in -ence like violence—a rising (surg) up that creates an -ENCE of chaos."},{"w":"intact","d":"Whole and undamaged; not broken or harmed.","s":"Amazingly, the glass trophy stayed intact when the shelf collapsed.","p":"in-TAKT","o":"Latin","y":3,"bp":76,"ps":"adjective","r":"Latin intactus, from in- (not) + tactus (touched) — untouched.","h":"IN (not) + TACT (touched): untouched, so still in one perfect piece.","nt":"vocab-NWFinal-2026-Junior"},{"w":"integer","d":"A whole number, positive, negative, or zero, with no fraction part.","s":"The teacher asked which integer comes right before negative three.","p":"IN-tuh-jur","o":"Latin","y":3,"bp":72,"ps":"noun","r":"Latin integer (whole, untouched), from in- + tangere (to touch).","h":"An integer is entire — a whole number like 7 or -2, never 7.5.","nt":"vocab-NWFinal-2026-Junior"},{"w":"integrity","d":"an undivided or unbroken completeness or totality with nothing wanting","s":"The integrity of the nervous system is required for normal development.","p":"ih-NTEH-gruh-tee","o":"Latin","y":2,"bp":46,"m":"integirty","sy":"ih.nteh.grah.tiy","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin integer = whole, complete, untouched","h":"INTEGRity shares its root with INTEGER — a whole number, a whole person: I-N-T-E-G-R-I-T-Y."},{"w":"intemperate","d":"(of weather or climate) not mild; subject to extremes","p":"ih-NTEH-mper-uht","o":"Latin","y":3,"bp":36,"m":"intemprate","sy":"ih.nteh.mper.ah.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin temperare = to moderate","h":"INTEMPerate weather has no TEMPER control — it rages at extremes.","t":["weather"]},{"w":"interact","d":"act together or towards others or with others","s":"He should interact more with his colleagues.","p":"ih-nter-AKT","o":"Latin","y":3,"bp":32,"m":"interract","sy":"ih.nter.ae.kt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin inter = between + agere = to do","h":"To interACT, people ACT between each other — INTER+ACT, clean and simple."},{"w":"intergalactic","d":"Existing or happening between galaxies.","s":"The movie's heroes traveled on an intergalactic voyage to a distant galaxy.","p":"in-tur-guh-LAK-tik","o":"Greek","y":3,"bp":66,"ps":"adjective","r":"Latin inter (between) + Greek galaxias (Milky Way, galaxy).","h":"INTER (between) + GALACTIC (galaxies): the vast space between star systems.","nt":"vocab-NWFinal-2026-Junior"},{"w":"intermediate","d":"a substance formed during a chemical process before the desired product is obtained","p":"ih-nter-MEE-dee-iht","o":"Latin","y":3,"bp":38,"m":"intermidiate","sy":"ih.nter.miy.diy.ih.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin intermedius = that which is between, medius = middle","h":"interMEDIATE has MEDI (middle) at its heart — it's the middle level, after all.","t":["chemistry"]},{"w":"interminable","d":"tiresomely long; seemingly without end","s":"The students groaned quietly as their teacher began reading the interminable list of rules aloud, and thirty minutes later they were still seated at their desks, staring at the clock and wondering if the recitation would ever end.","p":"ih-NTUR-muh-nuh-buhl","o":"Latin","y":3,"bp":38,"m":"interminabal","sy":"ih.nter.mah.nah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin in (not) + terminare = to end, terminus = boundary","h":"interMINABLE means it cannot TERMINATE — find TERMIN inside and add -ABLE."},{"w":"intermittent","d":"stopping and starting at irregular intervals","p":"ih-nter-MIH-tuhnt","o":"Latin","y":3,"bp":37,"m":"intermetent","sy":"ih.nter.mih.tah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin inter = between + mittere = to send/let go","h":"InterMITTent has a MITT in the middle — catch it between those double T's."},{"w":"interplay","d":"reciprocal action and reaction","s":"The exciting interplay between the two musicians made the concert unforgettable.","p":"IH-nter-play","o":"Latin","y":3,"bp":33,"m":"interply","sy":"ih.nter.pley","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin inter = between + Old English plega = play","h":"INTERPLAY is when two forces PLAY between each other — keep the full word PLAY inside."},{"w":"intimate","d":"someone to whom private matters are confided","p":"IH-ntuh-muht","o":"Latin","y":3,"bp":32,"m":"intamate","sy":"ih.ntah.mah.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin intimatus = made known, innermost","h":"An intimate is someone you let in — spell it with 'intim' at the core, like intimacy."},{"w":"intimidate","d":"to make fearful.","s":"Her boss intimidates her.","p":"ih-n-t-IH-m-ih-d-ay-t","o":"Latin","y":2,"bp":45,"m":"intimedate","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin timidus = fearful","h":"To INTIMIDATE someone, you put TIMID in them — you make them timid!"},{"w":"intrigue","d":"To make someone very curious or fascinated.","s":"The locked old chest in the attic intrigued the whole family.","p":"in-TREEG","o":"French","y":3,"bp":72,"ps":"verb","r":"French intriguer, from Latin intricare (to entangle).","h":"An intriguing mystery tangles your curiosity — you HAVE to know more.","nt":"vocab-NWFinal-2026-Junior"},{"w":"introspective","d":"given to examining own sensory and perceptual experiences","s":"The introspective young writer filled three journals with his private thoughts before ever sharing a single word publicly.","p":"ih-ntruh-SPEH-ktihv","o":"Latin","y":3,"bp":37,"m":"intraspective","sy":"ih.ntrah.speh.ktih.v","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin introspicere = to look within","h":"An introspective person is their own SPECTator—looking inward with intro + spect + ive."},{"w":"introversion","d":"The tendency to be quiet and focused on one's inner thoughts.","s":"Because of her introversion, she recharged by reading alone after the party.","p":"in-truh-VUR-zhuhn","o":"Latin","y":4,"bp":64,"ps":"noun","r":"Latin intro (inward) + vertere (to turn) — turning inward.","h":"INTRO (inward) + VERSION (turning): energy turned inside, toward one's own thoughts.","nt":"vocab-NWFinal-2026-Junior"},{"w":"intrusion","d":"any entry into an area not previously occupied","p":"ih-NTROO-zhuhn","o":"Latin","y":3,"bp":33,"m":"intrusian","sy":"ih.ntruw.zhah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin intrusio = a thrusting in","h":"An INTRUSION ends in '-sion' like a MISSION forced upon you uninvited."},{"w":"intuition","d":"instinctive knowing (without the use of rational processes)","s":"He had an intuition that something had gone wrong.","p":"ih-ntoo-IH-shuhn","o":"Latin","y":3,"bp":34,"m":"intution","sy":"ih.ntuw.ih.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin intuitio = a looking at","h":"INTUITION has two I's watching IN—i-n-t-u-I-t-I-o-n—two eyes looking inward.","t":["logic"]},{"w":"invaluable","d":"having incalculable monetary, intellectual, or spiritual worth","s":"The mentor's guidance proved invaluable to Marco as he prepared his science fair project and eventually won first place.","p":"ih-NVA-lyuh-buhl","o":"Latin","y":3,"bp":35,"m":"invaluble","sy":"ih.nvae.lyah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin in-(not)+valere(be worth)+English -able(can be)","h":"inVALUABLE is so valuable it CANNOT be valued — paradoxically, in means beyond value here.","t":["religion"]},{"w":"invasion","d":"the act of invading; the act of an army that invades for conquest or plunder","s":"An invasion of tourists.","p":"ih-NVAY-zhuhn","o":"French","y":3,"bp":73,"m":"invation","sy":"ih.nvey.zhah.n","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin invasio = attack, from invadere(to invade)","h":"inVASION — think inVASIVE without the ive, the VAST army comes in.","t":["war"]},{"w":"inventive","d":"(used of persons or artifacts) marked by independence and creativity in thought or action; - Lewis Mumford","p":"ih-NVEH-ntihv","o":"Latin","y":3,"bp":33,"m":"iventive","sy":"ih.nveh.ntih.v","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin invenire = to come upon, find","h":"An INVENTIVE mind lets ideas VENT freely — INVENT + IVE = alive with creativity.","t":["ancient"]},{"w":"inverse","d":"Opposite in position, order, or effect.","s":"Division is the inverse of multiplication, our math teacher reminded us.","p":"IN-vurs","o":"Latin","y":3,"bp":68,"ps":"adjective","r":"Latin inversus, from invertere (to turn upside down).","h":"Inverse means flipped — turned inside out or exactly reversed.","nt":"vocab-NWFinal-2026-Junior"},{"w":"invert","d":"make an inversion (in a musical composition)","s":"Here the theme is inverted.","p":"ih-NVURT","o":"Latin","y":3,"bp":70,"m":"envert","sy":"ih.nver.t","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin invertere = to turn upside down","h":"To INVERT is to turn IN the VERT(ical) — flip it inside out, like an umbrella in wind.","t":["music"]},{"w":"iota","d":"a tiny or scarcely detectable amount","s":"She didn't show an iota of fear when she stepped onto the stage for the first time.","p":"eye-OH-tuh","o":"Greek","y":1,"bp":37,"m":"iotta","sy":"ay.ow.tah","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek iota = ninth letter of Greek alphabet, smallest letter","h":"IOTA is a tiny Greek letter spelled with just four tiny letters — I-O-T-A, no doubles needed."},{"w":"judgment","d":"The ability to decide wisely; a decision or opinion reached.","s":"The referee's judgment was fair, even though our team lost the point.","p":"JUHJ-muhnt","o":"French","y":2,"bp":70,"ps":"noun","r":"Old French jugement, from Latin judicare (to judge).","h":"A judge uses judgment — careful thinking that leads to a decision.","nt":"vocab-NWFinal-2026-Junior"},{"w":"judiciary","d":"persons who administer justice","s":"The framers of the Constitution designed the judiciary to be independent from political pressure.","p":"joo-DIH-shee-eh-ree","o":"Latin","y":3,"bp":36,"m":"judicary","sy":"jhuw.dih.shiy.eh.riy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin judiciarius = of the courts (judex = judge)","h":"JUDICIARY has JUDICI + ARY — the judges are in the JUDICI-ARY, like a library of law."},{"w":"juror","d":"someone who serves (or waits to be called to serve) on a jury","s":"The juror listened carefully to every piece of evidence before making a decision about the case.","p":"JUU-rer","o":"Latin","y":2,"bp":40,"m":"jurror","sy":"jhuh.rer","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin jus/juris = law, right","h":"A juror listens to the law (jur) and gives an OR-der of verdict.","t":["law"]},{"w":"karate","d":"a method of self-defense","s":"After years of practice, Maya earned her black belt in karate and could break a wooden board with her hand.","p":"k-ur-AH-t-ee","o":"Latin","y":3,"bp":50,"m":"karate — misspelled as 'karati'","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Japanese kara = empty + te = hand","h":"KARATE = empty hand (kara+te) — your bare HAND is your weapon; ends in -te like 'tay.'"},{"w":"karma","d":"The belief that your actions bring matching good or bad results.","s":"She called it good karma when her kindness was repaid by a stranger's help.","p":"KAR-muh","o":"Sanskrit","y":3,"bp":70,"ps":"noun","r":"Sanskrit karman (action, deed) — deeds shape your fate.","h":"Karma: what goes around comes around — actions boomerang back to you.","nt":"vocab-NWFinal-2026-Junior"},{"w":"kilometer","d":"a metric unit of length equal to 1000 meters (or 0.621371 miles)","s":"The runners trained every morning by jogging one kilometer around the track before school.","p":"kuh-LAH-muh-ter","o":"Greek","y":3,"bp":34,"m":"killometer","sy":"kah.laa.mah.ter","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek khilioi = thousand + metron = measure","h":"A KILO METER measures a thousand meters — one kilo, one meter, no double letters needed!","t":["numbers"]},{"w":"kind-hearted","d":"Naturally gentle, caring, and generous toward others.","s":"The kind-hearted crossing guard always waves and asks about our day.","p":"KYND-HAR-tid","o":"Old English","y":2,"bp":68,"ps":"adjective","r":"Old English gecynde (natural, kind) + heorte (heart).","h":"KIND + HEART: a heart full of kindness — someone who cares by nature.","nt":"vocab-NWFinal-2026-Junior"},{"w":"kinetic","d":"Relating to motion or produced by movement.","s":"A rolling bowling ball has kinetic energy that knocks the pins down.","p":"kih-NEH-tik","o":"Greek","y":3,"bp":72,"ps":"adjective","r":"Greek kinetikos (of motion), from kinein (to move).","h":"Kinetic = moving: kinetic energy is the energy of things in motion.","nt":"vocab-NWFinal-2026-Junior"},{"w":"kingling","d":"A minor or unimportant king; a petty king.","s":"The legend told of a boastful kingling who ruled only one tiny valley.","p":"KING-ling","o":"Old English","y":4,"bp":58,"ps":"noun","r":"Old English cyning (king) + -ling (small, lesser).","h":"KING + LING (little, like duckling): a little king of a little land.","nt":"vocab-NWFinal-2026-Junior"},{"w":"kingship","d":"The position, power, or rule of a king.","s":"The prince prepared for kingship by studying the laws of the land.","p":"KING-ship","o":"Old English","y":3,"bp":64,"ps":"noun","r":"Old English cyning (king) + -scipe (state, condition).","h":"KING + SHIP (state of being, like friendship): the job of being king.","nt":"vocab-NWFinal-2026-Junior"},{"w":"knell","d":"The slow, solemn ringing of a bell, especially for a death.","s":"In the story, the church bell's knell told the village of the king's death.","p":"NEL","o":"Old English","y":4,"bp":66,"ps":"noun","r":"Old English cnyllan (to ring, strike a bell).","h":"A knell is a sad, slow BONG... BONG... — the bell of mourning.","nt":"vocab-NWFinal-2026-Junior"},{"w":"kudos","d":"an expression of approval and commendation","p":"KOO-dohs","o":"Greek","y":2,"bp":40,"m":"cutdos","sy":"kuw.dow.s","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek kydos = glory, renown, fame","h":"KUDOS starts with KU — give KUDOS to someone KUl who deserves the praise, ending in the O-S of glory."},{"w":"laborious","d":"characterized by effort to the point of exhaustion; especially physical effort","s":"Digging the irrigation trenches by hand was a laborious task that left the farmers exhausted by sunset.","p":"luh-BAW-ree-uhs","o":"Latin","y":3,"bp":34,"m":"laboriuos","sy":"la.bo.ri.ous","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin laborare = to toil","h":"Labor is in the word — hard LABOR makes it laborious.","t":["character"]},{"w":"laddie","d":"A boy or young man.","s":"The Scottish grandfather called his grandson a fine wee laddie.","p":"LAD-ee","o":"English","y":2,"bp":62,"ps":"noun","r":"English lad + -ie, a Scottish pet ending, as in lassie.","h":"LAD + IE: a friendly Scottish way to say 'boy' — lassie's brother.","nt":"vocab-NWFinal-2026-Junior"},{"w":"laud","d":"is to praise or extol","p":"l-AW-d","o":"French","y":3,"bp":47,"m":"lawd","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin laus/laudis = praise","h":"LAUD sounds like 'lord'—you LAUD someone by treating them like a lord."},{"w":"lax","d":"Not strict or careful enough; loose.","s":"The lax substitute let students chat instead of following class rules.","p":"LAKS","o":"Latin","y":3,"bp":70,"ps":"adjective","r":"Latin laxus (loose, slack).","h":"Lax rhymes with relax — rules so relaxed they're barely enforced.","nt":"vocab-NWFinal-2026-Junior"},{"w":"lead","d":"To guide people or show the way.","s":"The team captain will lead the warm-up before the big game.","p":"LEED","o":"Old English","y":2,"bp":62,"ps":"verb","r":"Old English laedan (to guide, cause to go).","h":"A leader leads — walks in front and shows everyone the way.","nt":"vocab-NWFinal-2026-Junior"},{"w":"legacy","d":"(law) a gift of personal property by will","s":"The scientist's greatest legacy was discovering a vaccine that saved millions of lives around the world.","p":"LEH-guh-see","o":"French","y":2,"bp":42,"m":"legasy","sy":"leh.gah.siy","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin legare = to bequeath, send as ambassador","h":"A LEGACY ends in -ACY like 'accuracy' — your ancestor's gift demands ACCURACY in spelling: l-e-g-a-c-y.","t":["law"]},{"w":"legendary","d":"so celebrated as to having taken on the nature of a legend","s":"The legendary exploits of the arctic trailblazers.","p":"LEH-juh-ndeh-ree","o":"French","y":3,"bp":34,"m":"legendery","sy":"leh.jhah.ndeh.riy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin legenda = things to be read","h":"legendARY: legends are extrAoRdinARY — legendARY ends in ARY, not ERY, because legends are extraordinARY.","t":["myth"],"vh":"relating to"},{"w":"lever","d":"A stiff bar that pivots on a point to lift or move heavy loads.","s":"We used a broomstick as a lever to lift the heavy garden rock.","p":"LEH-vur","o":"French","y":2,"bp":70,"ps":"noun","r":"Old French lever (to raise), from Latin levare (to lift).","h":"A lever LEVitates loads — a seesaw bar that lifts heavy things easily.","nt":"vocab-NWFinal-2026-Junior"},{"w":"liberalism","d":"a political orientation that favors social progress by reform and by changing laws rather than by revolution","s":"The professor explained how liberalism shaped many of the social reforms of the twentieth century.","p":"LIH-bur-uh-lih-zuhm","o":"Latin","y":3,"bp":37,"m":"liberalisim","sy":"lih.ber.ah.lih.zah.m","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin liber = free","h":"LIBERALism is the doctrine of being LIBERAL — just add -ism to the full word.","t":["law","politics"]},{"w":"liberate","d":"give equal rights to; of women and minorities","s":"The students liberated their slaves upon graduating from the university.","p":"LIH-bur-ayt","o":"Latin","y":3,"bp":32,"m":"liberate","sy":"lih.ber.ey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin liberare = to set free, from liber = free","h":"To LIBERATE ends in -ATE — you LIBERATE someone's fate by freeing them."},{"w":"likelihood","d":"The chance that something will happen; probability.","s":"With those dark clouds, the likelihood of rain at recess is high.","p":"LYK-lee-hood","o":"English","y":3,"bp":68,"ps":"noun","r":"Likely (from Old Norse likligr) + -hood (state of being).","h":"LIKELY + HOOD: how likely it is — the odds it will really happen.","nt":"vocab-NWFinal-2026-Junior"},{"w":"linear","d":"designating or involving an equation whose terms are of the first degree","p":"LIH-nee-er","o":"Latin","y":3,"bp":71,"m":"liniear","sy":"lih.niy.er","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin linearis = of a line, from linea = line","h":"LINEAR thinking goes in a straight LINE — no extra letters, no detours.","t":["numbers"]},{"w":"linguist","d":"A person skilled in languages or who studies how language works.","s":"The linguist amazed us by greeting students in seven different languages.","p":"LING-gwist","o":"Latin","y":3,"bp":74,"ps":"noun","r":"Latin lingua (tongue, language) + -ist (one who).","h":"LINGUA means tongue — a linguist's tongue speaks and studies many languages.","nt":"vocab-NWFinal-2026-Junior"},{"w":"link","d":"A ring in a chain; anything that connects two things.","s":"Each paper link in our classroom chain listed one act of kindness.","p":"LINGK","o":"Norse","y":2,"bp":64,"ps":"noun","r":"Old Norse hlekkr (link of a chain).","h":"Chain links connect — a link is the connector joining things together.","nt":"vocab-NWFinal-2026-Junior"},{"w":"liquidator","d":"A person who closes down a business and sells its property to pay debts.","s":"The liquidator sold the toy store's shelves and stock after the shop closed for good.","p":"LIH-kwih-day-ter","o":"Latin","y":4,"bp":60,"ps":"noun","r":"From Latin liquidare, 'to make liquid or clear,' as in clearing debts.","h":"Turns a company's stuff into 'liquid' cash to settle what it owes.","nt":"vocab-NWFinal-2026-Junior"},{"w":"liquor","d":"A strong alcoholic drink; also any liquid a food has been cooked in.","s":"The store keeps liquor on a high shelf where only adults can reach it.","p":"LIH-ker","o":"Latin","y":3,"bp":58,"ps":"noun","r":"From Latin liquor, 'a liquid,' from liquere, 'to be fluid.'","h":"Same root as 'liquid' — a strong drinkable liquid.","nt":"vocab-NWFinal-2026-Junior"},{"w":"literally","d":"in a literal sense","p":"LIH-ter-uh-lee","o":"French","y":3,"bp":34,"m":"literaly","sy":"lih.ter.ah.liy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adverb","r":"Latin littera = letter + -ally = in the manner of","h":"LITERALLY has double 'l' before '-y' — people literally overuse this word, so it doubly deserves that 'l'."},{"w":"literate","d":"a person who can read and write","p":"LIH-ter-uht","o":"Latin","y":3,"bp":73,"m":"litterate","sy":"lih.ter.ah.t","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin literatus = learned, from littera = letter","h":"A LITERATE person knows their letters — 'liter-ate', one 't', well-read and precise."},{"w":"literature","d":"creative writing of recognized artistic value","p":"LIH-ter-uh-cher","o":"Latin","y":3,"bp":35,"m":"litterature","sy":"lih.ter.ah.cher","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin literatura = writing, grammar, from littera = letter","h":"LITERATURE — one 't', because great writing is precise: liter-a-ture, letter by letter.","t":["painting"]},{"w":"litigate","d":"engage in legal proceedings","p":"LIH-tih-gayt","o":"Latin","y":3,"bp":32,"m":"litagate","sy":"lih.tih.gey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin litigare = to dispute, from lis = lawsuit + agere = to drive","h":"To litigate is to drive a lawsuit — 'liti' (dispute) + 'gate' (drive it through the courtroom gate).","t":["law"]},{"w":"locative","d":"A grammar form of a word that shows place or location.","s":"In Sanskrit class, Mia learned the locative case tells where something happens.","p":"LAH-kuh-tiv","o":"Latin","y":4,"bp":62,"ps":"noun","r":"From Latin locus, 'place,' the root of 'location' and 'local.'","h":"Think 'location' — the word form that points to a place.","nt":"vocab-NWFinal-2026-Junior"},{"w":"loco","d":"Crazy or out of one's mind; a slang word for wildly foolish.","s":"My cousin says our dog goes loco whenever the doorbell rings.","p":"LOH-koh","o":"Spanish","y":3,"bp":60,"ps":"adjective","r":"Borrowed straight from Spanish loco, meaning 'insane.'","h":"Spanish for crazy — a loco idea is a nutty one.","nt":"vocab-NWFinal-2026-Junior"},{"w":"logic","d":"Careful, step-by-step reasoning used to reach a sound conclusion.","s":"Priya used logic to figure out which locker had to be hers.","p":"LAH-jik","o":"Greek","y":2,"bp":70,"ps":"noun","r":"From Greek logos, 'word, reason,' via logike techne, 'art of reasoning.'","h":"Logic is thinking that follows clear reasons, one step after another.","nt":"vocab-NWFinal-2026-Junior"},{"w":"loiterer","d":"A person who hangs around a place slowly with no real purpose.","s":"The guard asked the loiterer by the gym doors to move along.","p":"LOY-ter-er","o":"Dutch","y":3,"bp":64,"ps":"noun","r":"From Middle Dutch loteren, 'to wobble, dawdle.'","h":"A loiterer lingers and lags around with nothing to do.","nt":"vocab-NWFinal-2026-Junior"},{"w":"loneliness","d":"The sad feeling of being alone or without friends.","s":"Writing letters to his grandma helped ease Sam's loneliness at camp.","p":"LOHN-lee-nes","o":"English","y":2,"bp":68,"ps":"noun","r":"From 'lone,' a shortened form of 'alone,' plus the suffix -ness.","h":"The '-ness' of being lone — the ache of no company.","nt":"vocab-NWFinal-2026-Junior"},{"w":"index","d":"An alphabetical list at a book's end showing where topics appear.","s":"Use the index in the back to find every page about volcanoes.","p":"IN-deks","o":"Latin","y":2,"bp":70,"ps":"noun","r":"From Latin index, 'pointer, forefinger,' from indicare, 'to point out.'","h":"Your index finger points; an index points you to the right page.","nt":"vocab-NWFinal-2026-Junior"},{"w":"indicant","d":"Something that serves as a sign or indication of something else.","s":"The coach said sore muscles are an indicant of a hard workout.","p":"IN-dih-kunt","o":"Latin","y":4,"bp":60,"ps":"noun","r":"From Latin indicare, 'to point out,' the same root as 'indicate.'","h":"An indicant indicates — it's a pointer or sign of something.","nt":"vocab-NWFinal-2026-Junior"},{"w":"indicate","d":"be a signal for or a symptom of","s":"These symptoms indicate a serious illness.","p":"IH-nduh-kayt","o":"Latin","y":3,"bp":32,"m":"indacate","sy":"ih.ndah.key.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin indicare = to point out, from index = pointer","h":"To indICate is to point — the INDIC finger (index) + ATE: indic+ATE something out.","t":["disease"]},{"w":"indigestible","d":"digested with difficulty","s":"The tough, rubbery meat was practically indigestible, and most of the campers left it on their plates.","p":"in-dih-JES-tuh-bul","o":"Latin","y":5,"bp":36,"sy":"in.di.gestible","ps":"adjective","r":"Old English (ca. 450-1100): in (Old English (ca. 450-1100))","h":"IN + DIGEST + IBLE: your stomach is NOT ABLE (IBLE) to DIGEST it.","nt":"vocab-NWFinal-2026-Junior"},{"w":"indistinct","d":"not clearly defined or easy to perceive or understand","s":"Indistinct shapes in the gloom.","p":"ih-ndih-STIHNGKT","o":"Latin","y":3,"bp":34,"m":"indistint","sy":"ih.ndih.stih.ngkt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin distinguere = to separate, mark off","h":"Indistinct has a hidden 'sting' — the 'stinct' stings like a bee you can barely see in the fog."},{"w":"ineligible","d":"not eligible","s":"The star quarterback was declared ineligible to play in the championship game after officials discovered that he had failed two of his classes, violating the strict academic requirements set by the school athletic association.","p":"ih-NEH-lih-juh-buhl","o":"Latin","y":3,"bp":37,"m":"ineligable","sy":"ih.neh.lih.jhah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin eligere = to choose","h":"INELIGIBLE players can't be chosen — end in '-ible' like 'eligible' itself, just blocked by 'in-'."},{"w":"inestimable","d":"beyond calculation or measure","p":"in-ES-tih-muh-bul","o":"French","y":5,"bp":35,"sy":"in.es.timable","ps":"adjective","r":"Latin: in- (Latin)","h":"IN-ESTIMATE-ABLE: you cannot ESTIMATE its value — too great to measure.","t":["numbers"],"nt":"vocab-NWFinal-2026-Junior"},{"w":"inexhaustible","d":"that cannot be entirely consumed or used up","s":"An inexhaustible supply of coal.","p":"ih-nih-GZAW-stuh-buhl","o":"Latin","y":3,"bp":39,"m":"inexhaustable","sy":"ih.nih.gzao.stah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin exhaustus = drained (ex+haurire = to draw out)","h":"INEXHAUSTIBLE ends in -IBLE not -ABLE — the supply of I's in this word is inexhaustible."},{"w":"inexpressible","d":"Too great or deep to be described in words.","s":"Winning the trophy filled Ana with inexpressible joy.","p":"in-ek-SPREH-suh-bul","o":"Latin","y":3,"bp":66,"ps":"adjective","r":"Latin in-, 'not,' plus exprimere, 'to press out, put into words.'","h":"Not expressible — feelings so big words can't carry them.","nt":"vocab-NWFinal-2026-Junior"},{"w":"infamous","d":"known widely and usually unfavorably","p":"IH-nfuh-muhs","o":"Latin","y":3,"bp":32,"m":"infameous","sy":"ih.nfah.mah.s","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin fama = fame, reputation","h":"INFAMOUS is the opposite of FAMOUS — just add IN- and drop an O to go from hero to villain."},{"w":"infatuated","d":"arouse unreasoning love or passion in and cause to behave in an irrational way","s":"His new car has infatuated him.","p":"ih-NFA-choo-ay-tihd","o":"Latin","y":3,"bp":37,"m":"infactuated","sy":"ih.nfae.chuw.ey.tih.d","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin fatuus = foolish, silly","h":"She was INFATUATED — FAT with foolish love, spelled FATU not FACTU."},{"w":"infatuation","d":"a foolish and usually extravagant passion or love or admiration","s":"Mia's infatuation with the new student in class faded after two weeks when she realized they had nothing in common.","p":"ih-nfa-choo-AY-shuhn","o":"Latin","y":3,"bp":37,"m":"infatuation","sy":"in.fat.u.a.tion","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin fatuus = foolish","h":"inFATUation: being FATUOUS (foolish) over someone you love"},{"w":"irksome","d":"Annoying, tiresome, or irritating.","s":"Raking the same leaves every weekend became an irksome chore.","p":"URK-sum","o":"Norse","y":3,"bp":70,"ps":"adjective","r":"From Middle English irken, 'to weary,' possibly from Old Norse yrkja, 'to work.'","h":"If something irks you, it's irksome — a small steady annoyance.","nt":"vocab-NWFinal-2026-Junior"},{"w":"irradiate","d":"give spiritual insight to; in religion","s":"Scientists use ultraviolet light to irradiate certain foods, a process that destroys harmful bacteria and significantly extends the shelf life of produce without changing its nutritional content or overall flavor.","p":"ih-RAY-dee-ayt","o":"Latin","y":3,"bp":34,"m":"iradate","sy":"ih.rey.diy.ey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin irradiare = to beam upon, from in+radiare = to shine","h":"IRRADIate has RADI in the middle — think RADIO waves RADIATING outward, with a double R at the start.","t":["religion"]},{"w":"irreverence","d":"an irreverent mental attitude","s":"The comedian's playful irreverence toward stuffy traditions delighted audiences who were tired of taking everything so seriously.","p":"ih-REH-ver-uhns","o":"Latin","y":3,"bp":36,"m":"irreverance","sy":"ih.reh.ver.ah.ns","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin revereri = to stand in awe of","h":"IrreveRENCE ends in -ence like reveRENCE — just slap ir- in front and keep the spelling."},{"w":"irreversible","d":"incapable of being reversed","s":"Irreversible momentum toward revolution.","p":"ih-rih-VUR-suh-buhl","o":"Latin","y":3,"bp":38,"m":"irreversable","sy":"ih.rih.ver.sah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin reversus = turned back","h":"You can't VERSE it back — irreversIBLE uses -ible, impossible to change to -able."},{"w":"irritable","d":"is easily irritated or annoyed","p":"IH-r-uh-t-uh-b-uh-l","o":"Latin","y":3,"bp":99,"m":"irritible","nt":"Junior | North South Finals, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin irritare = to provoke","h":"IRRItable has double 'r' and -able — an irritable person is always raring (rr) to snap."},{"w":"isle","d":"An island, especially a small one.","s":"The ferry dropped us on a tiny isle with one lighthouse.","p":"EYL","o":"Latin","y":2,"bp":68,"ps":"noun","r":"From Latin insula, 'island,' via Old French isle.","h":"An isle is an island — same word family, land ringed by water.","nt":"vocab-NWFinal-2026-Junior"},{"w":"itinerary","d":"an established line of travel or access","s":"Before the trip, Mom printed out a detailed itinerary so we would know exactly which cities to visit each day.","p":"eye-TIH-ner-eh-ree","o":"Latin","y":3,"bp":36,"m":"itinarary","sy":"ay.tih.ner.eh.riy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin iter/itineris = journey, road","h":"Your ITINERARY maps your ITER — the Latin road — keep both I's in place."},{"w":"itinerate","d":"travel from place to place, as for work","p":"eye-TIN-er-ayt","o":"Latin","y":3,"bp":34,"m":"itinnerate","sy":"i.tin.er.ate","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin iter/itineris = journey, road","h":"To ITINERATE is to ITERATE your journeys — one N, one T, keep moving."},{"w":"jaundice","d":"a yellow discoloration of the skin or eyes","s":"Jealousy had jaundiced his judgment.","p":"j-AW-n-d-uh-s","o":"English","y":3,"bp":48,"m":"jaundace","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old French jaunisse from jaune = yellow","h":"JAUNDICE: the JAUN sounds like 'john'—John turned yellow from jaundice; end with -DICE.","t":["body"]},{"w":"jovial","d":"Cheerful, jolly, and full of good humor.","s":"Our jovial bus driver greets every kid with a joke.","p":"JOH-vee-ul","o":"Latin","y":3,"bp":72,"ps":"adjective","r":"From Latin Jovialis, 'of Jove (Jupiter),' whose planet was thought to bring cheer.","h":"Born under jolly Jupiter — a jovial person laughs easily.","nt":"vocab-NWFinal-2026-Junior"},{"w":"longevity","d":"duration of service","s":"Her longevity as a star.","p":"law-NJEH-vuh-tee","o":"Latin","y":3,"bp":34,"m":"longevety","sy":"lao.njheh.vah.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin longus = long + aevum = age/life","h":"LONGEVITY means a LONG life with VITALITY — spot the word VITA (life) hiding inside: long-VITY."},{"w":"lovable","d":"Easy to love; having qualities that win affection.","s":"The shelter puppy was so lovable that three families wanted him.","p":"LUH-vuh-bul","o":"Old English","y":2,"bp":62,"ps":"adjective","r":"From Old English lufu, 'love,' plus the suffix -able.","h":"Able to be loved — cuddly, sweet, and hard to resist.","nt":"vocab-NWFinal-2026-Junior"},{"w":"love","d":"In tennis, a score of zero.","s":"The announcer called the score forty-love before the final serve.","p":"LUV","o":"Old English","y":3,"bp":72,"ps":"noun","r":"Tennis sense possibly from French l'oeuf, 'the egg,' shaped like a zero.","h":"In tennis, love means nothing — a score of zero.","nt":"vocab-NWFinal-2026-Junior","vh":"tennis score that is:"},{"w":"low-spirited","d":"Feeling sad, gloomy, or discouraged.","s":"Jaden was low-spirited after his team lost the semifinal.","p":"loh-SPIH-rih-tid","o":"English","y":3,"bp":64,"ps":"adjective","r":"English compound: 'low' plus 'spirited,' spirits sunk down low.","h":"When your spirits are low, you're down in the dumps.","nt":"vocab-NWFinal-2026-Junior"},{"w":"lure","d":"To tempt or attract someone, often with a promised reward.","s":"The smell of fresh cookies lured the kids into the kitchen.","p":"LOOR","o":"French","y":3,"bp":70,"ps":"verb","r":"From Old French loirre, a baited device used to call back hawks.","h":"A fishing lure tempts fish; to lure is to tempt anyone closer.","nt":"vocab-NWFinal-2026-Junior"},{"w":"lying","d":"Saying things that are not true; telling falsehoods.","s":"Lying about who broke the vase only made things worse.","p":"LY-ing","o":"Old English","y":2,"bp":60,"ps":"noun","r":"From Old English leogan, 'to tell an untruth.'","h":"A liar's habit — speaking untruths on purpose.","nt":"vocab-NWFinal-2026-Junior"},{"w":"machinery","d":"machines or machine systems collectively","s":"The complex machinery of negotiation.","p":"muh-SHEE-ner-ee","o":"French","y":3,"bp":34,"m":"machienery","sy":"mah.shiy.ner.iy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"French machine + -ery = collective system of machines","h":"MACHINERY = MACHINE + RY — the whole system of machines, just tack on RY.","t":["tools"]},{"w":"machinist","d":"a craftsman skilled in operating machine tools","s":"The skilled machinist carefully shaped the metal parts using a lathe and drill press.","p":"muh-SHEE-nuhst","o":"French","y":3,"bp":33,"m":"machenist","sy":"mah.shiy.nah.st","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"French machine + -ist (one who operates)","h":"A MACHINIST operates machines — MACHINE loses its E and gains -IST, the expert suffix.","t":["jobs","tools"]},{"w":"magnet","d":"A piece of metal that pulls iron or steel toward itself.","s":"We used a magnet to pick up the spilled paper clips.","p":"MAG-nit","o":"Greek","y":2,"bp":66,"ps":"noun","r":"From Greek magnetis lithos, 'stone of Magnesia,' a region with magnetic rocks.","h":"A magnet attracts — it pulls iron things right to it.","nt":"vocab-NWFinal-2026-Junior"},{"w":"magnificent","d":"is making a splendid appearance or show","p":"m-a-g-n-IH-f-uh-s-uh-n-t","o":"English","y":3,"bp":53,"m":"magnificant","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin magnificus = splendid (magnus = great + facere = to make)","h":"MAGNIficent — MAGNIfy the greatness; ends in -cent not -cant"},{"w":"maharaja","d":"A great king or prince in India.","s":"The museum showed the jeweled throne of a maharaja.","p":"mah-huh-RAH-juh","o":"Sanskrit","y":3,"bp":72,"ps":"noun","r":"Sanskrit maha, 'great,' plus raja, 'king.'","h":"Maha (great) + raja (king) = a great Indian king.","nt":"vocab-NWFinal-2026-Junior"},{"w":"maharishi","d":"A great Hindu sage or wise spiritual teacher.","s":"Villagers traveled far to hear the maharishi's wise teachings.","p":"mah-huh-REE-shee","o":"Sanskrit","y":4,"bp":66,"ps":"noun","r":"Sanskrit maha, 'great,' plus rishi, 'sage or seer.'","h":"Maha (great) + rishi (sage) = a great wise teacher.","nt":"vocab-NWFinal-2026-Junior"},{"w":"maiden","d":"A young unmarried girl; also means first, as in a maiden voyage.","s":"In the legend, a brave maiden outsmarted the dragon.","p":"MAY-den","o":"Old English","y":2,"bp":62,"ps":"noun","r":"From Old English maegden, 'young girl.'","h":"A maiden is a young girl; a maiden voyage is a ship's first trip.","nt":"vocab-NWFinal-2026-Junior"},{"w":"maidenhood","d":"The time or state of being a young unmarried girl.","s":"Grandma's diary describes her maidenhood on the family farm.","p":"MAY-den-hood","o":"Old English","y":4,"bp":58,"ps":"noun","r":"Old English maegden, 'girl,' plus -hood, 'state or condition.'","h":"Like childhood but for maidens — a girl's young unmarried years.","nt":"vocab-NWFinal-2026-Junior"},{"w":"maintain","d":"To keep something in good condition or keep it going.","s":"Dad taught me to maintain my bike by oiling the chain.","p":"mayn-TAYN","o":"French","y":2,"bp":68,"ps":"verb","r":"From Old French maintenir, from Latin manu tenere, 'to hold in the hand.'","h":"To maintain is to keep holding things steady and in shape.","nt":"vocab-NWFinal-2026-Junior"},{"w":"maize","d":"Corn; the tall grain plant with yellow kernels on cobs.","s":"The farmer planted rows of maize behind the barn.","p":"MAYZ","o":"Spanish","y":3,"bp":72,"ps":"noun","r":"From Spanish maíz, borrowed from Taíno mahiz.","h":"Maize is just corn — sounds like 'maze' but grows in rows.","nt":"vocab-NWFinal-2026-Junior"},{"w":"majestic","d":"Grand, dignified, and impressive enough to inspire awe.","p":"muh-JEH-stihk","o":"Latin","y":3,"bp":32,"m":"majesitc","sy":"mah.jheh.stih.k","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin majestas = greatness, dignity","h":"A MAJESTIC king wears a crown shaped like the letter J — no sneaky extra letters hiding inside.","t":["maps"]},{"w":"mammoth","d":"Huge; enormous in size. Also a giant hairy elephant of the Ice Age.","s":"Cleaning the whole garage turned into a mammoth job.","p":"MAM-uth","o":"English","y":3,"bp":70,"ps":"adjective","r":"From Russian mamont, the giant Ice Age elephant; English via that borrowing.","h":"Big as a woolly mammoth — anything mammoth is gigantic.","nt":"vocab-NWFinal-2026-Junior"},{"w":"mandatory","d":"the recipient of a mandate","p":"MA-nduh-taw-ree","o":"Latin","y":3,"bp":34,"m":"manditory","sy":"mae.ndah.tao.riy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin mandatorius = of a command, from mandatum = command","h":"MANDATORY has 'mandate' inside it — it is MANDATORY to remember the 'a', not 'i'."},{"w":"mania","d":"an irrational but irresistible motive for a belief or action","s":"The town was swept up in a mania for collecting trading cards, with students trading them at every recess.","p":"MAY-nee-uh","o":"Latin","y":3,"bp":71,"m":"maina","sy":"mey.niy.ah","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek mania = madness, frenzy","h":"MAY-nee-uh: say MAY, then NEE, then just 'a' — mania ends in -ia like phobia.","t":["logic"]},{"w":"manliness","d":"The qualities thought of as brave, strong, or manly.","s":"The knight believed true manliness meant protecting the weak.","p":"MAN-lee-nes","o":"Old English","y":3,"bp":58,"ps":"noun","r":"From Old English mann, 'person, man,' plus -ly and -ness.","h":"The '-ness' of being manly — courage and strength of character.","nt":"vocab-NWFinal-2026-Junior"},{"w":"mannerism","d":"A small habit of behavior or speech special to one person.","s":"Twirling her pencil while thinking is my teacher's funny mannerism.","p":"MAN-er-ih-zum","o":"French","y":3,"bp":70,"ps":"noun","r":"From 'manner,' Old French maniere, 'way of handling,' from Latin manus, 'hand.'","h":"A personal manner repeated — a quirky little habit.","nt":"vocab-NWFinal-2026-Junior"},{"w":"mantra","d":"A word or phrase repeated often, especially in prayer or for focus.","s":"Before each spelling round, her mantra was 'slow and steady.'","p":"MAHN-truh","o":"Sanskrit","y":3,"bp":74,"ps":"noun","r":"Sanskrit mantra, 'sacred utterance,' from man, 'to think.'","h":"A phrase you repeat and repeat to calm and focus the mind.","nt":"vocab-NWFinal-2026-Junior"},{"w":"marathon","d":"any long and arduous undertaking","s":"Studying for finals felt like a marathon as Jaylen sat at his desk for six straight hours reviewing every chapter.","p":"MEH-ruh-thahn","o":"Greek","y":1,"bp":40,"m":"marathone","sy":"mar.a.thon","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek Marathon, the Greek plain where Athenians defeated Persians in 490 BC","h":"MARAthon — a MARA-vel of endurance; think of the messenger who ran from MARA-thon to Athens"},{"w":"marinate","d":"soak in marinade","s":"Sofia decided to marinate the chicken overnight in lemon juice, garlic, and herbs so it would be incredibly tender on the grill.","p":"MEH-ruh-nayt","o":"Italian","y":4,"bp":60,"m":"marinade (used as verb)","sy":"mar.i.nate","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"verb","r":"Italian marinare, from marina = seashore, Latin mare = sea (originally meant to pickle in brine)","h":"MARINate — you soak food in the MARINE (sea-salty) liquid brine"},{"w":"martial","d":"Relating to war, fighting, or the military.","s":"Kayla practices karate, a martial art, three times a week.","p":"MAR-shul","o":"Latin","y":3,"bp":74,"ps":"adjective","r":"From Latin Martialis, 'of Mars,' the Roman god of war.","h":"From Mars, god of war — martial means war-related.","nt":"vocab-NWFinal-2026-Junior"},{"w":"marvel","d":"To be filled with wonder or amazement; also a wonderful thing.","s":"We marveled at the fireworks bursting over the lake.","p":"MAR-vul","o":"French","y":2,"bp":68,"ps":"verb","r":"From Old French merveille, from Latin mirabilia, 'wonderful things.'","h":"Marvel and 'marvelous' share a root — to marvel is to be amazed.","nt":"vocab-NWFinal-2026-Junior"},{"w":"masonry","d":"Stonework or brickwork; the craft of building with stone or brick.","s":"The old school's masonry has stood strong for a hundred years.","p":"MAY-sun-ree","o":"French","y":3,"bp":66,"ps":"noun","r":"From Old French maçon, 'stoneworker.'","h":"A mason lays bricks and stone; masonry is what the mason builds.","nt":"vocab-NWFinal-2026-Junior"},{"w":"massive","d":"Very large, heavy, and solid.","s":"A massive boulder blocked the hiking trail after the storm.","p":"MA-siv","o":"French","y":2,"bp":62,"ps":"adjective","r":"From French massif, from Latin massa, 'lump, mass.'","h":"Full of mass — massive things are huge and weighty.","nt":"vocab-NWFinal-2026-Junior"},{"w":"materialize","d":"come into being; become reality","s":"Her dream really materialized.","p":"muh-TIH-ree-uh-leyez","o":"Latin","y":2,"bp":49,"m":"materialise","sy":"mah.tih.riy.ah.lay.z","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin materia = matter, substance","h":"To MATERIALIZE is to become MATERIAL — keep 'material' inside the word and just add -ize."},{"w":"maternal","d":"characteristic of a mother; - Dorothy Sayers","s":"Warm maternal affection for her guest.","p":"muh-TUR-nuhl","o":"Latin","y":3,"bp":32,"m":"maternall","sy":"mah.ter.nah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin mater = mother","h":"MATERnal love comes from your MATER — Latin for mother — single L at the end.","t":["kinship"]},{"w":"maternity","d":"the state of being pregnant; the period from conception to birth when a woman carries a developing fetus in her uterus","p":"muh-TUR-nih-tee","o":"Latin","y":3,"bp":34,"m":"maturnity","sy":"mah.ter.nih.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin mater = mother","h":"MATERnity ward is where MATER (mom) goes — the E stays strong, no U in sight."},{"w":"matrimony","d":"the state of being a married couple voluntarily joined for life (or until divorce)","s":"The couple exchanged vows of matrimony beneath an archway of white roses as their family watched with joyful tears.","p":"MA-truh-moh-nee","o":"Latin","y":3,"bp":34,"m":"matrimoney","sy":"mat.ri.mo.ny","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin matrimonium, from mater = mother + -monium (condition, state)","h":"MATRImony — MATRI means MOTHER; matrimony creates a family with a MOTHER at its heart"},{"w":"maturation","d":"coming to full development; becoming mature","p":"ma-cher-AY-shuhn","o":"Latin","y":3,"bp":35,"m":"maturaton","sy":"mae.cher.ey.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin maturare = to ripen","h":"The NATION celebrated its maturation into a fully developed country."},{"w":"maxim","d":"A short well-known saying that states a rule or truth.","s":"Coach's favorite maxim is 'practice makes perfect.'","p":"MAK-sim","o":"Latin","y":3,"bp":74,"ps":"noun","r":"From Latin maxima propositio, 'greatest statement.'","h":"A maximum truth packed into a tiny saying — a wise one-liner.","nt":"vocab-NWFinal-2026-Junior"},{"w":"maze","d":"A confusing network of paths designed to be hard to get through.","s":"We got happily lost in the corn maze at the fall fair.","p":"MAYZ","o":"Old English","y":2,"bp":64,"ps":"noun","r":"From Middle English masen, 'to confuse,' related to 'amaze.'","h":"A maze makes you amazed and confused — twisty paths everywhere.","nt":"vocab-NWFinal-2026-Junior"},{"w":"meager","d":"is deficient in quantity or quality","s":"The pioneers survived the harsh winter on a meager supply of dried beans and salted meat, rationing every portion carefully and hoping the spring thaw would arrive before their reserves completely ran out.","p":"m-EE-g-ur","o":"Anglo-Norman","y":3,"bp":46,"m":"meagre","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Old French maigre = thin, lean","h":"MEAGER portions leave you EAGER for more—ME+EAGER, you're so eager because there's so little."},{"w":"media","d":"Ways of sharing news and information, like TV, radio, newspapers, and the internet.","s":"The local media covered our school's science fair on the evening news.","p":"MEE-dee-uh","o":"Latin","y":2,"bp":66,"ps":"noun","r":"Latin plural of medium, 'middle, means,' a go-between for messages.","h":"Media stand in the middle, carrying news from events to you.","nt":"vocab-NWFinal-2026-Junior"},{"w":"medial","d":"In or toward the middle.","s":"The medial letter in 'cat' is the a.","p":"MEE-dee-ul","o":"Latin","y":4,"bp":62,"ps":"adjective","r":"From Latin medius, 'middle,' the root of 'medium' and 'median.'","h":"Medial = middle — think of the median strip in a road.","nt":"vocab-NWFinal-2026-Junior"},{"w":"megadose","d":"A very large amount of something, especially a vitamin or medicine.","s":"The doctor warned that a megadose of vitamins can be harmful.","p":"MEH-guh-dohs","o":"Greek","y":3,"bp":60,"ps":"noun","r":"Greek megas, 'great,' plus dosis, 'a giving, portion.'","h":"Mega (huge) + dose = a giant-sized dose.","nt":"vocab-NWFinal-2026-Junior"},{"w":"mentality","d":"a habitual or characteristic mental attitude that determines how you will interpret and respond to situations","p":"meh-NTA-luh-tee","o":"Latin","y":3,"bp":34,"m":"mentallity","sy":"meh.ntae.lah.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin mens/mentis = mind","h":"MenTALity — one L, like one mind guiding your mental attitude."},{"w":"mere","d":"Nothing more than; only what is stated and no more.","s":"He finished the puzzle in a mere five minutes.","p":"MEER","o":"Latin","y":3,"bp":68,"ps":"adjective","r":"From Latin merus, 'pure, unmixed.'","h":"Mere shrinks things down — 'a mere child' means only a child.","nt":"vocab-NWFinal-2026-Junior"},{"w":"meritorious","d":"deserving reward or praise","s":"A lifetime of meritorious service.","p":"meh-ruh-TAW-ree-uhs","o":"Latin","y":3,"bp":37,"m":"meritourious","sy":"meh.rah.tao.riy.ah.s","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin meritorius = bringing in money, deserving","h":"MERITORIOUS ends in -ORIOUS like glorious — a glorious deed is meritorious, both end the same way."},{"w":"mesmerize","d":"is to hypnotize","p":"m-EH-z-m-ur-ay-z","o":"French","y":5,"bp":51,"m":"mesmorize","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Franz Mesmer = Austrian hypnotist","h":"To MESMERIZE, channel Mesmer: M-E-S-M-E-R, then -IZE — his name will hypnotize you into spelling it right."},{"w":"methodical","d":"characterized by method and orderliness","p":"muh-THAH-duh-kuhl","o":"Greek","y":3,"bp":35,"m":"methodicle","sy":"mah.thaa.dah.kah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Greek meta = after + hodos = way","h":"A methodICAL person follows the method logICAL — both end in ICAL, both mean structured thinking.","t":["character"]},{"w":"metric","d":"Relating to the measuring system based on meters, liters, and grams.","s":"In science class we record lengths in metric units like centimeters.","p":"MEH-trik","o":"Greek","y":2,"bp":64,"ps":"adjective","r":"From Greek metron, 'measure,' the root of 'meter.'","h":"Metric means measured by meters — the tens-based measuring system.","nt":"vocab-NWFinal-2026-Junior"},{"w":"microbes","d":"Living things too tiny to see without a microscope, like bacteria.","s":"Washing your hands removes microbes that could make you sick.","p":"MY-krohbz","o":"Greek","y":3,"bp":70,"ps":"noun","r":"Greek mikros, 'small,' plus bios, 'life' — tiny life.","h":"Micro (tiny) + bios (life) = invisible tiny living things.","nt":"vocab-NWFinal-2026-Junior"},{"w":"microphone","d":"device for converting sound waves into electrical energy","s":"The nervous singer tapped the microphone to check if the audience could hear her.","p":"MEYE-kruh-fohn","o":"Greek","y":3,"bp":75,"m":"micraphone","sy":"may.krah.fow.n","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek mikros=small + phone=voice/sound","h":"A MICROPHONE amplifies small PHONE (sound)—micro+phone, just like telephone and saxophone.","t":["physics","waterways","tools"]},{"w":"migrant","d":"A person or animal that moves from one place to another to live or work.","s":"Migrant geese stop at our pond every autumn on their way south.","p":"MY-grunt","o":"Latin","y":3,"bp":72,"ps":"noun","r":"From Latin migrare, 'to move from place to place.'","h":"A migrant migrates — always moving to a new place to live.","nt":"vocab-NWFinal-2026-Junior"},{"w":"migratory","d":"used of animals that move seasonally","s":"Each autumn, migratory birds gather by the thousands along the river corridor, resting and feeding before continuing their long journey to warmer southern climates.","p":"MEYE-gruh-taw-ree","o":"Latin","y":3,"bp":34,"m":"migratary","sy":"may.grah.tao.riy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin migrare = to move, depart","h":"MigratORY birds use their ORY — their territory — as a highway.","t":["animals","time"]},{"w":"mileage","d":"The number of miles traveled, or miles a vehicle goes per gallon of fuel.","s":"Mom checked the car's mileage before our long road trip.","p":"MY-lij","o":"English","y":3,"bp":62,"ps":"noun","r":"From 'mile,' Latin milia passuum, 'a thousand paces,' plus -age.","h":"Mileage counts the miles — how far something has gone.","nt":"vocab-NWFinal-2026-Junior"},{"w":"mock","d":"To make fun of someone in a mean way, often by imitating them.","s":"It's unkind to mock a classmate who answers a question wrong.","p":"MAHK","o":"French","y":2,"bp":70,"ps":"verb","r":"From Old French mocquer, 'to jeer or ridicule.'","h":"To mock is to copy and tease — mean-spirited mimicking.","nt":"vocab-NWFinal-2026-Junior"},{"w":"mockery","d":"Mean teasing or ridicule that makes someone or something look foolish.","s":"The new student ignored the mockery and kept practicing his lines.","p":"MAH-kuh-ree","o":"French","y":3,"bp":68,"ps":"noun","r":"From Old French mocquer, 'to ridicule,' plus -ery.","h":"Mockery is mocking in action — jeering that makes fun of someone.","nt":"vocab-NWFinal-2026-Junior"},{"w":"mode","d":"a particular way or manner in which something is done or happens","s":"Please switch your phone to silent mode during class.","p":"MOHD","o":"French","y":3,"bp":67,"m":"moad","sy":"mow.d","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin modus = measure, manner","h":"A mode is a METHOD—both start with MO and describe a way of doing things."},{"w":"modem","d":"A device that connects a computer to the internet over phone or cable lines.","s":"When the modem blinked red, our house lost its internet.","p":"MOH-dem","o":"English","y":3,"bp":60,"ps":"noun","r":"A blend of 'modulator' and 'demodulator,' coined in twentieth-century English.","h":"The box that gets your computer talking to the internet.","nt":"vocab-NWFinal-2026-Junior"},{"w":"monologue","d":"speech you make to yourself","s":"The actor delivered a powerful monologue that left the entire audience holding its breath.","p":"MAH-nuh-lawg","o":"Greek","y":3,"bp":33,"m":"monolog","sy":"maa.nah.lao.g","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek monos=single + logos=word/speech","h":"A MONOlogue is ONE person's LOGUE (speech) — one mouth, lots of words, add the UE."},{"w":"monosyllable","d":"A word of only one syllable, such as 'yes' or 'dog.'","s":"Too sleepy to chat, Ben answered every question with a monosyllable.","p":"MAH-nuh-sih-luh-bul","o":"Greek","y":3,"bp":68,"ps":"noun","r":"Greek monos, 'single,' plus syllabe, 'syllable.'","h":"Mono means one — a one-syllable word like 'cat.'","nt":"vocab-NWFinal-2026-Junior"},{"w":"monotonous","d":"tediously repetitious or lacking in variety","p":"muh-NAH-tuh-nuhs","o":"Greek","y":3,"bp":35,"m":"monotonious","sy":"mah.naa.tah.nah.s","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Greek monos=single + tonos=tone","h":"Full of ONE TONE — monoTONous has no 'i' after ton; it's too bored to add extra letters."},{"w":"monsoon","d":"a seasonal wind in southern Asia; blows from the southwest (bringing rain) in summer and from the northeast in winter","s":"The monsoon arrived in July, flooding the streets and filling the dry riverbeds overnight.","p":"mah-NSOON","o":"Arabic","y":3,"bp":67,"m":"monsoon","sy":"maa.nsuw.n","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Arabic mawsim = season","h":"MON-SOON: the monsoon arrives SO-ON every season, soaking everything.","t":["weather","time"]},{"w":"monstrosity","d":"a person or animal that is markedly unusual or deformed","s":"The ancient legend described a monstrosity lurking in the deep lake, its shadowy form unlike anything ever seen.","p":"mah-NSTRAH-suh-tee","o":"Latin","y":1,"bp":44,"m":"monstrocity","sy":"mon.stros.i.ty","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin monstrum = omen, monster","h":"A MONSTER creates a monstrOSITY — keep the 's', not a 'c'","t":["animals"]},{"w":"monumental","d":"relating or belonging to or serving as a monument","s":"Winning the regional science fair was a monumental achievement for the small rural school that had never competed before.","p":"mah-nyuh-MEH-ntuhl","o":"Latin","y":1,"bp":43,"m":"monumentel","sy":"mon.u.men.tal","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin monumentum = monument, reminder","h":"Think of a MONUMENT — something MONUMENTAL is as big and important as one"},{"w":"moonbeam","d":"A ray of light from the moon.","s":"A silver moonbeam slipped through the tent flap while we camped.","p":"MOON-beem","o":"English","y":2,"bp":60,"ps":"noun","r":"English compound of 'moon' and 'beam,' both from Old English.","h":"A sunbeam's nighttime cousin — one ray of moonlight.","nt":"vocab-NWFinal-2026-Junior"},{"w":"morality","d":"Beliefs about what is right and wrong behavior.","s":"The fable teaches morality by rewarding honesty and punishing greed.","p":"muh-RAL-ih-tee","o":"Latin","y":3,"bp":70,"ps":"noun","r":"From Latin moralis, 'relating to customs and character.'","h":"Morality is your moral compass — knowing right from wrong.","nt":"vocab-NWFinal-2026-Junior"},{"w":"moralize","d":"interpret the moral meaning of","s":"The old professor would often stop his lecture to moralize about honesty and hard work, urging his students to think carefully about the ethical choices they made each day.","p":"MAW-ruh-leyez","o":"Latin","y":3,"bp":32,"m":"moralise","sy":"mao.rah.lay.z","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin moralis = manner + -ize = to make","h":"Americans moralIZE with a Z — like a ZEALOUS preacher pointing a finger.","t":["logic"]},{"w":"muddle","d":"To mix things up in a confused mess; also a confused state.","s":"I muddled the directions and ended up at the wrong classroom.","p":"MUH-dul","o":"Dutch","y":3,"bp":66,"ps":"verb","r":"Probably from Middle Dutch moddelen, 'to make muddy.'","h":"Muddle sounds like mud — thoughts stirred into a muddy mess.","nt":"vocab-NWFinal-2026-Junior"},{"w":"multiplicity","d":"the property of being multiple","s":"The museum displayed a multiplicity of artifacts from ancient civilizations, filling every hall with history.","p":"muh-ltuh-PLIH-sih-tee","o":"Latin","y":3,"bp":38,"m":"multiplicty","sy":"mah.ltah.plih.sih.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin multiplicitas = manifoldness, from multiplex = many-fold","h":"MULTIPLICITY ends in -CITY — a city with a MULTIPLICITY of people has I-T-Y at the end, just like the word CITY."},{"w":"mundane","d":"found in the ordinary course of events; - Anita Diamant","p":"muh-NDAYN","o":"Latin","y":2,"bp":42,"m":"mundain","sy":"mah.ndey.n","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin mundus = world","h":"MUNDANE ends in DANE — even a Viking from Denmark finds the ordinary world boring."},{"w":"mutable","d":"Able to change or be changed.","s":"Spring weather is mutable, sunny one hour and stormy the next.","p":"MYOO-tuh-bul","o":"Latin","y":4,"bp":72,"ps":"adjective","r":"From Latin mutare, 'to change,' the root of 'mutation.'","h":"Mutable things can mutate — they are changeable.","nt":"vocab-NWFinal-2026-Junior"},{"w":"mutant","d":"Relating to or produced by a change, or mutation, in genes.","s":"The scientist studied a mutant plant whose leaves grew purple instead of green.","p":"MYOO-tunt","o":"Latin","y":3,"bp":70,"ps":"adjective","r":"From Latin mutare, 'to change' — a mutant organism has changed genes.","h":"Mutant means changed by mutation — genes that took a new turn.","nt":"vocab-NWFinal-2026-Junior","vh":"relating to"},{"w":"muted","d":"Made quieter or softer; toned down in sound or color.","s":"The library's muted voices made it easy to concentrate.","p":"MYOO-tid","o":"Latin","y":3,"bp":64,"ps":"adjective","r":"From Latin mutus, 'silent,' the root of 'mute.'","h":"Like pressing the mute button — sound or color turned way down.","nt":"vocab-NWFinal-2026-Junior"},{"w":"mutual","d":"Shared or felt equally by two or more people.","s":"The two rivals developed a mutual respect after the chess final.","p":"MYOO-choo-ul","o":"Latin","y":3,"bp":72,"ps":"adjective","r":"From Latin mutuus, 'borrowed, exchanged between.'","h":"Mutual means both ways — each side gives and gets the same feeling.","nt":"vocab-NWFinal-2026-Junior"},{"w":"mystification","d":"The state of being completely puzzled or confused.","s":"The magician's vanishing act left the audience in total mystification.","p":"mis-tih-fih-KAY-shun","o":"French","y":4,"bp":62,"ps":"noun","r":"From French mystifier, built on Greek mystes, 'one initiated into mysteries.'","h":"A mystery in your mind — the fog of total puzzlement.","nt":"vocab-NWFinal-2026-Junior"},{"w":"mythical","d":"based on or told of in traditional stories; lacking factual basis or historical validity","s":"The griffin is a mythical creature from ancient legends, said to have the powerful body of a lion combined with the wings and sharp talons of a mighty eagle.","p":"MIH-thuh-kuhl","o":"Greek","y":3,"bp":32,"m":"mythicle","sy":"mih.thah.kah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Greek mythos = story, legend","h":"MYTHICAL = MYTH + IC + AL; three clean blocks — the unicorn is mythIC-AL, not mythICLE.","t":["poetry","festivals"]},{"w":"nameless","d":"Having no name, or with a name kept unknown.","s":"A nameless donor paid for the new playground equipment.","p":"NAYM-les","o":"Old English","y":2,"bp":58,"ps":"adjective","r":"Old English nama, 'name,' plus -leas, 'without.'","h":"-Less means without — nameless means without a name.","nt":"vocab-NWFinal-2026-Junior"},{"w":"narrative","d":"a message that tells the particulars of an act or occurrence or course of events; presented in writing or drama or cinema or as a radio or television program","s":"His narrative was interesting.","p":"NA-ruh-tihv","o":"Latin","y":3,"bp":33,"m":"narative","sy":"nae.rah.tih.v","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin narrativus = of narrating","h":"A naRRative needs double R — two rails for the story train to run on.","t":["stage"]},{"w":"nationality","d":"people having common origins or traditions and often comprising a nation","s":"Immigrants of the same nationality often seek each other out.","p":"na-shuh-NA-luh-tee","o":"French","y":3,"bp":37,"m":"nationallity","sy":"nae.shah.nae.lah.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin natio = birth, people","h":"Your nationalITY is your national IDENTITY — one 'l,' and end with i-t-y.","t":["nations","festivals"]},{"w":"nausea","d":"is sickness at the stomach especially when loathing food","s":"The rough waves on the ocean caused a wave of nausea to wash over the young sailor.","p":"n-AW-z-ee-uh","o":"English","y":3,"bp":46,"m":"nauseau","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek nausia from naus = ship (seasickness)","h":"NAUSEA ends in -EA like the SEA — sailors get sick on the sea.","t":["body"]},{"w":"nautical","d":"relating to or involving ships or shipping or navigation or seamen","s":"The old captain's bedroom was filled with nautical maps, brass compasses, and faded photographs of ships he had sailed across every major ocean during his long career at sea.","p":"NAW-tuh-kuhl","o":"Latin","y":2,"bp":44,"m":"nautacal","sy":"nao.tah.kah.l","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Greek nautikos from nautes = sailor from naus = ship","h":"NAUTICAL has NAUTI- like NAUGHTY sailors who sail the sea — end it with -ICAL.","t":["maps","seafaring"]},{"w":"naval","d":"Relating to a navy or its warships.","s":"We toured a naval base and climbed aboard a destroyer.","p":"NAY-vul","o":"Latin","y":3,"bp":72,"ps":"adjective","r":"From Latin navis, 'ship,' the root of 'navy' and 'navigate.'","h":"Naval with an a is about the navy — ships and sailors.","nt":"vocab-NWFinal-2026-Junior"},{"w":"navel","d":"The small hollow in the middle of your belly; the belly button.","s":"The baby giggled when the doctor gently checked her navel.","p":"NAY-vul","o":"Old English","y":3,"bp":72,"ps":"noun","r":"From Old English nafela, 'belly button.'","h":"Navel with an e is on your belly — your belly button.","nt":"vocab-NWFinal-2026-Junior"},{"w":"navigate","d":"travel on water propelled by wind or by other means","p":"NA-vuh-gayt","o":"Latin","y":3,"bp":32,"m":"navigat","sy":"nae.vah.gey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin navigare = to sail (navis=ship + agere=to drive)","h":"A NAVY ship needs to NAViGATE the waves — NAV is right at the front!","t":["weather"]},{"w":"needlework","d":"Sewing, embroidery, or other work done with a needle and thread.","s":"Grandma's needlework turned plain napkins into flowered treasures.","p":"NEE-dul-wurk","o":"English","y":2,"bp":60,"ps":"noun","r":"English compound of 'needle' and 'work,' both from Old English roots.","h":"Work done with a needle — stitching, sewing, embroidery.","nt":"vocab-NWFinal-2026-Junior"},{"w":"neglectful","d":"not showing due care or attention","p":"nih-GLEH-ktfuhl","o":"Latin","y":3,"bp":34,"m":"neglectfull","sy":"nih.gleh.ktfah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin neglegere = to disregard","h":"A neglectful person is FULL of not-caring — one 'l' at the end, like careful."},{"w":"negligence","d":"failure to act with the prudence that a reasonable person would exercise under the same circumstances","s":"The company was sued for negligence after failing to repair the broken staircase that injured a customer.","p":"NEH-gluh-juhns","o":"Latin","y":3,"bp":34,"m":"negligance","sy":"neh.glah.jhah.ns","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin neglegere = to disregard","h":"NEGLIGENCE ends in '-ence' not '-ance' — remember 'negligENt' becomes negligENce."},{"w":"nerd","d":"A person deeply interested in studies or a subject, sometimes seen as unstylish.","s":"Proud to be a space nerd, Leo knows every planet's moons.","p":"NURD","o":"English","y":2,"bp":58,"ps":"noun","r":"American English coinage; a creature called a nerd appears in a 1950 Dr. Seuss book.","h":"A brainy super-fan of books, science, or any favorite subject.","nt":"vocab-NWFinal-2026-Junior"},{"w":"networking","d":"Meeting and talking with people to share help, ideas, or job contacts.","s":"At the science fair, Dad did some networking with other coaches.","p":"NET-wur-king","o":"English","y":3,"bp":60,"ps":"noun","r":"From 'network,' originally a net-like fabric of crossing lines.","h":"Building a net of people who know and help each other.","nt":"vocab-NWFinal-2026-Junior"},{"w":"neurologist","d":"a medical specialist in the nervous system and the disorders affecting it","s":"The neurologist examined the patient's reflexes to check for nerve damage.","p":"nuu-RAH-luh-juhst","o":"Greek","y":3,"bp":36,"m":"nuerologist","sy":"nuh.raa.lah.jhah.st","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek neuron = nerve + logos = study","h":"A NEUROLOGISt studies nerves with the loGISt-ics of the brain.","t":["body","disease"]},{"w":"neuter","d":"Neither masculine nor feminine, as in grammar or gender.","s":"In German class we learned that some nouns are neuter.","p":"NOO-ter","o":"Latin","y":4,"bp":64,"ps":"adjective","r":"Latin ne, 'not,' plus uter, 'either' — neither of the two.","h":"Neuter means neither — not the masculine side, not the feminine.","nt":"vocab-NWFinal-2026-Junior"},{"w":"neutralize","d":"make politically neutral and thus inoffensive","s":"The treaty neutralized the small republic.","p":"NOO-truh-leyez","o":"French","y":3,"bp":34,"m":"neutralise","sy":"nuw.trah.lay.z","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin neutralis = neither side","h":"To make something NEUTRAL, you neutralIZE it — the IZE means 'make it so.'","t":["politics"]},{"w":"newtonian","d":"Relating to Isaac Newton or his laws of motion and gravity.","s":"Our teacher used a rolling cart to show Newtonian laws of motion.","p":"noo-TOH-nee-un","o":"English","y":4,"bp":62,"ps":"adjective","r":"From the name of English scientist Sir Isaac Newton plus -ian.","h":"Anything Newtonian follows Newton — gravity, motion, falling apples.","nt":"vocab-NWFinal-2026-Junior"},{"w":"nuisance","d":"(law) a broad legal concept including anything that disturbs the reasonable use of your property or endangers life and health or is offensive","p":"n-OO-s-uh-n-s","o":"Anglo-Norman","y":4,"bp":63,"m":"nuisanse","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin nocere = to harm","h":"A NUISance is no USE to anyone.","t":["law"]},{"w":"numeration","d":"The act or system of counting or numbering.","s":"Our math unit on numeration taught us to read huge numbers.","p":"noo-muh-RAY-shun","o":"Latin","y":4,"bp":62,"ps":"noun","r":"From Latin numerare, 'to count,' from numerus, 'number.'","h":"Numeration is all about numbers — counting and naming them.","nt":"vocab-NWFinal-2026-Junior"},{"w":"nunnery","d":"A building where nuns live; a convent.","s":"The quiet nunnery on the hill rang its bells each morning.","p":"NUH-nuh-ree","o":"Latin","y":3,"bp":64,"ps":"noun","r":"From Late Latin nonna, 'nun,' plus the place suffix -ery.","h":"Like a bakery is for baking, a nunnery is where nuns live.","nt":"vocab-NWFinal-2026-Junior"},{"w":"nuptial","d":"is of or pertaining to marriage or the ceremony","s":"The couple exchanged their nuptial vows beneath a canopy of white flowers, with family and friends gathered around them to celebrate the beginning of their shared life together.","p":"n-UH-p-ch-uh-l","o":"Latin","y":4,"bp":66,"m":"nuptual","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin nuptiae = marriage, from nubere = to wed/veil","h":"NUPTIAL contains NUPTi-AL — remember the I before AL, because 'I do' comes before the altar.","t":["religion","kinship"],"vh":"Of or pertaining to"},{"w":"nurture","d":"to care for and encourage the growth or development of someone or something","s":"They debated whether nature or nurture was more important.","p":"n-UR-ch-ur","o":"English","y":3,"bp":47,"m":"nurcher","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin nutrire = to feed, nourish","h":"NURTure sounds like NURSE — both involve caring and feeding.","t":["kinship"]},{"w":"nutriment","d":"a source of materials to nourish the body","s":"The growing seedlings drew nutriment from the rich, dark soil of the garden bed.","p":"NOO-trih-ment","o":"Latin","y":3,"bp":33,"m":"nutriament","sy":"nu.tri.ment","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin nutrimentum = nourishment, from nutrire = to nourish","h":"NUTRIment is the NUTRI-ment of life — like 'nutrition' but ending in '-ment' like 'supplement'."},{"w":"oaken","d":"Made of oak wood.","s":"The library's heavy oaken doors creaked as we pushed them open.","p":"OH-kin","o":"Old English","y":3,"bp":62,"ps":"adjective","r":"Old English ac, 'oak tree,' plus the material suffix -en, as in 'wooden.'","h":"Like golden means made of gold, oaken means made of oak.","nt":"vocab-NWFinal-2026-Junior"},{"w":"oasis","d":"a fertile tract in a desert (where the water table approaches the surface)","s":"The weary travelers were overjoyed when they spotted a lush oasis shimmering in the distance.","p":"oh-AY-sihs","o":"Greek","y":1,"bp":38,"m":"oassis","sy":"ow.ey.sih.s","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek oasis = fertile spot, from Egyptian wḥꜣt = oasis","h":"An OASIS has only ONE 's' in the middle — like a lone palm tree in the desert, not two.","t":["landforms","household"]},{"w":"objective","d":"the goal intended to be attained (and which is believed to be attainable)","p":"uh-BJEH-ktihv","o":"Latin","y":3,"bp":33,"m":"objectve","sy":"ah.bjheh.ktih.v","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin ob- = against/toward + jacere = to throw","h":"Your obJECTive is what you THROW yourself TOWARD — the goal you aim at.","t":["sports"]},{"w":"obsession","d":"an irrational motive for performing trivial or repetitive actions, even against your will","p":"uh-BSEH-shuhn","o":"Latin","y":3,"bp":33,"m":"obsesion","sy":"ah.bseh.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin obsessio = a siege, blockade","h":"An obSESSion has double S — the idea besieges your brain and refuses to leave, just like that extra S."},{"w":"occurrence","d":"an event that happens","s":"A disease of frequent occurrence.","p":"uh-KUR-uhns","o":"Latin","y":3,"bp":34,"m":"occurence","sy":"ah.ker.ah.ns","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin occurrere = to run to meet","h":"An OCCURRence has double 'c' AND double 'r' — four consonants for one big event."},{"w":"ointment","d":"A smooth, greasy cream rubbed on skin to heal or soothe.","s":"The nurse dabbed ointment on my scraped knee.","p":"OYNT-ment","o":"French","y":2,"bp":66,"ps":"noun","r":"From Old French oignement, from Latin unguentum, 'salve.'","h":"A healing cream you smear on cuts, burns, and rashes.","nt":"vocab-NWFinal-2026-Junior"},{"w":"opportunistic","d":"taking immediate advantage, often unethically, of any circumstance of possible benefit","s":"The opportunistic vendor raised his prices the moment the storm knocked out power across the neighborhood.","p":"ah-per-too-NIH-stihk","o":"Latin","y":3,"bp":39,"m":"oportunistic","sy":"aa.per.tuw.nih.stih.k","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin opportunus = favorable","h":"OPPORTUNISTIC has double P — the sneaky person grabs twice before anyone notices."},{"w":"optimal","d":"Best or most favorable possible.","s":"Morning is the optimal time for Nina to memorize her word list.","p":"AHP-tih-mul","o":"Latin","y":3,"bp":72,"ps":"adjective","r":"From Latin optimus, 'best,' also the root of 'optimist.'","h":"Optimal = the optimum — the very best choice or condition.","nt":"vocab-NWFinal-2026-Junior"},{"w":"oration","d":"A formal speech given on a special occasion.","s":"The class president delivered a stirring oration at graduation.","p":"aw-RAY-shun","o":"Latin","y":3,"bp":72,"ps":"noun","r":"From Latin orare, 'to speak, plead,' the root of 'orator.'","h":"An orator gives an oration — a big formal speech.","nt":"vocab-NWFinal-2026-Junior"},{"w":"ordain","d":"To officially order or decree; also to make someone a priest or minister.","s":"The king ordained that the festival be held every spring.","p":"or-DAYN","o":"French","y":4,"bp":68,"ps":"verb","r":"From Old French ordener, from Latin ordinare, 'to put in order.'","h":"To ordain is to order it officially — set by high authority.","nt":"vocab-NWFinal-2026-Junior"},{"w":"orientation","d":"the act of orienting","p":"aw-ree-eh-NTAY-shuhn","o":"French","y":3,"bp":37,"m":"orientaion","sy":"ao.riy.eh.ntey.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin oriens = rising sun, east","h":"Your ORIENTATION points you ORIENT-ATION, like a nation facing the rising sun."},{"w":"out-and-out","d":"Complete and total; absolute.","s":"Claiming he never eats candy was an out-and-out fib.","p":"owt-und-OWT","o":"English","y":3,"bp":60,"ps":"adjective","r":"English phrase from 'out,' doubled for emphasis — thoroughly, completely.","h":"Through and through — an out-and-out lie is completely a lie.","nt":"vocab-NWFinal-2026-Junior"},{"w":"outcry","d":"A loud protest or strong public complaint.","s":"Cutting recess caused an outcry from every grade.","p":"OWT-kry","o":"English","y":3,"bp":68,"ps":"noun","r":"English compound: 'out' plus 'cry' — a crying out.","h":"People crying out together — a burst of loud protest.","nt":"vocab-NWFinal-2026-Junior"},{"w":"outlive","d":"To live longer than someone or something else.","s":"The old oak has outlived every house on our street.","p":"owt-LIV","o":"English","y":2,"bp":62,"ps":"verb","r":"English compound: 'out-' meaning beyond, plus 'live.'","h":"To out-live is to live past — lasting longer than others.","nt":"vocab-NWFinal-2026-Junior"},{"w":"outrageous","d":"grossly offensive to decency or morality; causing horror","s":"The outrageous price of twelve dollars for a single apple at the airport café made every traveler do a double take.","p":"ow-TRAY-juhs","o":"Anglo-Norman","y":1,"bp":38,"m":"outragous","sy":"out.ra.geous","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Old French outrage = excess, from outre = beyond","h":"OUT + RAGE + OUS: outrageous makes you want to RAGE — keep the 'e' in rage","t":["logic"]},{"w":"outright","d":"Complete and total; also done openly, at once, or without holding back.","s":"She won the game outright, with no tiebreaker needed.","p":"OWT-ryt","o":"English","y":3,"bp":64,"ps":"adjective","r":"Middle English 'out' plus 'right,' meaning straight out.","h":"Right out in the open and complete — an outright win is total.","nt":"vocab-NWFinal-2026-Junior"},{"w":"overdose","d":"Too large an amount of a medicine or drug, enough to be dangerous.","s":"The label warns that taking extra pills can cause an overdose.","p":"OH-ver-dohs","o":"English","y":3,"bp":62,"ps":"noun","r":"English 'over-' plus 'dose,' from Greek dosis, 'a giving.'","h":"Over the safe dose — a dangerously large amount of medicine.","nt":"vocab-NWFinal-2026-Junior"},{"w":"overseer","d":"A person who watches over and directs workers or a task.","s":"As overseer of the food drive, Maya assigned each class a job.","p":"OH-ver-see-er","o":"English","y":3,"bp":66,"ps":"noun","r":"English 'over' plus 'seer,' one who sees — a supervisor.","h":"One who sees over the work — the boss keeping watch.","nt":"vocab-NWFinal-2026-Junior"},{"w":"overthrow","d":"To remove a ruler or government from power, often by force.","s":"In the play, the villagers overthrow the cruel duke.","p":"oh-ver-THROH","o":"English","y":3,"bp":70,"ps":"verb","r":"English 'over' plus 'throw' — to throw down from power.","h":"Picture throwing a king over — toppling whoever rules.","nt":"vocab-NWFinal-2026-Junior"},{"w":"pact","d":"an agreement covenant or compact","s":"The two friends made a pact to always support each other no matter what happened.","p":"p-A-k-t","o":"Latin","y":3,"bp":47,"m":"pact","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin pactum = agreement, from pacisci = to agree","h":"A PACT is a promise — it's short and tight, just four letters P-A-C-T, like a firm handshake."},{"w":"paddy","d":"A flooded field where rice is grown; also rice still in its husk.","s":"From the train we saw workers planting seedlings in a rice paddy.","p":"PA-dee","o":"English","y":3,"bp":70,"ps":"noun","r":"Borrowed into English from Malay padi, 'rice in the husk.'","h":"A paddy is a watery rice field — rice loves wet feet.","nt":"vocab-NWFinal-2026-Junior"},{"w":"palatable","d":"acceptable to the taste or mind","s":"The chef added extra spices to make the bitter medicine more palatable for the children who refused to swallow it plain.","p":"PA-luh-tuh-buhl","o":"Latin","y":3,"bp":34,"m":"pallatable","sy":"pal.at.a.ble","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin palatum = palate (roof of the mouth)","h":"PALATAble — if it suits your PALATE, it's palatable"},{"w":"pamper","d":"treat with excessive indulgence","s":"Grandparents often pamper the children.","p":"PA-mper","o":"Dutch","y":1,"bp":33,"m":"pampur","sy":"pae.mper","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"verb","r":"Low German or Dutch pamperen = to cram with food, indulge","h":"To PAMPER someone, wrap them like a PAMPER diaper — soft, cushioned, and ended with E-R: P-A-M-P-E-R."},{"w":"pamphlet","d":"a short essay generally controversial on some subject","s":"The student council distributed a colorful pamphlet explaining the new recycling program to every homeroom class.","p":"p-A-m-f-l-uh-t","o":"Latin","y":4,"bp":67,"m":"pamflet","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"noun","r":"Medieval Latin Pamphilus = title of a popular 12th-century Latin poem, shortened to pamphlet","h":"A PAMphlet fits in the PALM of your hand","t":["poetry"]},{"w":"pamphleteer","d":"a writer of pamphlets (usually taking a partisan stand on public issues)","s":"The fiery pamphleteer printed hundreds of leaflets urging citizens to stand up against the unfair tax.","p":"pa-mfluh-TIHR","o":"French","y":3,"bp":34,"m":"pamphletteer","sy":"pae.mflah.tih.r","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Medieval Latin 'Pamphilus' (a popular 12th-c. love poem) + French '-eer' = one who does","h":"A PAMPHLETEER writes pamphlets with zeal — end it with -EER like a pioneer with a pen!","t":["poetry"]},{"w":"panel","d":"A flat board section; also a small group chosen to judge or discuss.","s":"A panel of three teachers judged the debate finals.","p":"PA-nul","o":"French","y":2,"bp":62,"ps":"noun","r":"From Old French panel, 'piece of cloth,' from Latin pannus, 'cloth.'","h":"A flat piece or a flat group — boards on walls, judges at tables.","nt":"vocab-NWFinal-2026-Junior"},{"w":"paradox","d":"(logic) a statement that contradicts itself","s":"`I always lie' is a paradox because if it is true it must be false.","p":"PEH-ruh-dahks","o":"French","y":3,"bp":72,"m":"paradocks","sy":"peh.rah.daa.ks","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek paradoxos = contrary to expectation","h":"A PARADOX defies your DOXa (belief) — spell it para-DOX, with an X that crosses out your expectations.","t":["logic"]},{"w":"parameter","d":"a constant in the equation of a curve that can be varied to yield a family of similar curves","s":"The teacher set one clear parameter for the project: all posters must fit on a single sheet of paper.","p":"per-A-muh-ter","o":"French","y":3,"bp":34,"m":"perameter","sy":"per.ae.mah.ter","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek para=beside + metron=measure","h":"A parameter measures alongside — it's para+meter, like a parking meter beside the road.","t":["kinship","numbers"]},{"w":"parasite","d":"an organism that lives in or on a host organism and gets its food at the host's expense without killing it","s":"The biology teacher showed a diagram of a tapeworm as an example of a parasite that can live inside the digestive system of mammals.","p":"PEH-ruh-seyet","o":"Latin","y":1,"bp":40,"m":"parasight","sy":"par.a.site","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek para (beside) + sitos (food, grain) = one who eats beside another","h":"A PARASITE eats at your SITE (dinner table) without paying"},{"w":"parcel","d":"a wrapped container","p":"PAH-rsuhl","o":"French","y":2,"bp":41,"m":"parsel","sy":"paa.rsah.l","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old French parcelle, from Latin particella = small part","h":"A PARCEL is wrapped with CARE and a C — not an S — in the middle: P-A-R-C-E-L."},{"w":"militate","d":"have force or influence; bring about an effect or change","s":"Politeness militated against this opinion being expressed.","p":"MIH-lih-tayt","o":"Latin","y":3,"bp":32,"m":"millitate","sy":"mih.lih.tey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin militare = to serve as a soldier","h":"A soldier's actions MILITATE change — one 'l', like one army.","t":["physics"],"vh":"mind set"},{"w":"miniature","d":"painting or drawing included in a book (especially in illuminated medieval manuscripts)","s":"The artist spent three weeks painting a breathtaking miniature landscape on a piece of ivory no larger than a postage stamp, using a brush with a single hair.","p":"MIH-nee-uh-chuur","o":"Latin","y":3,"bp":34,"m":"miniature","sy":"mih.niy.ah.chuh.r","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin miniatura = painting in red lead, from minium = red lead","h":"MINIATURE has MINI inside it—it's a MINI painting, so spot MINI at the start: M-I-N-I-A-T-U-R-E.","t":["painting","poetry"]},{"w":"minimal","d":"The smallest possible in amount or degree; very little.","s":"The storm caused only minimal damage to the playground.","p":"MIH-nih-mul","o":"Latin","y":3,"bp":66,"ps":"adjective","r":"From Latin minimus, 'smallest,' the root of 'minimum.'","h":"Minimal = at the minimum — as little as it can be.","nt":"vocab-NWFinal-2026-Junior"},{"w":"minimize","d":"make small or insignificant","s":"Let's minimize the risk.","p":"MIH-nuh-meyez","o":"Latin","y":3,"bp":32,"m":"minimise","sy":"mih.nah.may.z","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin minimus = smallest","h":"American spelling uses -IZE: 'Americans use Z with pizzazZ' — minimiZE."},{"w":"minority","d":"a group of people who differ racially or politically from a larger group of which it is a part","s":"The school principal made sure that every minority student in the district had equal access to advanced placement courses.","p":"meye-NAW-ruh-tee","o":"French","y":1,"bp":41,"m":"minoritie","sy":"mi.nor.i.ty","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin minor = smaller, lesser","h":"MINORITY contains MINOR — a minor group or a younger person","t":["politics"]},{"w":"minute","d":"Extremely small; tiny.","s":"The biologist studied minute creatures swimming in a single water drop.","p":"my-NOOT","o":"Latin","y":3,"bp":76,"ps":"adjective","r":"From Latin minutus, 'made small,' from minuere, 'to lessen.'","h":"Say my-NOOT and it means tiny — not the sixty-second minute.","nt":"vocab-NWFinal-2026-Junior"},{"w":"misconception","d":"an incorrect conception","s":"It is a common misconception that we only use ten percent of our brains — scientists say we use virtually all of it.","p":"mih-skuh-NSEH-pshuhn","o":"Latin","y":1,"bp":45,"m":"misconseption","sy":"mis.con.cep.tion","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin concipere = to conceive or take in","h":"MIS(wrong)+CONCEPTION: a wrongly conceived idea"},{"w":"misdeed","d":"A bad or wrong act.","s":"The puppy's latest misdeed was chewing Dad's slipper.","p":"mis-DEED","o":"Old English","y":2,"bp":64,"ps":"noun","r":"Old English misdaed: mis-, 'wrongly,' plus daed, 'deed.'","h":"A deed gone wrong — mis + deed = a bad act.","nt":"vocab-NWFinal-2026-Junior"},{"w":"misinterpret","d":"interpret falsely","s":"The student misinterpret ed the poem's final stanza, thinking it was about love when it was actually about loss.","p":"mih-sih-NTUR-pruht","o":"French","y":1,"bp":90,"m":"misinterperate","sy":"mis.in.ter.pret","nt":"Primary | North South Finals, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin interpretari = to explain, expound","h":"MIS- means wrong, so you interpret it the WRONG way"},{"w":"misrepresent","d":"represent falsely","s":"This statement misrepresents my intentions.","p":"mih-sreh-pruh-ZEHNT","o":"Latin","y":3,"bp":37,"m":"misrepresant","sy":"mih.sreh.prah.zeh.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin repraesentare = to present again","h":"MISREPRESENT hides 'present' inside — giving someone the wrong present is misrepresenting them!"},{"w":"mobile","d":"Able to move or be moved easily.","s":"The mobile library van visits our neighborhood every Tuesday.","p":"MOH-bul","o":"Latin","y":2,"bp":64,"ps":"adjective","r":"From Latin mobilis, 'movable,' from movere, 'to move.'","h":"Mobile things move — like a mobile phone that travels with you.","nt":"vocab-NWFinal-2026-Junior"},{"w":"nibble","d":"To take small, gentle bites of something.","s":"The rabbit nibbled the lettuce leaf at the edge of the garden.","p":"NIH-bul","o":"Dutch","y":2,"bp":62,"ps":"verb","r":"Probably from Low German or Dutch nibbelen, 'to gnaw in little bites.'","h":"Tiny bite after tiny bite — a mouse-sized way of eating.","nt":"vocab-NWFinal-2026-Junior"},{"w":"nimble","d":"Quick and light in movement or thinking.","s":"The nimble gymnast flipped across the beam without a wobble.","p":"NIM-bul","o":"Old English","y":3,"bp":74,"ps":"adjective","r":"From Old English niman, 'to take, grasp' — quick to grasp.","h":"Jack be nimble — quick, light, and agile on your feet.","nt":"vocab-NWFinal-2026-Junior"},{"w":"noisy","d":"Making a lot of noise; loud.","s":"The cafeteria gets noisy the minute the lunch bell rings.","p":"NOY-zee","o":"French","y":2,"bp":56,"ps":"adjective","r":"From 'noise,' Old French noise, 'din, quarrel.'","h":"Full of noise — the opposite of quiet.","nt":"vocab-NWFinal-2026-Junior"},{"w":"nomad","d":"A person who moves from place to place instead of settling in one home.","s":"The desert nomad packed his tent and moved with the seasons.","p":"NOH-mad","o":"Greek","y":3,"bp":76,"ps":"noun","r":"From Greek nomas, 'roaming for pasture,' from nemein, 'to graze.'","h":"A nomad has no fixed address — home is wherever the tent goes.","nt":"vocab-NWFinal-2026-Junior"},{"w":"nomadic","d":"Roaming from place to place rather than living in one spot.","s":"Some herding families still follow a nomadic way of life.","p":"noh-MA-dik","o":"Greek","y":3,"bp":74,"ps":"adjective","r":"From Greek nomas, 'wandering herder,' plus -ic.","h":"Living like a nomad — wandering with all you own.","nt":"vocab-NWFinal-2026-Junior"},{"w":"nomination","d":"the act of officially naming a candidate","s":"The Republican nomination for Governor.","p":"nah-muh-NAY-shuhn","o":"Latin","y":3,"bp":35,"m":"nominasion","sy":"naa.mah.ney.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin nominatio = a naming, from nomen = name","h":"A NOMINATION is the ACT of naming — NOMIN + ATION, like a nation of names gathering together.","t":["politics"]},{"w":"non-existent","d":"Not existing at all; not real.","s":"His excuses for skipping practice were based on a non-existent injury.","p":"nahn-ig-ZIS-tent","o":"Latin","y":3,"bp":60,"ps":"adjective","r":"Latin non, 'not,' plus existere, 'to come into being.'","h":"Non + existent = it simply isn't there.","nt":"vocab-NWFinal-2026-Junior"},{"w":"notable","d":"Worth noticing; important or remarkable.","s":"Scoring a perfect test was a notable achievement for the whole class.","p":"NOH-tuh-bul","o":"Latin","y":3,"bp":68,"ps":"adjective","r":"From Latin notare, 'to mark, note.'","h":"Worth taking note of — something you'd jot down and remember.","nt":"vocab-NWFinal-2026-Junior"},{"w":"noticeable","d":"capable or worthy of being perceived","s":"Noticeable shadows under her eyes.","p":"NOH-tuh-suh-buhl","o":"Latin","y":3,"bp":35,"m":"noticible","sy":"now.tah.sah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin notitia = knowledge + -able = capable of","h":"Keep the E in noticEable — the E wants to be NOTICED and refuses to disappear."},{"w":"notorious","d":"known widely and usually unfavorably","p":"noh-TAW-ree-uhs","o":"Latin","y":3,"bp":34,"m":"notrious","sy":"now.tao.riy.ah.s","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin notus = known","h":"NOTORious criminals are NOTE-worthy for all the WRONG reasons."},{"w":"novelty","d":"The quality of being new and unusual; also a small new toy or trinket.","s":"The novelty of the class pet wore off once cage-cleaning began.","p":"NAH-vul-tee","o":"French","y":3,"bp":72,"ps":"noun","r":"From Old French novelete, from Latin novus, 'new.'","h":"Novel means new — novelty is the shiny newness of a thing.","nt":"vocab-NWFinal-2026-Junior"},{"w":"nowadays","d":"At the present time; in these days.","s":"Nowadays most students turn in homework online.","p":"NOW-uh-dayz","o":"English","y":2,"bp":58,"ps":"adverb","r":"Middle English phrase 'now a dayes,' meaning in these days.","h":"Now-a-days — literally 'in the days of now.'","nt":"vocab-NWFinal-2026-Junior"},{"w":"parentage","d":"the state of being a parent","p":"PEH-ruh-ntuhj","o":"French","y":3,"bp":74,"m":"parentige","sy":"peh.rah.ntah.jh","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin parentem = one who begets","h":"PARENTAGE ends in -AGE like heritage — your parentage is your family heritage.","t":["kinship"]},{"w":"parrot","d":"To repeat someone's words without understanding; also a bright talking bird.","s":"Don't just parrot the definition — explain it in your own words.","p":"PAIR-ut","o":"French","y":2,"bp":66,"ps":"verb","r":"From French perrot, a pet form of the name Pierre.","h":"Parrots copy speech — to parrot is to repeat without thinking.","nt":"vocab-NWFinal-2026-Junior"},{"w":"participate","d":"share in something","s":"The teacher encouraged every student to participate in the science fair, reminding them that sharing their ideas and discoveries was just as important as winning a ribbon or trophy.","p":"pah-RTIH-suh-payt","o":"Latin","y":3,"bp":36,"m":"participaite","sy":"paa.rtih.sah.pey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin participare = to partake, from pars = part + capere = take","h":"To participATE, you take PART and CAPTURE your fate — end with ATE, like you ate your share."},{"w":"pathologist","d":"a doctor who specializes in medical diagnosis","s":"The pathologist examined the tissue sample under a microscope to determine the exact cause of death.","p":"puh-THAH-luh-juhst","o":"Greek","y":3,"bp":36,"m":"pathologyst","sy":"pah.thaa.lah.jhah.st","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek pathos = disease + logos = study","h":"A PATHologIST is the study-IST of disease — end with ‑IST not ‑YST.","t":["body"]},{"w":"pauper","d":"A very poor person with no money.","s":"In the story, a prince trades places with a pauper.","p":"PAW-per","o":"Latin","y":3,"bp":76,"ps":"noun","r":"From Latin pauper, 'poor,' the root of 'poverty.'","h":"Pauper and poor start alike — a pauper has nothing.","nt":"vocab-NWFinal-2026-Junior"},{"w":"pediatrician","d":"a specialist in the care of babies","s":"The pediatrician reassured the nervous parents that their baby's slight fever would pass within a day.","p":"pee-dee-uh-TRIH-shuhn","o":"Latin","y":3,"bp":38,"m":"pediatritian","sy":"piy.diy.ah.trih.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek pais(child)+iatros(healer)","h":"pediatrICIAN ends in -ICIAN like magICIAN — a pediatrician works magic healing children.","vh":"doctor who specializes in"},{"w":"penalty","d":"A punishment for breaking a rule or law.","s":"The soccer team paid the penalty for the foul with a free kick.","p":"PEH-nul-tee","o":"Latin","y":2,"bp":64,"ps":"noun","r":"From Latin poena, 'punishment,' the root of 'pain.'","h":"Break the rule, pay the penalty — the price of a foul.","nt":"vocab-NWFinal-2026-Junior"},{"w":"penance","d":"Something a person does to show sorrow for doing wrong.","s":"As penance for teasing his sister, Rob did her chores all week.","p":"PEH-nuns","o":"French","y":4,"bp":70,"ps":"noun","r":"From Old French penance, from Latin paenitentia, 'repentance.'","h":"Penance shares roots with 'penalty' — making up for a wrong.","nt":"vocab-NWFinal-2026-Junior"},{"w":"pending","d":"awaiting conclusion or confirmation","p":"PEH-ndihng","o":"Latin","y":3,"bp":71,"m":"pendding","sy":"peh.ndih.ng","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin pendere = to hang/be suspended","h":"PENDING means hanging in midair — like a decision dangling, PENDing = still hanging.","t":["logic"]},{"w":"pendulum","d":"an apparatus consisting of an object mounted so that it swings freely under the influence of gravity","s":"The steady tick of the grandfather clock's pendulum filled the quiet hallway with rhythm.","p":"PEH-njuh-luhm","o":"Latin","y":3,"bp":32,"m":"pendulim","sy":"peh.njhah.lah.m","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin pendulum = hanging thing","h":"A pendULUM swings — ULU sounds like it swings back and forth, ending in M like a metronome.","t":["physics","tools"]},{"w":"penetrate","d":"pass into or through, often by overcoming resistance","s":"The bullet penetrated her chest.","p":"PEH-nuh-trayt","o":"Latin","y":3,"bp":33,"m":"penatrate","sy":"peh.nah.trey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin penetrare = to enter deeply, from penitus = deeply within","h":"PENEtrate — the E after PEN is key, like going deeply WITHIN: pen-E-trate, never penat."},{"w":"penetration","d":"an attack that penetrates into enemy territory","s":"The penetration of upper management by women.","p":"peh-nuh-TRAY-shuhn","o":"French","y":3,"bp":36,"m":"penatration","sy":"peh.nah.trey.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin penetratio = act of entering deeply","h":"PENEtration starts with PENE — four letters before the T, like four walls being broken through."},{"w":"pentagon","d":"a government building with five sides that serves as the headquarters of the United States Department of Defense","s":"Officials at the Pentagon held a press conference to address the nation's new defense strategy.","p":"PEH-ntih-gahn","o":"Greek","y":3,"bp":32,"m":"pentegon","sy":"peh.ntih.gaa.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek penta = five + gonia = angle","h":"A PENTAgon has FIVE angles — pen-ta sounds like 'penta' which always means five.","t":["buildings","politics"],"vh":"per diem"},{"w":"perceive","d":"is to become aware of","s":"I could perceive the ship coming over the horizon.","p":"p-ur-s-EE-v","o":"French","y":3,"bp":52,"m":"percieve","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin percipere = to seize, grasp, from per-(thoroughly)+capere(to take)","h":"Remember: I before E except after C — perCEIVE has C-E-I-V-E, not C-I-E."},{"w":"perception","d":"the representation of what is perceived; basic component in the formation of a concept","s":"Luther had a new perception of the Bible.","p":"per-SEH-pshuhn","o":"French","y":3,"bp":34,"m":"percpetion","sy":"per.seh.pshah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin perceptio = a seizing, perceiving","h":"PERCEPTion: keep the full word PERCEPT inside it — your brain seizes a concept."},{"w":"perimeter","d":"the boundary line or the area immediately inside the boundary","s":"To find the perimeter of the rectangle, the student added up the lengths of all four sides.","p":"per-IH-muh-ter","o":"Greek","y":3,"bp":34,"m":"perimitur","sy":"per.ih.mah.ter","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek peri = around + metron = measure","h":"A PERIMETER MEASURES AROUND a shape — PERI + METER, the measure goes all the way around.","t":["maps"]},{"w":"period","d":"A length or portion of time; also the dot ending a sentence.","s":"The Jurassic period was a time when dinosaurs ruled the land.","p":"PEER-ee-ud","o":"Greek","y":2,"bp":60,"ps":"noun","r":"From Greek periodos, 'a going around, cycle.'","h":"A period is a stretch of time — class periods, history periods.","nt":"vocab-NWFinal-2026-Junior"},{"w":"permeable","d":"allowing fluids or gases to pass or diffuse through","s":"Scientists discovered that the rock layer beneath the construction site was highly permeable, meaning groundwater could flow freely through it and potentially cause serious flooding problems in the building's basement.","p":"PUR-mee-uh-buhl","o":"Latin","y":3,"bp":34,"m":"permable","sy":"per.miy.ah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin permeare = to pass through","h":"A PERMEable wall lets water PASS — remember the 'mea' in the middle, like a doorMEAn you can walk through."},{"w":"permissive","d":"not preventive","s":"Direct primary legislation is largely permissive rather than prescriptive.","p":"per-MIH-sihv","o":"Latin","y":3,"bp":34,"m":"permissibe","sy":"per.mih.sih.v","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin permissivus = allowing","h":"A perMISSIVE parent never says no — perMISS+IVE: they'd MISS giving an IV(eto) and let kids do anything."},{"w":"permutation","d":"an event in which one thing is substituted for another","s":"The math club calculated every permutation of the four-digit code before they finally cracked it open.","p":"pur-myoo-TAY-shuhn","o":"French","y":3,"bp":36,"m":"permutation","sy":"per.mu.ta.tion","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin permutare (to change completely); per- (thoroughly) + mutare (to change)","h":"perMUTAtion: it MUTAtes — everything changes place"},{"w":"perpetuate","d":"cause to continue or prevail","s":"Repeating harmful stereotypes in movies and television programs can perpetuate negative attitudes toward certain groups of people, making it harder for society to move toward greater understanding and fairness.","p":"per-PEH-chuh-wayt","o":"Latin","y":3,"bp":35,"m":"perpetuiate","sy":"per.peh.chah.wey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin perpetuare = to make perpetual, from perpetuus = continuous","h":"To perpetuate is to keep going: PER-PET-U-ATE — pet the U and it keeps purring forever."},{"w":"perspiration","d":"salty fluid secreted by sweat glands","p":"pur-sper-AY-shuhn","o":"French","y":3,"bp":37,"m":"persperation","sy":"per.sper.ey.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin perspirare = to breathe through (per=through + spirare=to breathe)","h":"PERSPIR-ATION: your pores breathe (SPIR like spirit/breath) through your skin — SPIR not SPER.","t":["body"]},{"w":"perspire","d":"excrete perspiration through the pores in the skin","p":"per-SPEYER","o":"French","y":3,"bp":71,"m":"perspier","sy":"per.spay.r","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin perspirare = to breathe through","h":"To PERSPIRE, your skin BREATHES — spot SPIRE like a breath of air reaching upward.","t":["body"]},{"w":"persuade","d":"is to prevail on a person to do something","p":"p-ur-s-w-AY-d","o":"Latin","y":4,"bp":67,"m":"persuaid","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin persuadere = to advise thoroughly","h":"PERSUADE ends like SUEDE leather — smooth talk is as smooth as SUEDE."},{"w":"perturb","d":"To upset, worry, or disturb someone greatly.","s":"The strange noise from the basement perturbed the babysitter.","p":"per-TURB","o":"Latin","y":4,"bp":74,"ps":"verb","r":"Latin per-, 'thoroughly,' plus turbare, 'to disturb, stir up.'","h":"Hear 'disturb' inside perturb — to rattle someone's calm.","nt":"vocab-NWFinal-2026-Junior"},{"w":"pervade","d":"To spread through every part of something.","s":"The smell of popcorn pervaded the whole movie theater.","p":"per-VAYD","o":"Latin","y":4,"bp":74,"ps":"verb","r":"Latin per-, 'through,' plus vadere, 'to go' — to go through.","h":"Per means through — what pervades goes through everything.","nt":"vocab-NWFinal-2026-Junior"},{"w":"perverse","d":"Stubbornly doing the opposite of what is right or expected.","s":"Out of perverse stubbornness, he wore sandals in the snow.","p":"per-VURS","o":"Latin","y":4,"bp":68,"ps":"adjective","r":"From Latin perversus, 'turned the wrong way.'","h":"Turned the wrong way on purpose — contrary just to be contrary.","nt":"vocab-NWFinal-2026-Junior"},{"w":"petty","d":"Small and unimportant; also mean over little things.","s":"They wasted recess arguing over a petty difference in scores.","p":"PEH-tee","o":"French","y":3,"bp":70,"ps":"adjective","r":"From French petit, 'small.'","h":"From French for small — petty problems are tiny ones.","nt":"vocab-NWFinal-2026-Junior"},{"w":"phenomenal","d":"of or relating to a phenomenon","s":"The young gymnast delivered a phenomenal performance at the regional championship, earning perfect scores on two events and leaving the entire crowd breathless with her extraordinary combination of strength and grace.","p":"fuh-NAH-muh-nuhl","o":"Latin","y":3,"bp":35,"m":"phenominal","sy":"fah.naa.mah.nah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Greek phainomenon = that which appears","h":"PHENOMENAL spells out PHENOM-EN-AL — there's no I, just EN in the middle."},{"w":"phobia","d":"A very strong, often unreasonable fear of something.","s":"Her phobia of spiders makes even cartoon spiders scary.","p":"FOH-bee-uh","o":"Greek","y":3,"bp":76,"ps":"noun","r":"From Greek phobos, 'fear, panic.'","h":"The -phobia ending always signals fear — arachnophobia, fear of spiders.","nt":"vocab-NWFinal-2026-Junior"},{"w":"phonic","d":"Relating to sound, especially the sounds of speech.","s":"Phonic drills helped the first graders match letters to sounds.","p":"FAH-nik","o":"Greek","y":3,"bp":66,"ps":"adjective","r":"From Greek phone, 'sound, voice,' as in 'telephone.'","h":"Phone means sound — phonic is all about sounds.","nt":"vocab-NWFinal-2026-Junior"},{"w":"phosphorescence","d":"a fluorescence that persists after the bombarding radiation has ceased","s":"The eerie phosphorescence of the deep-sea jellyfish lit up the dark water like a tiny lantern.","p":"fah-sfer-EH-suhns","o":"Greek","y":3,"bp":39,"m":"phosphoresence","sy":"faa.sfer.eh.sah.ns","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek phōsphoros = light-bearing","h":"PHOSPHORESCENCE glows long after the light leaves — it has ESSENCE (-ENCE) of lingering light; spell out all five syllables: PHOS-PHOR-ES-CENCE.","t":["physics"]},{"w":"photometry","d":"The science of measuring light and its brightness.","s":"Using photometry, astronomers measured how brightly the star shines.","p":"foh-TAH-muh-tree","o":"Greek","y":4,"bp":62,"ps":"noun","r":"Greek phos/photo-, 'light,' plus -metria, 'measuring.'","h":"Photo (light) + metry (measure) = measuring light.","nt":"vocab-NWFinal-2026-Junior"},{"w":"piece","d":"A part or portion of something larger.","s":"Each camper got a piece of the giant birthday cake.","p":"PEES","o":"French","y":2,"bp":56,"ps":"noun","r":"From Old French piece, 'bit, portion.'","h":"A piece of pie — one part cut from the whole.","nt":"vocab-NWFinal-2026-Junior"},{"w":"pious","d":"having or showing or expressing reverence for a deity","s":"The pious monk rose before dawn every morning to pray, devoting his entire life to quiet reflection and selfless service to those around him in the monastery.","p":"PEYE-uhs","o":"Latin","y":3,"bp":69,"m":"pyous","sy":"pay.ah.s","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin pius = devout, dutiful","h":"A PIOUS person says their PIece On US — spell it p-i-o-u-s, no y in duty.","t":["myth"]},{"w":"piteous","d":"So sad or pathetic that it stirs pity.","s":"The lost kitten gave a piteous meow at our door.","p":"PIH-tee-us","o":"French","y":4,"bp":70,"ps":"adjective","r":"From Old French pitos, from Latin pietas, 'compassion, duty.'","h":"Piteous sights make you feel pity — heartbreakingly sad.","nt":"vocab-NWFinal-2026-Junior"},{"w":"pitfall","d":"A hidden danger or trap that is easy to fall into.","s":"Rushing through the test is a pitfall that costs easy points.","p":"PIT-fawl","o":"English","y":3,"bp":72,"ps":"noun","r":"English compound: a covered pit dug as a trap for animals.","h":"Literally a pit you fall into — a hidden trap ahead.","nt":"vocab-NWFinal-2026-Junior"},{"w":"pitiable","d":"Deserving pity; sad enough to make others feel sorry.","s":"The soaked, shivering puppy was a pitiable sight.","p":"PIH-tee-uh-bul","o":"French","y":3,"bp":66,"ps":"adjective","r":"From Old French pitier, 'to pity,' plus -able.","h":"Able to be pitied — a sight that tugs at your heart.","nt":"vocab-NWFinal-2026-Junior"},{"w":"pitiless","d":"Showing no pity or mercy; cruel.","s":"The pitiless sun beat down on the runners all afternoon.","p":"PIH-tee-les","o":"English","y":3,"bp":68,"ps":"adjective","r":"From 'pity,' Old French pite, plus -less, 'without.'","h":"Without pity — pitiless hearts show no mercy at all.","nt":"vocab-NWFinal-2026-Junior"},{"w":"pixel","d":"One tiny dot of light that helps make a picture on a screen.","s":"Zoom in far enough and the photo becomes squares of single pixels.","p":"PIK-sul","o":"English","y":3,"bp":64,"ps":"noun","r":"Twentieth-century English blend of 'picture element' (pix + el).","h":"Pix + element — one dot in the grid that builds a screen image.","nt":"vocab-NWFinal-2026-Junior"},{"w":"plaque","d":"a tablet or plate of metal intended for use as an ornament","s":"A bronze plaque on the library wall honored the generous donor who funded its construction.","p":"p-l-A-k","o":"English","y":3,"bp":45,"m":"plack","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"French plaque = plate, from Dutch plak = flat board","h":"A plAQUE hangs on the wall—it has a QUEUE of letters: Q-U-E at the end.","t":["pharmacy"]},{"w":"plight","d":"a condition or situation especially an unfavorable one","p":"p-l-AY-t","o":"English","y":4,"bp":60,"m":"plite","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old English pliht = danger, risk","h":"A PLIGHT is a frightful situation — the GH is silent but hides the danger within, like fright."},{"w":"ploy","d":"A clever trick or plan used to gain an advantage.","s":"Pretending to yawn was Ravi's ploy to hide his surprise move in chess.","p":"PLOY","o":"English","y":3,"bp":74,"ps":"noun","r":"Origin uncertain; perhaps a shortened form of 'employ,' first used in Scotland.","h":"A ploy is a play — a sneaky little scheme to win.","nt":"vocab-NWFinal-2026-Junior"},{"w":"pluck","d":"To pull something off or out quickly, like feathers or a flower.","s":"She stopped to pluck a daisy from the field.","p":"PLUK","o":"Old English","y":2,"bp":66,"ps":"verb","r":"From Old English pluccian, 'to pull off.' As a noun, pluck also means courage.","h":"A quick pull — pluck a petal, a string, or an eyebrow.","nt":"vocab-NWFinal-2026-Junior"},{"w":"plummet","d":"To fall straight down very fast.","s":"The hawk plummeted toward the field to catch a mouse.","p":"PLUH-mit","o":"French","y":3,"bp":76,"ps":"verb","r":"From Old French plommet, 'lead weight,' from Latin plumbum, 'lead.'","h":"Drop like a lead weight — plummeting means falling fast.","nt":"vocab-NWFinal-2026-Junior"},{"w":"polygon","d":"A flat closed shape with three or more straight sides.","s":"A hexagon is a polygon with six sides.","p":"PAH-lee-gahn","o":"Greek","y":3,"bp":70,"ps":"noun","r":"Greek poly, 'many,' plus gonia, 'angle' — many angles.","h":"Poly (many) + gon (angle) = a many-angled shape.","nt":"vocab-NWFinal-2026-Junior"},{"w":"pomp","d":"A grand, showy display, especially at a ceremony.","s":"The coronation was full of pomp, with trumpets and golden robes.","p":"PAHMP","o":"Greek","y":3,"bp":72,"ps":"noun","r":"From Greek pompe, 'solemn procession,' via Latin and Old French.","h":"Pomp and circumstance — the fancy show at big ceremonies.","nt":"vocab-NWFinal-2026-Junior"},{"w":"pompous","d":"puffed up with vanity","p":"PAH-mpuhs","o":"Latin","y":3,"bp":71,"m":"pompus","sy":"paa.mpah.s","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin pompa = solemn procession, pomp","h":"A POMPOUS person puts on a big POMP show — note the 'ous' ending like 'glorious.'"},{"w":"porous","d":"Full of tiny holes that let liquid or air pass through.","s":"The porous sponge soaked up the spilled juice instantly.","p":"POR-us","o":"Latin","y":3,"bp":74,"ps":"adjective","r":"From Latin porus, 'opening,' from Greek poros, 'passage.'","h":"Full of pores — porous things drink liquids right in.","nt":"vocab-NWFinal-2026-Junior"},{"w":"possess","d":"is to have as belonging to one to own","s":"He possesses great knowledge about the Middle East.","p":"p-uh-z-EH-s","o":"English","y":3,"bp":47,"m":"posess","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin possidere = to have and hold, from potis = able + sedere = to sit","h":"POSSESS has double S twice — you must SEIZE what you own, SS-SS."},{"w":"possible","d":"falling within the bounds of what may be done or be conceived","s":"Politics is the art of the possible.","p":"p-AH-s-uh-b-uh-l","o":"English","y":2,"bp":37,"m":"possable","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin 'posse' = to be able","h":"It IS possible — remember the -IBLE ending by thinking 'I'll Be Leaving Early' if I can't spell it."},{"w":"postdate","d":"To write a later date on something than the actual date.","s":"Mom postdated the check so the club would cash it next month.","p":"pohst-DAYT","o":"Latin","y":4,"bp":62,"ps":"verb","r":"Latin post, 'after,' plus 'date' — to date after.","h":"Post means after — postdating pushes the written date forward.","nt":"vocab-NWFinal-2026-Junior"},{"w":"prerequisite","d":"something that is required in advance","s":"Latin was a prerequisite for admission.","p":"pree-REH-kwuh-zuht","o":"Latin","y":3,"bp":37,"m":"prerequisit","sy":"priy.reh.kwah.zah.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin prae=before + requirere=to seek/require","h":"A PREREQUISITE is a REQUI-SITE thing you need BEFORE — don't drop the final E at the site."},{"w":"prestige","d":"The respect and high standing earned by success or excellence.","s":"Winning nationals brought great prestige to our small school.","p":"preh-STEEZH","o":"French","y":3,"bp":76,"ps":"noun","r":"From French prestige, from Latin praestigium, 'illusion, dazzling trick.'","h":"Prestige is star-power respect — fame earned through excellence.","nt":"vocab-NWFinal-2026-Junior"},{"w":"prestigious","d":"is having a high reputation","s":"Winning a spot at the prestigious summer science academy required months of hard work, dozens of recommendations, and an original research proposal that impressed a panel of university professors.","p":"p-r-eh-s-t-IH-j-uh-s","o":"English","y":4,"bp":67,"m":"prestigous","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin praestigiae (tricks, illusions) later evolving to mean admiration","h":"PRESTIGIOUS has PRESTIGE built right inside it"},{"w":"pretension","d":"a false or unsupportable quality","s":"His pretension to the crown.","p":"pree-TEH-nshuhn","o":"Latin","y":3,"bp":34,"m":"pretention","sy":"priy.teh.nshah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin praetensio = a stretching before, claim","h":"preTENSION has TENSION in it — the pretentious person is full of TENSION stretched before others."},{"w":"prevail","d":"To win out or prove stronger; also to be common or widespread.","s":"After three overtimes, the underdogs finally prevailed.","p":"prih-VAYL","o":"Latin","y":3,"bp":76,"ps":"verb","r":"Latin praevalere, 'to be stronger,' from valere, 'to be strong.'","h":"To prevail is to come out on top — strength that wins through.","nt":"vocab-NWFinal-2026-Junior"},{"w":"prevention","d":"the act of preventing","p":"pree-VEH-nshuhn","o":"Latin","y":3,"bp":34,"m":"prevension","sy":"priy.veh.nshah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin praevenire = to come before","h":"PreVENTion blocks the VENT before smoke escapes — it's pre+VENT+ion, no sneaky -s."},{"w":"primer","d":"A small beginner's book that teaches the first basics of a subject, like reading","s":"Grandma still keeps the primer she used when she first learned to read.","p":"PRIH-mer","o":"Latin","y":3,"bp":70,"ps":"noun","r":"From Latin primarius, 'first,' from primus — a first book for learners.","h":"A PRIMer is your PRIMary, very first lesson book.","nt":"vocab-NWFinal-2026-Junior"},{"w":"principal","d":"the original amount of a debt on which interest is calculated","s":"She sent unruly pupils to see the principal.","p":"PRIH-nsuh-puhl","o":"Latin","y":3,"bp":33,"m":"principle","sy":"prih.nsah.pah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin principalis = first in importance","h":"Your school PRINCIPAL is your PAL — principAL ends in A-L like PAL.","t":["economy"]},{"w":"prior","d":"Coming earlier in time; happening or existing before something else","s":"We had to skip the party because of a prior promise to visit our cousins.","p":"PRY-er","o":"Latin","y":2,"bp":75,"ps":"adjective","r":"Latin prior means 'former, earlier,' the comparative of 'before.'","h":"PRIor things happened PREviously — before now.","nt":"vocab-NWFinal-2026-Junior"},{"w":"productive","d":"producing or capable of producing (especially abundantly)","s":"The study group had its most productive session yet, finishing all three chapters of review and creating a shared set of flash cards in just under two focused hours.","p":"pruh-DUH-ktihv","o":"Latin","y":3,"bp":34,"m":"productave","sy":"prah.dah.ktih.v","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin productivus = able to produce","h":"PRODUCTIVE ends in '-ive' not '-ave' — if you're capable (ive) of leading (duct) forward, you're productive."},{"w":"yielding","d":"Giving way easily; not stiff or stubborn; soft or bendable","s":"The yielding mattress sank down as soon as the puppy jumped on it.","p":"YEEL-ding","o":"Old English","y":3,"bp":65,"ps":"adjective","r":"From Old English gieldan, 'to pay or give' — giving way when pushed.","h":"Something YIELDING gives in — like soft dough under your thumb.","nt":"vocab-NWFinal-2026-Junior"},{"w":"proficient","d":"having or showing knowledge and skill and aptitude","p":"prah-FIH-shuhnt","o":"Latin","y":3,"bp":34,"m":"proficiant","sy":"praa.fih.shah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin proficiens = making progress, advancing","h":"A proficient person is EFFICIENT — spot 'fici' in the middle, like an efficient factory.","t":["logic"]},{"w":"profile","d":"an analysis (often in graphical form) representing the extent to which something exhibits various characteristics","s":"The detective created a detailed profile of the suspect based on witness descriptions and security camera footage.","p":"PROH-feyel","o":"French","y":2,"bp":42,"m":"profiel","sy":"pro.file","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Italian profilo = outline, from profilare (to draw an outline), from pro (forward) + filo (thread, line)","h":"A PROFILE shows the outline — FILE the features in a single line"},{"w":"profusely","d":"in an abundant manner","p":"pruh-FYOO-slee","o":"Latin","y":3,"bp":33,"m":"profusly","sy":"prah.fyuw.sliy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adverb","r":"Latin profusus = poured forth","h":"She apologized profusELY — keep the 'e' from 'profuse' before adding 'ly': profuse+ly."},{"w":"prolong","d":"To make something last longer; to stretch out in time","s":"We begged the coach to prolong recess for ten more minutes.","p":"pruh-LAWNG","o":"Latin","y":3,"bp":75,"ps":"verb","r":"Latin pro- 'forward' + longus 'long' — to lengthen out.","h":"ProLONG makes something LONGer in time.","nt":"vocab-NWFinal-2026-Junior"},{"w":"promoter","d":"someone who is an active supporter and advocate","s":"The concert promoter worked tirelessly to sell out the stadium before the big show.","p":"pruh-MOH-ter","o":"Latin","y":3,"bp":32,"m":"promottor","sy":"prah.mow.ter","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin promovere = to move forward","h":"A promoter moves things forward with just one 't' — doubling slows the momentum.","t":["character"],"vh":"one who"},{"w":"propeller","d":"a mechanical device that rotates to push against air or water","s":"The old wooden propeller on the vintage plane gleamed after the mechanic polished it.","p":"pruh-PEH-ler","o":"Latin","y":3,"bp":33,"m":"propeler","sy":"prah.peh.ler","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin propellere = to drive forward + -er = one that does","h":"A propeLLEr has two L's spinning like two blades on a propeller — double-L, then -ER.","t":["tools"]},{"w":"prophetic","d":"foretelling events as if by supernatural intervention","s":"Her warning about the company's financial troubles turned out to be prophetic, as the business collapsed only six months after she predicted it would fail.","p":"pruh-FEH-tihk","o":"Greek","y":3,"bp":33,"m":"profetic","sy":"prah.feh.tih.k","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Greek prophetikos = of a prophet","h":"ProPHETic: if the PROPHET was right, his words were proPHETic—same PH root!"},{"w":"prospect","d":"Something expected or looked forward to; a possibility for the future","s":"The prospect of a snow day made the whole class cheer.","p":"PRAH-spekt","o":"Latin","y":3,"bp":75,"ps":"noun","r":"Latin pro- 'forward' + specere 'to look' — a look ahead.","h":"A PROspect is what you SPECtate ahead — a look at what's coming.","nt":"vocab-NWFinal-2026-Junior"},{"w":"protection","d":"the activity of protecting someone or something","s":"The witnesses demanded police protection.","p":"pruh-TEH-kshuhn","o":"Latin","y":3,"bp":34,"m":"protecton","sy":"prah.teh.kshah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin protectio = a covering","h":"proTECTion is the act of covering — TECT is the roof, and -ION seals it as a noun, like a helmet locked on."},{"w":"proximity","d":"the property of being close together","s":"The proximity of the two rival schools made every sporting event feel like a championship game.","p":"prah-KSIH-muh-tee","o":"Latin","y":3,"bp":34,"m":"proximitiy","sy":"praa.ksih.mah.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin proximus = nearest","h":"PRO X marks the spot—proximity means nearness to that X."},{"w":"pungent","d":"Having a sharp, strong smell or taste that stings the senses","s":"The pungent smell of onions made my eyes water while Dad cooked.","p":"PUN-jent","o":"Latin","y":3,"bp":80,"ps":"adjective","r":"Latin pungere, 'to prick or sting' — a smell that stings the nose.","h":"PUNgent smells PUNch your nose, like strong onions.","nt":"vocab-NWFinal-2026-Junior"},{"w":"puny","d":"inferior in strength or significance","s":"The puny seedling barely reached two inches tall, yet by the end of summer it had somehow grown into a sturdy plant taller than the garden fence.","p":"PYOO-nee","o":"French","y":3,"bp":68,"m":"punie","sy":"pyuw.niy","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"adjective","r":"French puisné = born afterward, younger, hence weak","h":"A PUNY pony is too tiny — PUNY rhymes with TINY and both end in Y."},{"w":"purge","d":"To clean out or get rid of something unwanted completely","s":"Before the move, we purged the closet of toys nobody played with.","p":"PURJ","o":"Latin","y":3,"bp":70,"ps":"verb","r":"Latin purgare, 'to make pure or clean.'","h":"PURge makes things PURe by clearing the junk out.","nt":"vocab-NWFinal-2026-Junior"},{"w":"quadrant","d":"One of four equal parts of a circle or area","s":"Our teacher shaded one quadrant of the circle to show one fourth.","p":"KWAH-drunt","o":"Latin","y":3,"bp":70,"ps":"noun","r":"Latin quadrans, 'a fourth part,' from quattuor 'four.'","h":"QUADrant = QUARTER: think quad (four), one of four pieces.","nt":"vocab-NWFinal-2026-Junior"},{"w":"quadruped","d":"an animal especially a mammal having four limbs specialized for walking","s":"The horse is a classic quadruped whose four powerful legs allow it to gallop at impressive speeds.","p":"KWOD-roo-ped","o":"French","y":3,"bp":33,"m":"quadrupped","sy":"quad.ru.ped","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin quadru = four + pes/pedis = foot","h":"A quadruPED has four PEDs (feet) — think of a centipede but with only four legs.","t":["body","animals"]},{"w":"quadruple","d":"a set of four similar things considered as a unit","s":"His stock earning quadrupled.","p":"kwah-DROO-puhl","o":"Latin","y":3,"bp":33,"m":"quadrupple","sy":"kwaa.druw.pah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin quadruplus = fourfold","h":"QUADRUple — QUADRU sounds like 'quad' as in four wheels; one 'p', not two, multiplies it correctly.","vh":"to multiply by"},{"w":"quarrelsome","d":"given to quarreling","s":"The quarrelsome neighbor complained about every tiny noise, picking fights with anyone who dared park too close to his driveway or let their dog wander onto his lawn.","p":"KWAW-ruh-lsuhm","o":"Greek","y":3,"bp":34,"m":"quarrelsom","sy":"kwao.rah.lsah.m","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin querela = complaint + Old English sum = tending to be","h":"A quarrelsome person is troubleSOME — always remember the -some at the end."},{"w":"query","d":"A question, especially one asking for information","s":"The librarian answered my query about where the dinosaur books were kept.","p":"KWEER-ee","o":"Latin","y":3,"bp":75,"ps":"noun","r":"Latin quaerere, 'to ask or seek' — same root as 'question.'","h":"QUERY starts like QUEstion — both mean asking something.","nt":"vocab-NWFinal-2026-Junior"},{"w":"quest","d":"A long search or journey to find or achieve something","s":"In the video game, our hero goes on a quest to find the golden key.","p":"KWEST","o":"Latin","y":2,"bp":70,"ps":"noun","r":"Latin quaerere, 'to seek,' through Old French queste, 'a search.'","h":"A QUEST is a big search — knights quest for treasure.","nt":"vocab-NWFinal-2026-Junior"},{"w":"radiance","d":"the amount of electromagnetic radiation leaving or arriving at a point on a surface","s":"The radiance of her countenance.","p":"RAY-dee-uhns","o":"Latin","y":3,"bp":32,"m":"radianse","sy":"rey.diy.ah.ns","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin radiare = to emit rays, from radius = ray","h":"RADIANCE ends in -ANCE, not -ANSE — a glowing DANCE of light has that ANCE ending too.","t":["physics"]},{"w":"rag","d":"A torn or worn scrap of cloth, often used for cleaning","s":"Mom handed me a rag to wipe the paint off the table.","p":"RAG","o":"Norse","y":2,"bp":60,"ps":"noun","r":"Likely from Old Norse rögg, 'shaggy tuft' — a raggedy scrap of cloth.","h":"A RAG is a RAGgedy old cloth for wiping messes.","nt":"vocab-NWFinal-2026-Junior"},{"w":"random","d":"Happening by chance, without any plan, order, or pattern","s":"The teacher drew a random name from the jar to pick line leader.","p":"RAN-dum","o":"French","y":2,"bp":70,"ps":"adjective","r":"Old French randon, 'rush, disorder' — moving with no set path.","h":"RANDOM means no rules, no plan — like rolling dice.","nt":"vocab-NWFinal-2026-Junior"},{"w":"ransack","d":"To search a place wildly and messily, often while stealing things","s":"I ransacked my whole room looking for my missing library book.","p":"RAN-sak","o":"Norse","y":3,"bp":75,"ps":"verb","r":"Old Norse rannsaka, 'to search a house' (rann 'house' + saka 'seek').","h":"RANsack: someone RAN through and turned every SACK inside out.","nt":"vocab-NWFinal-2026-Junior"},{"w":"rapport","d":"is relation or connection","s":"The teacher quickly built a warm rapport with her students by listening to their ideas.","p":"r-a-p-AW-r","o":"English","y":3,"bp":47,"m":"raport","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"French rapporter = to bring back, relate","h":"Good RAPPORT carries a silent T at the end — like a French diplomat, elegantly quiet: R-A-P-P-O-R-T."},{"w":"rash","d":"Acting too quickly without thinking about what might happen","s":"It was rash of him to trade his whole lunch for one sticker.","p":"RASH","o":"German","y":3,"bp":75,"ps":"adjective","r":"From Middle English rasch, related to German rasch, 'quick, hasty.'","h":"A RASH choice is made in a RUSH — fast and careless.","nt":"vocab-NWFinal-2026-Junior"},{"w":"rasping","d":"Rough, harsh, and scratchy sounding, like grating metal","s":"After yelling all game, the coach spoke in a rasping voice.","p":"RAS-ping","o":"French","y":3,"bp":65,"ps":"adjective","r":"From Old French rasper, 'to scrape' — a scraping, gritty sound.","h":"RASPing sounds like a RASP file scraping wood — rough and scratchy.","nt":"vocab-NWFinal-2026-Junior"},{"w":"referable","d":"capable of being assigned or credited to","s":"The scientist concluded that the unusual symptoms were referable to a rare mineral deficiency.","p":"REF-ur-uh-bul","o":"Latin","y":3,"bp":34,"m":"referrable","sy":"ref.er.a.ble","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin referre = to carry back","h":"REFERable has only one R after REFER — it's ABLE to be referred, no need to double up yet."},{"w":"reflection","d":"a calm, lengthy, intent consideration","p":"rih-FLEH-kshuhn","o":"French","y":3,"bp":34,"m":"reflextion","sy":"rah.fleh.kshah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin reflectere = to bend back","h":"REFLECTION bends light and bends letters: re-FLECT-ION — no X, just CT then ION."},{"w":"refrain","d":"the part of a song where a soloist is joined by a group of singers","s":"By the third verse everyone in the auditorium had learned the refrain and sang along at the top of their lungs.","p":"rih-FRAYN","o":"French","y":2,"bp":42,"m":"refrane","sy":"re.frain","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old French refraindre = to repeat, from Latin refrangere = to break back","h":"The refrain REFRAINS from stopping — it keeps coming back.","t":["music"]},{"w":"regard","d":"To think of or consider someone or something in a certain way","s":"Everyone in class regards Maya as the best artist in fourth grade.","p":"rih-GARD","o":"French","y":3,"bp":70,"ps":"verb","r":"Old French regarder, 'to look at' (re- + garder 'to watch').","h":"To reGARD is to GUARD someone with your eyes — look at and consider them.","nt":"vocab-NWFinal-2026-Junior"},{"w":"regenerate","d":"reestablish on a new, usually improved, basis or make new or like new","p":"ree-JEH-ner-ayt","o":"Latin","y":3,"bp":35,"m":"regenarate","sy":"riy.jheh.ner.ey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin regenerare = to bring forth again","h":"RE-GEN-erate: to GENerate again from scratch."},{"w":"regime","d":"A government that rules a country, or a system of rule","s":"The history book described how the old regime was replaced by elected leaders.","p":"ruh-ZHEEM","o":"French","y":4,"bp":70,"ps":"noun","r":"French régime, from Latin regimen, 'rule, guidance,' from regere 'to rule.'","h":"A REGime REIGNs — it's the group in charge of a country.","nt":"vocab-NWFinal-2026-Junior"},{"w":"register","d":"an official written record of names or events or transactions","s":"The school secretary carefully recorded each student's arrival in the morning register.","p":"REH-jih-ster","o":"Latin","y":3,"bp":32,"m":"registar","sy":"reh.jhih.ster","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin registrum = list, from regerere = to record","h":"REGISTER ends in -STER like a gangSTER who records all the names."},{"w":"regress","d":"To go backward, especially to an earlier or worse condition","s":"Without practice all summer, my piano skills started to regress.","p":"rih-GRES","o":"Latin","y":4,"bp":70,"ps":"verb","r":"Latin re- 'back' + gradi 'to step' — to step backward.","h":"REgress is the REverse of progress — sliding backward.","nt":"vocab-NWFinal-2026-Junior"},{"w":"rein","d":"A strap used to guide and control a horse","s":"She pulled gently on the rein to turn her pony toward the barn.","p":"RAYN","o":"French","y":2,"bp":65,"ps":"noun","r":"Old French rene, from Latin retinere, 'to hold back.'","h":"REINs let a rider REIGN over the horse — steering straps.","nt":"vocab-NWFinal-2026-Junior"},{"w":"relative","d":"a person related by blood or marriage","s":"Police are searching for relatives of the deceased.","p":"REH-luh-tihv","o":"Latin","y":3,"bp":32,"m":"relativve","sy":"reh.lah.tih.v","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin relativus = having reference or relation","h":"Your reLATIVE is someone you reLATE to — RELATE drops the E and adds -IVE.","t":["body","kinship"]},{"w":"relativity","d":"(physics) the theory that space and time are relative concepts rather than absolute concepts","s":"Einstein's theory of relativity forever changed the way scientists understood space, time, and gravity.","p":"reh-luh-TIH-vuh-tee","o":"Latin","y":3,"bp":37,"m":"relativety","sy":"reh.lah.tih.vah.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin relatus = carried back, related","h":"Einstein's RELATIVITY relates space and time — spot 'relate' hiding inside it.","t":["physics","logic","time"],"vh":"theory"},{"w":"concerning","d":"be relevant to","p":"kuh-NSUR-nihng","o":"Latin","y":3,"bp":34,"m":"concering","sy":"kah.nser.nih.ng","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin concernere = to sift together, relate to","h":"conCERNing keeps the full CERN — don't drop letters when adding -ING here!"},{"w":"relent","d":"To become less strict or harsh; to finally give in","s":"After we begged for an hour, Dad relented and let us camp in the yard.","p":"rih-LENT","o":"Latin","y":3,"bp":75,"ps":"verb","r":"Latin re- + lentus 'soft, flexible' — to soften one's stand.","h":"To reLENT is to LET up — a strict 'no' melts into 'okay.'","nt":"vocab-NWFinal-2026-Junior"},{"w":"relentless","d":"not to be placated or appeased or moved by entreaty","s":"The relentless wind battered the tiny sailboat for three days straight, giving the exhausted crew no chance to rest as they struggled to keep the vessel on course through the storm.","p":"rih-LEH-ntlihs","o":"Latin","y":3,"bp":34,"m":"relentles","sy":"rih.leh.ntlih.s","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin lentus = slow, flexible","h":"The RELENTLESS storm had LESS and LESS mercy — it never softened."},{"w":"reliance","d":"certainty based on past experience","s":"He wrote the paper with considerable reliance on the work of other scientists.","p":"rih-LEYE-uhns","o":"Latin","y":3,"bp":32,"m":"relience","sy":"rih.lay.ah.ns","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin religare = to bind fast","h":"RELIANCE ends in -ANCE: your ANCE-stors RELIED on each other for survival."},{"w":"reliant","d":"Depending on someone or something for help or support","s":"The baby birds are completely reliant on their mother for food.","p":"rih-LY-unt","o":"French","y":3,"bp":70,"ps":"adjective","r":"From rely, Old French relier, Latin religare 'to bind fast.'","h":"RELIant means you RELY on someone — you lean on them.","nt":"vocab-NWFinal-2026-Junior"},{"w":"remediable","d":"Able to be fixed, cured, or made right","s":"The coach said my slow start was remediable with a few extra drills.","p":"rih-MEE-dee-uh-buhl","o":"Latin","y":4,"bp":70,"ps":"adjective","r":"Latin remedium, 'cure' + -able — able to be remedied.","h":"REMEDIable holds REMEDY — if there's a remedy, it can be fixed.","nt":"vocab-NWFinal-2026-Junior"},{"w":"remedial","d":"tending or intended to rectify or improve","s":"The teacher offered remedial math sessions every Tuesday to help students who had fallen behind.","p":"rih-MEE-dee-uhl","o":"Latin","y":1,"bp":41,"m":"remidial","sy":"re.me.di.al","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin remedium = cure, remedy","h":"REMEDY + ial — remedial work is the REMEDY for gaps in learning","vh":"Pertaining to"},{"w":"renovate","d":"restore to a previous or better condition","s":"They renovated the ceiling of the Sistine Chapel.","p":"REH-nuh-vayt","o":"Latin","y":3,"bp":32,"m":"renovait","sy":"reh.nah.vey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin renovare = to renew; novus = new","h":"reNOVAte: NOVel things are NEW — renovate makes a place new again."},{"w":"reorganize","d":"organize anew","s":"We must reorganize the company if we don't want to go under.","p":"ree-AW-rguh-neyez","o":"Latin","y":3,"bp":35,"m":"reorganise","sy":"riy.ao.rgah.nay.z","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Greek organon = instrument, tool","h":"REORGANIZE uses American -IZE — picture an ORGAN being tuned with a Z-shaped wrench."},{"w":"resistant","d":"relating to or conferring immunity (to disease or infection)","p":"rih-ZIH-stuhnt","o":"French","y":3,"bp":33,"m":"resistent","sy":"rih.zih.stah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin resistere = to stand against","h":"RESISTANT ends in -ANT — the resistant ANT stands firm against the picnic invaders.","t":["disease"]},{"w":"resource","d":"A supply of something useful that can be used when needed","s":"The library is a great resource for our science fair projects.","p":"REE-sors","o":"French","y":2,"bp":65,"ps":"noun","r":"French ressource, from Latin resurgere, 'to rise again' — a source to draw on.","h":"A reSOURCE is a SOURCE of help — water, books, or money you can use.","nt":"vocab-NWFinal-2026-Junior"},{"w":"restrain","d":"To hold back or keep under control","s":"I had to restrain my dog from chasing the squirrel across the street.","p":"rih-STRAYN","o":"Latin","y":3,"bp":75,"ps":"verb","r":"Latin re- 'back' + stringere 'to bind tight' — to hold back.","h":"ReSTRAIN puts on the STRAP — holding something back.","nt":"vocab-NWFinal-2026-Junior"},{"w":"retain","d":"To keep or continue to have something","s":"She managed to retain her title as spelling champion for a second year.","p":"rih-TAYN","o":"Latin","y":3,"bp":75,"ps":"verb","r":"Latin retinere, 'to hold back or keep' (re- + tenere 'to hold').","h":"ReTAIN means keep it — a reTAINer holds your teeth in place.","nt":"vocab-NWFinal-2026-Junior"},{"w":"retainer","d":"a fee charged in advance to retain the services of someone","s":"The family paid the lawyer a monthly retainer so she would always be available whenever legal questions arose.","p":"rih-TAY-ner","o":"Latin","y":3,"bp":32,"m":"retaner","sy":"rih.tey.ner","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin retinere = to hold back","h":"A RETAINER holds your teeth or your lawyer — re + TAIN + er, it holds the AIN in place."},{"w":"retrieve","d":"To get something back; to go and bring something back","s":"Our golden retriever loves to retrieve the tennis ball from the pond.","p":"rih-TREEV","o":"French","y":3,"bp":75,"ps":"verb","r":"Old French retrover, 'to find again' (re- 'again' + trouver 'to find').","h":"A reTRIEVEr fetches the ball back — retrieve means bring it back.","nt":"vocab-NWFinal-2026-Junior"},{"w":"revel","d":"To enjoy something greatly; to celebrate with wild delight","s":"The team reveled in their championship win with pizza and cheering.","p":"REH-vuhl","o":"French","y":3,"bp":75,"ps":"verb","r":"Old French reveler, 'to make merry,' from Latin rebellare 'to rebel, make noise.'","h":"To REVEL is to have a party-level of joy — think 'revelers' celebrating.","nt":"vocab-NWFinal-2026-Junior"},{"w":"revelation","d":"the speech act of making something evident","s":"It was a complete revelation to the class when the scientist announced that the fossil they had found belonged to a brand-new species of dinosaur.","p":"reh-vuh-LAY-shuhn","o":"Latin","y":3,"bp":35,"m":"revelaton","sy":"rev.e.la.tion","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin revelare = to unveil, from re-(back)+velum(veil)","h":"reveLATion — the LATE part reveals the -LATION suffix; think 'the veil is lifted LATE in the story.'"},{"w":"revoke","d":"To officially take back or cancel something, like a rule or permission","s":"The principal revoked our extra recess after the hallway got too rowdy.","p":"rih-VOHK","o":"Latin","y":3,"bp":80,"ps":"verb","r":"Latin revocare, 'to call back' (re- 'back' + vocare 'to call').","h":"ReVOKE calls it back — permission granted, then canceled.","nt":"vocab-NWFinal-2026-Junior"},{"w":"ridicule","d":"language or behavior intended to mock or humiliate","s":"The satirists ridiculed the plans for a new opera house.","p":"RIH-duh-kyool","o":"Latin","y":3,"bp":32,"m":"ridicuel","sy":"rih.dah.kyuw.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin ridiculus = laughable, from ridere = to laugh","h":"RIDICULE: RID someone of dignity — R-I-D-I-C-U-L-E, keep the U before L-E.","t":["wordwords"]},{"w":"rift","d":"A crack or split; a break in friendship between people","s":"A silly argument over a board game caused a rift between the two friends.","p":"RIFT","o":"Norse","y":3,"bp":75,"ps":"noun","r":"From Old Norse ript, 'a breach or break.'","h":"A RIFT is a RIP — a crack in rock or in a friendship.","nt":"vocab-NWFinal-2026-Junior"},{"w":"robust","d":"Strong, healthy, and sturdy; not likely to break or fail","s":"The robust treehouse survived the windstorm without losing a single board.","p":"roh-BUST","o":"Latin","y":3,"bp":80,"ps":"adjective","r":"Latin robustus, 'oaken, strong,' from robur, 'oak tree.'","h":"ROBUST = built like an oak — strong and tough.","nt":"vocab-NWFinal-2026-Junior"},{"w":"rowdy","d":"Noisy, rough, and hard to control","s":"The rowdy crowd stomped and shouted through the whole basketball game.","p":"ROW-dee","o":"English","y":2,"bp":70,"ps":"adjective","r":"American English word from the early 1800s, possibly related to 'row,' a noisy fight.","h":"ROWdy people raise a ROW — a loud, wild ruckus.","nt":"vocab-NWFinal-2026-Junior"},{"w":"safeguard","d":"a precautionary measure warding off impending danger or damage or injury etc.","p":"SAY-fgahrd","o":"French","y":3,"bp":72,"m":"safegaurd","sy":"sey.fgaa.rd","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old French sauf = safe + garde = guard","h":"A SAFEGUARD keeps you SAFE — GUARD the spelling: s-a-f-e-g-u-a-r-d, 'guard' spelled fully at the end.","t":["numbers"]},{"w":"saga","d":"a narrative telling the adventures of a hero or a family; originally (12th to 14th centuries) a story of the families that settled Iceland and their descendants but now any prose narrative that resembles such an account","s":"The family saga spanned four generations, from the Viking age to modern times.","p":"SAH-guh","o":"Norse","y":2,"bp":35,"m":"saaga","sy":"saa.gah","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old Norse saga = story, from segja = to say","h":"A SAGA is a long story but a SHORT word — only four letters: S-A-G-A, alternating consonant-vowel twice.","t":["poetry","kinship","time"]},{"w":"scholarly","d":"characteristic of scholars or scholarship","s":"Her scholarly article on medieval trade routes was so thoroughly researched and carefully argued that it was immediately accepted by one of the most respected academic journals in the history department.","p":"SKAH-ler-lee","o":"Latin","y":3,"bp":33,"m":"scholerly","sy":"skaa.ler.liy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin schola = school, from Greek skholē = leisure","h":"SCHOLARLY = SCHOLAR + LY; a scholarly person IS a scholar, just dressed up with '-ly' at the end."},{"w":"scope","d":"The range or extent of what something covers or deals with","s":"Fixing the whole playground was beyond the scope of our small class project.","p":"SKOHP","o":"Greek","y":3,"bp":70,"ps":"noun","r":"Greek skopos, 'target, aim; watcher' — how far your aim reaches.","h":"SCOPE is how far you can see or reach — like a telescope's view.","nt":"vocab-NWFinal-2026-Junior"},{"w":"scribe","d":"A person whose job is writing or copying documents by hand","s":"Long before printers, a scribe copied every page of a book by hand.","p":"SKRYB","o":"Latin","y":3,"bp":75,"ps":"noun","r":"Latin scribere, 'to write' — root of scribble, describe, script.","h":"A SCRIBE SCRIBbles for a living — a professional writer-copier.","nt":"vocab-NWFinal-2026-Junior"},{"w":"secondary","d":"the defensive football players who line up behind the linemen","s":"The stone will be hauled to a secondary crusher.","p":"SEH-kuh-ndeh-ree","o":"Latin","y":3,"bp":34,"m":"secondery","sy":"seh.kah.ndeh.riy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin secundarius = of the second rank, from secundus(second)","h":"secondARY: ARe You second? ARY says yes—spell it with an A not an E.","t":["sports"]},{"w":"secretive","d":"inclined to secrecy or reticence about divulging information","p":"SEE-kruh-tihv","o":"Latin","y":3,"bp":33,"m":"secrettive","sy":"siy.krah.tih.v","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin secretus = hidden, set apart","h":"secretIVE: a secretive person keeps things SECRET—just add IVE, like a private detective hiding the evidence.","t":["character"]},{"w":"postulate","d":"(logic) a proposition that is accepted as true in order to provide a basis for logical reasoning","p":"PAH-schuh-layt","o":"Latin","y":3,"bp":33,"m":"postulaite","sy":"paa.schah.ley.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin postulare = to demand/request","h":"POSTULATE — POSTUL sounds like POSTURE, and you ATE the assumption whole as given truth.","t":["logic"],"vh":"to"},{"w":"potent","d":"Very powerful, strong, or effective","s":"The doctor gave her a potent medicine that cleared the fever overnight.","p":"POH-tent","o":"Latin","y":3,"bp":80,"ps":"adjective","r":"Latin potens, 'powerful,' from posse, 'to be able.'","h":"POTENT hides in 'POTENTial power' — full strength.","nt":"vocab-NWFinal-2026-Junior"},{"w":"potential","d":"the inherent capacity for coming into being","s":"The science teacher told Priya that she had enormous potential as a researcher, because she asked better questions than most students twice her age and never stopped investigating answers.","p":"puh-TEH-nshuhl","o":"Latin","y":3,"bp":33,"m":"potencial","sy":"pah.teh.nshah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin potentialis = powerful, from potentia = power","h":"potenTIAL: the T-I-A-L ending is like 'initial' — your initial power is your potential."},{"w":"practicable","d":"usable for a specific purpose","s":"The engineer proposed several solutions, but only two were truly practicable given the limited budget and the tight six-week construction deadline the city had set.","p":"PRA-ktuh-kuh-buhl","o":"French","y":3,"bp":36,"m":"practicible","sy":"prae.ktah.kah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"French practicable from Latin practicare = to practice","h":"PracticABLE — if it's ABLE to be practiced, it's practicABLE, not practicIBLE."},{"w":"precedence","d":"status established in order of importance or urgency","s":"...its precedence as the world's leading manufacturer of pharmaceuticals.","p":"PREH-suh-duhns","o":"Latin","y":3,"bp":34,"m":"preceedence","sy":"preh.sah.dah.ns","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin prae=before + cedere=to go","h":"PRECE-dence: the state of going BEFORE — one E in the middle, not two."},{"w":"precise","d":"Exact and accurate; carefully correct in every detail","s":"The recipe needs a precise amount of baking soda or the cake sinks.","p":"prih-SYS","o":"Latin","y":2,"bp":75,"ps":"adjective","r":"Latin praecisus, 'cut short exactly' (prae- + caedere 'to cut').","h":"PRECISE is cut exactly right — no more, no less.","nt":"vocab-NWFinal-2026-Junior"},{"w":"predispose","d":"make susceptible","s":"This illness predisposes you to gain weight.","p":"pree-dih-SPOHZ","o":"Latin","y":3,"bp":34,"m":"predispoze","sy":"priy.dih.spow.z","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin disponere = to arrange (dis=apart + ponere=to place)","h":"Being preDISPOSEd means you're already POSED in a certain direction before the game begins."},{"w":"predominant","d":"most frequent or common","s":"Blue and silver were the predominant colors throughout the school's hallways, appearing on every banner, locker, and painted tile from the entrance to the gymnasium.","p":"prih-DAH-muh-nuhnt","o":"Latin","y":3,"bp":36,"m":"predominent","sy":"prih.daa.mah.nah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin dominari = to rule","h":"The preDOMINANT ant rules the hill — spell it with -ANT like the insect that dominates."},{"w":"preface","d":"An introduction at the beginning of a book or speech","s":"In the preface, the author explains why she wrote the story.","p":"PREH-fus","o":"Latin","y":3,"bp":75,"ps":"noun","r":"Latin praefatio, 'a saying beforehand' (prae- 'before' + fari 'to speak').","h":"The PREface comes PRE (before) the book FACES its first chapter.","nt":"vocab-NWFinal-2026-Junior"},{"w":"prefix","d":"A word part added to the beginning of a word to change its meaning","s":"Adding the prefix 'un' turns 'happy' into 'unhappy.'","p":"PREE-fiks","o":"Latin","y":2,"bp":70,"ps":"noun","r":"Latin prae- 'before' + figere 'to fasten' — fastened on the front.","h":"A PREfix is FIXed to the front — 're-' in 'redo.'","nt":"vocab-NWFinal-2026-Junior"},{"w":"premier","d":"First in rank or importance; the very best","s":"She trains at the premier gymnastics club in the whole state.","p":"prih-MEER","o":"French","y":3,"bp":75,"ps":"adjective","r":"French premier, 'first,' from Latin primarius, 'of first rank.'","h":"PREMIER = PRIME spot — number one, top of the list.","nt":"vocab-NWFinal-2026-Junior"},{"w":"preparatory","d":"preceding and preparing for something","s":"The athletes completed a rigorous preparatory training camp every August, conditioning their bodies and reviewing strategy before the official season games began in September.","p":"prih-PEH-ruh-taw-ree","o":"Latin","y":3,"bp":37,"m":"preparitory","sy":"prih.peh.rah.tao.riy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin praeparatorius=making ready","h":"preparATORY — it's preparatory, not preparitory; think 'prepare' + -atory like 'laboratory.'"},{"w":"readjust","d":"To adjust something again or in a new way, especially after a change in circumstances has made a previous arrangement no longer suitable or accurate.","s":"After moving back to America, he had to readjust.","p":"ree-uh-JUHST","o":"French","y":3,"bp":32,"m":"re-adjust","sy":"riy.ah.jhah.st","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"French ajuster = to make exact","h":"READJUST: RE + ADJUST — think 'I need to adjust again,' no hyphen needed."},{"w":"ready","d":"Prepared and able to do something right away","s":"By seven o'clock she was ready for school with her backpack zipped.","p":"REH-dee","o":"Old English","y":2,"bp":55,"ps":"adjective","r":"Old English ræde, 'prepared, arranged.'","h":"READY, set, go — all prepared before the start.","nt":"vocab-NWFinal-2026-Junior"},{"w":"realignment","d":"The act of putting things back into proper position or order","s":"The bike shop did a realignment of my crooked front wheel.","p":"ree-uh-LYN-ment","o":"French","y":4,"bp":65,"ps":"noun","r":"Re- 'again' + align, from French à ligne, 'into line.'","h":"REalignment puts things back in LINE again.","nt":"vocab-NWFinal-2026-Junior"},{"w":"reassure","d":"cause to feel sure; give reassurance to","s":"The airline tried to reassure the customers that the planes were safe.","p":"ree-uh-SHUUR","o":"French","y":3,"bp":32,"m":"reassurre","sy":"riy.ah.shuh.r","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"French assurer = to make secure/sure","h":"To REASSURE is to make someone SURE again — RE+ASSURE, and SURE ends it all."},{"w":"reboot","d":"To restart a computer or device so it begins fresh","s":"When the tablet froze, Dad had to reboot it before we could play.","p":"ree-BOOT","o":"English","y":2,"bp":60,"ps":"verb","r":"Re- 'again' + boot, from 'bootstrap,' the process a computer uses to start.","h":"REboot means BOOT it up again — turn it off and on.","nt":"vocab-NWFinal-2026-Junior"},{"w":"rebuild","d":"To build something again after it has been damaged or destroyed","s":"After the flood, the whole town helped rebuild the playground.","p":"ree-BILD","o":"Old English","y":2,"bp":55,"ps":"verb","r":"Re- 'again' (Latin) + Old English byldan, 'to construct a house.'","h":"REbuild = BUILD it again from the ground up.","nt":"vocab-NWFinal-2026-Junior"},{"w":"receivable","d":"awaiting payment","s":"The accountant carefully listed every receivable invoice in the company's ledger, tracking the money that customers still owed so the business could plan its monthly budget accurately.","p":"rih-SEE-vuh-buhl","o":"French","y":3,"bp":35,"m":"recievable","sy":"rih.siy.vah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin recipere = to receive, re- + capere = take","h":"I before E rule breaks here: reCEIVable — CEI, because you RECEIVE money into your CEIling of income."},{"w":"recess","d":"A short break from work or activity, like a pause in the school day","s":"At recess we played kickball until the bell rang.","p":"REE-ses","o":"Latin","y":2,"bp":60,"ps":"noun","r":"Latin recessus, 'a going back, retreat,' from recedere 'to go back.'","h":"RECESS is when class RECEDES — everyone steps back for a break.","nt":"vocab-NWFinal-2026-Junior"},{"w":"recluse","d":"one who lives in solitude","s":"After years of fame, the retired actress became a recluse who rarely left her mountain cabin.","p":"rih-KLOOS","o":"French","y":1,"bp":83,"m":"recluese","sy":"re.cluse","nt":"Primary | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old French reclus, from Latin recludere = to shut away (re- + claudere = to close)","h":"A recluse is CLOSED off (re-CLUSE) from the world."},{"w":"recreate","d":"give new life or energy to","p":"REH-kree-ayt","o":"Latin","y":3,"bp":32,"m":"re-create (hyphen error) or recreat","sy":"reh.kriy.ey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin recreare = to refresh, create anew","h":"To RECREATE is to CREATE something again — the prefix re- is your clue.","t":["physics"]},{"w":"recruit","d":"To get new people to join a group, team, or organization","s":"The chess club made posters to recruit new members this fall.","p":"rih-KROOT","o":"French","y":3,"bp":75,"ps":"verb","r":"French recruter, from Latin recrescere, 'to grow again' — new growth for the group.","h":"ReCRUIT means grow your CREW — sign up new members.","nt":"vocab-NWFinal-2026-Junior"},{"w":"rectify","d":"is to make or set right","s":"The store manager promised to rectify the billing mistake immediately, refunding the overcharged amount and offering the frustrated customer a discount on their next purchase as an apology.","p":"r-EH-k-t-uh-f-ay","o":"French","y":4,"bp":66,"m":"rectafy","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin rectus = straight + facere = to make","h":"To RECTIFY a wrong, you make it straight — RECT means straight, -IFY means make."},{"w":"sedentary","d":"requiring sitting or little activity","s":"The doctor warned that a sedentary lifestyle of sitting all day without exercise could lead to serious health problems over time.","p":"SEH-duh-nteh-ree","o":"Latin","y":3,"bp":34,"m":"sedenterry","sy":"sed.en.ta.ry","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin sedere = to sit","h":"SEDENtary: you SIT like you're SED(ated) — no movement."},{"w":"sediment","d":"matter that has been deposited by some natural process","s":"After the floodwaters receded, a thick layer of brown sediment coated the floors of every house in the neighborhood.","p":"SEH-duh-muhnt","o":"Latin","y":3,"bp":32,"m":"sedimant","sy":"sed.i.ment","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin sedimentum = settling, from sedere = to sit/settle","h":"SEDIment SETTLES — both start with SE and involve sinking down."},{"w":"sensibility","d":"mental responsiveness and awareness","s":"Cruelty offended his sensibility.","p":"seh-nsih-BIH-lih-tee","o":"Latin","y":3,"bp":37,"m":"sensability","sy":"seh.nsih.bih.lih.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin sensibilis = capable of feeling + -ity = state of","h":"SENSIBILITY hides SENSIBLE — drop the E from SENSIBLE and add ITY: sensiBLE → sensiBILITY."},{"w":"separable","d":"Able to be separated or taken apart","s":"The hood is separable from the jacket, so I unzipped it on the warm day.","p":"SEH-per-uh-buhl","o":"Latin","y":3,"bp":65,"ps":"adjective","r":"Latin separare, 'to pull apart' + -able.","h":"SEPARable = able to SEPARATE — it comes apart.","nt":"vocab-NWFinal-2026-Junior"},{"w":"sequential","d":"in regular succession without gaps","s":"The recipe required sequential steps that had to be followed in exact order; skipping even one early stage could ruin the entire dish and waste every ingredient that came after.","p":"suh-KWEH-nshuhl","o":"Latin","y":3,"bp":34,"m":"sequencial","sy":"sah.kweh.nchah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin sequi = to follow","h":"SEQUENTIAL ends in -TIAL not -CIAL — think 'The Incredible Arrangement Leads' forward step by step."},{"w":"sergeant","d":"a noncommissioned officer above the rank of corporal","s":"The sergeant ordered his squad to march in formation across the muddy field.","p":"s-AH-r-j-uh-n-t","o":"English","y":4,"bp":63,"m":"sargeant","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old French sergent, from Latin servire = to serve","h":"A SERGEANT SERves with GRIT — spell it ser-GE-ANT, with an E not an A in the first syllable."},{"w":"sergeant-at-arms","d":"An officer who keeps order at meetings of a club or lawmaking group","s":"As sergeant-at-arms, Leo quiets the room when student council begins.","p":"SAR-junt-at-ARMZ","o":"French","y":4,"bp":65,"ps":"noun","r":"From Old French sergent, 'servant' (Latin servire), an armed officer serving assemblies.","h":"The sergeant-AT-ARMS guards the meeting — the order-keeper.","nt":"vocab-NWFinal-2026-Junior"},{"w":"servile","d":"Acting like a slave; too eager to obey and please others","s":"He gave the team captain servile compliments, hoping to be picked first.","p":"SER-vyl","o":"Latin","y":4,"bp":75,"ps":"adjective","r":"Latin servilis, from servus, 'slave' — same root as 'servant.'","h":"SERVile people over-SERVE — bowing and obeying like a servant.","nt":"vocab-NWFinal-2026-Junior"},{"w":"severely","d":"to a severe or serious degree","p":"suh-VIH-rlee","o":"Latin","y":3,"bp":32,"m":"severley","sy":"sah.vih.rliy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adverb","r":"Latin severus = strict","h":"SEVERELY: SEVERE plus LY — the punishment was SEVERE, delivered SEVERELY, E before LY."},{"w":"shackle","d":"A metal ring or chain that fastens around a prisoner's wrist or ankle","s":"The museum displayed an old iron shackle from a pirate ship's jail.","p":"SHA-kuhl","o":"Old English","y":3,"bp":70,"ps":"noun","r":"Old English sceacel, 'fetter, chain link.'","h":"A SHACKLE is a locking chain cuff — it stops you from moving free.","nt":"vocab-NWFinal-2026-Junior"},{"w":"shiftless","d":"Lazy and lacking ambition; not trying to do anything useful","s":"The shiftless character in the story napped all day while others worked.","p":"SHIFT-lus","o":"Old English","y":4,"bp":70,"ps":"adjective","r":"Shift once meant 'to manage, get things done' + -less, 'without.'","h":"SHIFTless = won't lift a finger or work a SHIFT — pure laziness.","nt":"vocab-NWFinal-2026-Junior"},{"w":"shriek","d":"A loud, sharp, high-pitched scream or cry","s":"She let out a shriek when the spider dropped onto her desk.","p":"SHREEK","o":"Norse","y":2,"bp":65,"ps":"noun","r":"Probably from Old Norse skrækja, 'to screech' — an imitation of the sound.","h":"A SHRIEK is a SHRill scream — EEK is right inside it.","nt":"vocab-NWFinal-2026-Junior"},{"w":"shroud","d":"Something that covers or hides, like a cloth or a layer of fog","s":"A shroud of morning mist hid the whole soccer field from view.","p":"SHROWD","o":"Old English","y":3,"bp":75,"ps":"noun","r":"Old English scrud, 'garment, clothing' — a covering cloth.","h":"A SHROUD covers like a cloud — wrapping something out of sight.","nt":"vocab-NWFinal-2026-Junior"},{"w":"shuffle","d":"the act of mixing cards haphazardly","s":"Before dealing the cards, Grandpa performed an impressive shuffle that made the deck impossible to predict.","p":"SHUH-fuhl","o":"German","y":2,"bp":38,"m":"shuffel","sy":"shuf.fle","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Low German schuffeln = to walk clumsily, to mix","h":"Shuffle has double F and ends in -LE, like trifle"},{"w":"siblings","d":"a person's brother or sister","s":"The three siblings argued over the remote control every Saturday morning until their parents stepped in.","p":"SIH-blihngz","o":"Old English","y":2,"bp":38,"m":"sibings","sy":"sib.lings","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old English sibling = relative, from sib = related","h":"SIBlings share a SIB (family bond)","t":["culinary","kinship"]},{"w":"sidelong","d":"Directed to the side; slanting sideways rather than straight ahead","s":"He gave his sister a sidelong glance to see if she was still mad.","p":"SYD-lawng","o":"Old English","y":3,"bp":70,"ps":"adjective","r":"From Old English side + -long (older -ling, 'in the direction of').","h":"SIDElong looks go aLONG the SIDE — a sneaky sideways peek.","nt":"vocab-NWFinal-2026-Junior"},{"w":"simile","d":"a figure of speech in which two unlike things are compared","s":"The poet used a vivid simile, writing that her smile was like the first ray of morning sunlight.","p":"SIM-ih-lee","o":"English","y":4,"bp":62,"m":"similey","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin similis = like, resembling","h":"A SIMILE ends in E — like a SMILE on the page when you compare two things cleverly."},{"w":"simplistic","d":"characterized by extreme and often misleading simplicity","s":"A simplistic theory of the universe.","p":"sih-MPLIH-stihk","o":"Latin","y":3,"bp":34,"m":"simplistick","sy":"sih.mplih.stih.k","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin simplus = simple","h":"SIMPLISTIC thinking is too SIMPLE — the word hides 'simple' inside, just with a '-tic' twist at the end.","t":["character"]},{"w":"site","d":"The place where something is located, happens, or will be built","s":"We visited the site where the new school gym will be built.","p":"SYT","o":"Latin","y":2,"bp":60,"ps":"noun","r":"Latin situs, 'position, place.'","h":"A SITE is a spot — a campsite is the place where you camp.","nt":"vocab-NWFinal-2026-Junior"},{"w":"situated","d":"determine or indicate the place, site, or limits of, as if by an instrument or by a survey","p":"SIH-choo-ay-tihd","o":"Latin","y":3,"bp":33,"m":"situaited","sy":"sih.chuw.ey.tih.d","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin situare = to place, from situs = place","h":"The house was SITUATED on a quiet SITE — no extra I sneaking in after the A.","t":["music"]},{"w":"sleek","d":"Smooth, shiny, and glossy; smoothly styled","s":"The otter's sleek fur glistened as it slid off the wet rock.","p":"SLEEK","o":"English","y":2,"bp":70,"ps":"adjective","r":"A Middle English variant of 'slick,' meaning smooth.","h":"SLEEK = SLICK and shiny, like a seal's smooth coat.","nt":"vocab-NWFinal-2026-Junior"},{"w":"sober","d":"Serious, calm, and sensible; not silly or playful","s":"The principal's sober voice told us the assembly news was important.","p":"SOH-ber","o":"Latin","y":3,"bp":70,"ps":"adjective","r":"Latin sobrius, 'moderate, sensible.'","h":"A SOBER face is a no-jokes face — calm and serious.","nt":"vocab-NWFinal-2026-Junior"},{"w":"solar","d":"Pertaining to the sun or powered by the sun's energy","s":"Our class built a tiny car that runs on solar power from the sun.","p":"SOH-ler","o":"Latin","y":2,"bp":65,"ps":"adjective","r":"Latin sol, 'sun' + -ar, 'relating to.'","h":"SOLar comes from SOL, the sun — solar panels drink sunlight.","nt":"vocab-NWFinal-2026-Junior","vh":"pertaining to"},{"w":"solvent","d":"A substance, usually a liquid, used to dissolve other substances","s":"Water is the solvent that dissolves the sugar in our lemonade.","p":"SAHL-vent","o":"Latin","y":3,"bp":75,"ps":"noun","r":"Latin solvere, 'to loosen, dissolve' — the liquid that loosens things apart.","h":"A SOLVent diSSOLVEs things — water melting sugar away.","nt":"vocab-NWFinal-2026-Junior","vh":"substance used to"},{"w":"sonar","d":"a measuring instrument that sends out an acoustic pulse in water and measures distances in terms of the time for the echo of the pulse to return","s":"The research vessel used sonar to map the ocean floor and locate shipwrecks hundreds of meters below the surface.","p":"SOH-nahr","y":3,"bp":39,"sy":"sow.naa.r","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Acronym: Sound Navigation And Ranging","h":"SONAR = Sound Navigation And Ranging — the acronym IS the word.","t":["music","numbers","time"],"vh":"apparatus to"},{"w":"spam","d":"Unwanted junk messages, especially emails sent to many people","s":"Dad deleted a folder full of spam about prizes he never won.","p":"SPAM","o":"English","y":2,"bp":60,"ps":"noun","r":"From the canned meat brand Spam, via a comedy sketch repeating the word endlessly.","h":"SPAM piles up like unwanted canned meat — junk email you never asked for.","nt":"vocab-NWFinal-2026-Junior"},{"w":"specify","d":"To state something clearly and exactly, giving the details","s":"Please specify which flavor of cupcake you want for the class party.","p":"SPEH-sih-fy","o":"Latin","y":3,"bp":70,"ps":"verb","r":"Latin species, 'kind, sort' + facere, 'to make' — to make the exact kind clear.","h":"SPECify gives the SPECifics — name it exactly.","nt":"vocab-NWFinal-2026-Junior"},{"w":"specimen","d":"an example regarded as typical of its class","s":"The biology teacher passed around a perfectly preserved beetle specimen so that every student could examine its iridescent shell.","p":"SPEH-suh-muhn","o":"Latin","y":3,"bp":73,"m":"speciman","sy":"spec.i.men","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin specimen = example, evidence, from specere = to look at","h":"specIMEN — the specimen is often studied by science MEN and women; ends in -MEN not -MAN"},{"w":"spherical","d":"of or relating to spheres or resembling a sphere","s":"Astronomers explained to the students that Earth is not perfectly spherical but rather slightly flattened at the poles and bulging at the equator due to the constant forces created by its rotation.","p":"SFEH-rih-kuhl","o":"Latin","y":3,"bp":33,"m":"sphereical","sy":"sfeh.rih.kah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Greek sphaira = ball, globe","h":"SPHERICAL has PH and ends in -ICAL — a sPHERical ball is perfectly ICAL-culated."},{"w":"spinous","d":"Covered with spines or thorns; sharp and prickly like a spine","s":"The spinous cactus poked right through my garden glove.","p":"SPY-nus","o":"Latin","y":4,"bp":65,"ps":"adjective","r":"Latin spinosus, 'thorny,' from spina, 'thorn, spine.'","h":"SPINous means full of SPINEs — prickly like a porcupine.","nt":"vocab-NWFinal-2026-Junior"},{"w":"spirited","d":"infuse with spirit","s":"The company spirited him up.","p":"SPIH-rih-tihd","o":"Latin","y":3,"bp":32,"m":"spiritid","sy":"spih.rah.tah.d","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin spiritus = breath, soul","h":"A spirited horse is full of spirit — just add -ed and keep all the spirit intact."},{"w":"spouse","d":"A husband or wife; the person someone is married to","s":"My teacher brought her spouse to the school's family picnic.","p":"SPOWS","o":"Latin","y":3,"bp":70,"ps":"noun","r":"Latin sponsus/sponsa, 'promised one,' from spondere, 'to pledge.'","h":"A SPOUSE said 'I do' — a marriage partner, husband or wife.","nt":"vocab-NWFinal-2026-Junior"},{"w":"stamina","d":"The strength and energy to keep going for a long time","s":"Running every morning built up her stamina for the mile race.","p":"STA-mih-nuh","o":"Latin","y":3,"bp":80,"ps":"noun","r":"Latin stamina, plural of stamen, 'thread' — the threads of life spun by the Fates.","h":"STAMINA keeps you STAnding to the finish — lasting energy.","nt":"vocab-NWFinal-2026-Junior"},{"w":"state-of-the-art","d":"Using the newest and most advanced technology or methods","s":"The new library has a state-of-the-art computer lab with 3D printers.","p":"STAYT-uv-thee-ART","o":"English","y":3,"bp":65,"ps":"adjective","r":"English phrase meaning 'the current state (level) of the art (skill or technology).'","h":"State-of-the-ART = the latest and greatest tech there is.","nt":"vocab-NWFinal-2026-Junior"},{"w":"status","d":"the relative position or standing of things or especially persons in a society","s":"He had the status of a minor.","p":"STA-tuhs","o":"Latin","y":3,"bp":70,"m":"statis","sy":"stae.tah.s","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin status = standing, position","h":"Your STATUS depends on where you STAND — STAT-US, as in how you STAND among US."},{"w":"steadfast","d":"Firm, loyal, and unchanging; not giving up","s":"Even when the team kept losing, her steadfast fans still cheered.","p":"STED-fast","o":"Old English","y":3,"bp":80,"ps":"adjective","r":"Old English stedefæst — 'fixed in place' (stede 'place' + fæst 'firm').","h":"STEADfast = STEADy and holding FAST — loyal no matter what.","nt":"vocab-NWFinal-2026-Junior"},{"w":"stereotyped","d":"treat or classify according to a mental stereotype","s":"I was stereotyped as a lazy Southern European.","p":"STEH-ree-uh-teyept","o":"Greek","y":3,"bp":36,"m":"steriotyped","sy":"steh.riy.ah.tay.pt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Greek stereos = solid + typos = impression/mold","h":"Once STEREOTYPED, you're stamped like a solid mold — STEREO+TYPE+D."},{"w":"stigma","d":"A mark of shame or disgrace attached to a person or thing","s":"Our counselor says there should be no stigma in asking for help.","p":"STIG-muh","o":"Greek","y":4,"bp":75,"ps":"noun","r":"Greek stigma, 'a mark made by a pointed tool, a brand.'","h":"A STIGMA is a shame STICKER — a bad mark others put on you.","nt":"vocab-NWFinal-2026-Junior"},{"w":"stipend","d":"A fixed, regular payment of money, often for work or study","s":"The library gives its summer teen helpers a small monthly stipend.","p":"STY-pend","o":"Latin","y":4,"bp":75,"ps":"noun","r":"Latin stipendium, 'soldier's pay' (stips 'small payment' + pendere 'to pay').","h":"A STIPEND is money you dePEND on — steady pay, like allowance.","nt":"vocab-NWFinal-2026-Junior"},{"w":"submerge","d":"To put or sink completely under water or another liquid","s":"The submarine can submerge deep below the ocean waves.","p":"sub-MERJ","o":"Latin","y":3,"bp":75,"ps":"verb","r":"Latin sub- 'under' + mergere 'to plunge, dip.'","h":"SUBmerge goes under like a SUBmarine — all the way beneath the water.","nt":"vocab-NWFinal-2026-Junior"},{"w":"submit","d":"To hand in something for others to review, or to give in to authority","s":"Remember to submit your book report before Friday's deadline.","p":"sub-MIT","o":"Latin","y":2,"bp":65,"ps":"verb","r":"Latin sub- 'under' + mittere 'to send' — to send under someone's judgment.","h":"SubMIT means send it in — homework goes up, your will bows down.","nt":"vocab-NWFinal-2026-Junior"},{"w":"submittal","d":"The act of handing something in; something that is submitted","s":"The science fair requires the submittal of your project form by March.","p":"sub-MIH-tuhl","o":"Latin","y":4,"bp":60,"ps":"noun","r":"From submit (Latin sub- + mittere 'to send') + -al, making it a noun.","h":"A subMITTAL is the act of subMITting — the official hand-in.","nt":"vocab-NWFinal-2026-Junior"},{"w":"subsidy","d":"Money given, usually by a government, to help support something","s":"A city subsidy helped the youth soccer league buy new uniforms.","p":"SUB-sih-dee","o":"Latin","y":4,"bp":75,"ps":"noun","r":"Latin subsidium, 'help, support, reserve troops.'","h":"A SUBSIDY is support money — cash slid under something to hold it up.","nt":"vocab-NWFinal-2026-Junior"},{"w":"superabundance","d":"A very great amount; much more than is needed","s":"Our garden produced a superabundance of zucchini, so we gave bags to neighbors.","p":"soo-per-uh-BUN-dents","o":"Latin","y":4,"bp":65,"ps":"noun","r":"Latin super- 'over, beyond' + abundare 'to overflow.'","h":"SUPER + ABUNDANCE = a SUPER-sized overflow, way more than enough.","nt":"vocab-NWFinal-2026-Junior"},{"w":"superficial","d":"concerned with or comprehending only what is apparent or obvious; not deep or penetrating emotionally or intellectually","p":"soo-per-FIH-shuhl","o":"Latin","y":3,"bp":36,"m":"superfitial","sy":"suw.per.fih.shah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin superficies = surface (super=above + facies=face)","h":"SUPERFICIAL means only surface-deep — spot the word 'face' hiding inside: super-FIC-ial, the face on the surface.","t":["emotions"]},{"w":"superfluous","d":"serving no useful purpose; having no excuse for being","p":"SOO-per-flwuhs","o":"Latin","y":3,"bp":34,"m":"superfulous","sy":"suw.per.flwah.s","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin superfluus = overflowing (super=over + fluere=to flow)","h":"SUPERFLUOUS things overflow uselessly — spot 'flu' flowing in the middle: super-FLU-ous."},{"w":"superintendent","d":"a person who oversees or directs some work","s":"The school superintendent visited every classroom to check on the new reading program.","p":"s-oo-p-ur-uh-n-t-EH-n-d-uh-n-t","o":"English","y":3,"bp":57,"m":"superintendant","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin superintendere = to oversee (super=over + intendere=to direct)","h":"The SUPERINTENDENT intends to oversee — spell 'intend' inside: super-INTEND-ent, ending in '-ent' not '-ant'."},{"w":"superlative","d":"an exaggerated expression (usually of praise)","s":"The art critic used every superlative she knew — magnificent, extraordinary, breathtaking — to describe the young painter's debut exhibition.","p":"suu-PUR-luh-tihv","o":"French","y":3,"bp":77,"m":"superlitive","sy":"su.per.la.tive","nt":"Open | North South Finals, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin superlativus = exaggerated, from super = above + latus = carried (past participle of ferre)","h":"A SUPERLATIVE goes SUPER above all others — remember SUPER at the start!"},{"w":"surety","d":"A guarantee or certainty; a person who promises to pay another's debt","s":"He offered his allowance as surety that he would return the borrowed game.","p":"SHUR-uh-tee","o":"French","y":4,"bp":70,"ps":"noun","r":"Old French seurte, from Latin securitas, 'safety, security.'","h":"SURety makes it SURE — a promise that backs someone up.","nt":"vocab-NWFinal-2026-Junior"},{"w":"surly","d":"Grumpy, rude, and unfriendly","s":"The surly cashier barely grunted when we said good morning.","p":"SUR-lee","o":"English","y":3,"bp":80,"ps":"adjective","r":"From Middle English sirly, 'lordly, haughty,' from 'sir' — proud turned rude.","h":"SURLY sounds like a growly 'GRRR-ly' mood — rude and cranky.","nt":"vocab-NWFinal-2026-Junior"},{"w":"surmount","d":"To overcome a difficulty; to get over or on top of something","s":"She had to surmount her stage fright before the vocabulary finals.","p":"ser-MOWNT","o":"French","y":4,"bp":80,"ps":"verb","r":"Old French sur- 'above' + monter 'to climb' — to climb above.","h":"SurMOUNT means climb the MOUNTain of a problem and stand on top.","nt":"vocab-NWFinal-2026-Junior"},{"w":"technique","d":"the manner in which the technical skills of a particular art are used","p":"t-eh-k-n-EE-k","o":"French","y":4,"bp":68,"m":"tecnique","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"noun","r":"French technique from Greek tekhne = art, skill","h":"TECHNIQUE ends in -IQUE like UNIQUE — a unique technique needs that silent QUE: T-E-C-H-N-I-Q-U-E."},{"w":"temper","d":"A person's usual mood, or a tendency to get angry","s":"He lost his temper when his little brother knocked over the block tower.","p":"TEM-per","o":"Latin","y":2,"bp":65,"ps":"noun","r":"Latin temperare, 'to mix in proper proportion' — the mix of moods in a person.","h":"A TEMPER is your anger thermometer — lose it and you boil over.","nt":"vocab-NWFinal-2026-Junior"},{"w":"tempo","d":"The speed at which music is played, or the pace of an activity","s":"The band teacher tapped her baton to set a faster tempo.","p":"TEM-poh","o":"Italian","y":3,"bp":70,"ps":"noun","r":"Italian tempo, 'time,' from Latin tempus.","h":"TEMPO is the TIME-beat of music — fast tempo, fast song.","nt":"vocab-NWFinal-2026-Junior"},{"w":"termination","d":"a coming to an end of a contract period","p":"ter-muh-NAY-shuhn","o":"Latin","y":3,"bp":36,"m":"terminiation","sy":"ter.mah.ney.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin terminus = end, boundary","h":"The TERMINATION of a contract ends at the NATION's border — both end in ‑ATION.","t":["law"]},{"w":"terrestrial","d":"of or relating to or inhabiting the land as opposed to the sea or air","p":"ter-EH-stree-uhl","o":"Latin","y":2,"bp":48,"m":"terrestrial","sy":"ter.eh.striy.ah.l","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin terrestris, from terra = earth","h":"TERRESTRIAL creatures live on TERRA (earth) — find TERRE + STRIAL and remember Earth is their TRIAL ground.","t":["waterways"]},{"w":"theorist","d":"someone who theorizes (especially in science or art)","s":"As a leading theorist in quantum physics, she developed bold ideas that challenged everything scientists thought they understood about matter.","p":"THEE-er-ihst","o":"Greek","y":3,"bp":32,"m":"theoriest","sy":"thiy.er.ih.st","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek theoria = contemplation","h":"A THEORIST builds theories — THEORY drops the Y, add IST: the IST person to have the idea.","vh":"One who"},{"w":"therapeutic","d":"a medicine or therapy that cures disease or relieves pain","s":"The doctor recommended therapeutic exercises to help the injured swimmer rebuild strength in her shoulder.","p":"theh-ruh-PYOO-tihk","o":"Latin","y":4,"bp":68,"m":"theraputic","sy":"ther.a.peu.tic","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek therapeutikos = inclined to serve, from therapeuein = to nurse","h":"THERAPEUTIC contains THERAPY—both help you heal","t":["body","disease","pharmacy"]},{"w":"thesaurus","d":"a dictionary of synonyms and antonyms","s":"She grabbed her thesaurus to find a more powerful word than good for her essay.","p":"th-uh-s-AW-r-uh-s","o":"English","y":4,"bp":66,"m":"theserous","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek thesauros=treasure, storehouse","h":"A thesAURUS is a treasure chest — AUR sounds like OR(e), precious like gold ore.","t":["wordwords"]},{"w":"thrive","d":"To grow strong and healthy; to do very well and succeed","s":"The tomato plants thrive in the sunny corner of our garden.","p":"THRYV","o":"Norse","y":2,"bp":75,"ps":"verb","r":"Old Norse thrifask, 'to grasp for oneself, prosper.'","h":"To THRIVE is to be very much aLIVE — growing and winning.","nt":"vocab-NWFinal-2026-Junior"},{"w":"tiara","d":"A small, jeweled crown worn on the head, especially by women","s":"The pageant winner wore a sparkling tiara during the parade.","p":"tee-AR-uh","o":"Persian","y":3,"bp":70,"ps":"noun","r":"From Persian via Greek tiara, an ancient headdress of Persian kings.","h":"A TIARA is a mini crown — princess headgear with jewels.","nt":"vocab-NWFinal-2026-Junior"},{"w":"tint","d":"A light shade of a color, or a small trace of color","s":"The painter added white to give the sky a soft pink tint.","p":"TINT","o":"Latin","y":2,"bp":65,"ps":"noun","r":"Latin tinctus, 'a dyeing,' from tingere, 'to dye.'","h":"A TINT is a tiny taste of color — a hint of pink.","nt":"vocab-NWFinal-2026-Junior"},{"w":"tolerant","d":"showing respect for the rights or opinions or practices of others","p":"TAH-ler-uhnt","o":"French","y":3,"bp":32,"m":"tolerent","sy":"taa.ler.ah.nt","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin tolerans = bearing, enduring","h":"A tolerANT ant bears a heavy load — '-ant', not '-ent'."},{"w":"toleration","d":"a disposition to tolerate or accept people or situations","s":"All people should practice toleration and live together in peace.","p":"tah-ler-AY-shuhn","o":"Latin","y":3,"bp":35,"m":"tolleration","sy":"taa.ler.ey.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin toleratio = endurance","h":"TOLERATION: one 'l', then '-ation' — the nation needs tollerATION? No, tolerATION!","t":["character"]},{"w":"torso","d":"The main part of the body, not counting the head, arms, and legs","s":"The art teacher showed us how to sketch the torso before adding arms.","p":"TOR-soh","o":"Italian","y":3,"bp":70,"ps":"noun","r":"Italian torso, 'stalk, stump,' from Greek thyrsos, 'stem.'","h":"The TORSO is your trunk — the body's middle without limbs or head.","nt":"vocab-NWFinal-2026-Junior"},{"w":"traditional","d":"consisting of or derived from tradition","s":"Every year at the harvest festival, the village elders performed the traditional dance that their ancestors had passed down through countless generations of celebration and gratitude.","p":"truh-DIH-shuh-nuhl","o":"Latin","y":3,"bp":36,"m":"tradtional","sy":"trah.dih.shah.nah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin traditio = a handing over","h":"TRADITIONAL = TRADITION + AL — all the letters of tradition, plus AL at the end.","t":["festivals"]},{"w":"tranquil","d":"free from disturbance; calm and peaceful","p":"t-r-A-ng-k-w-uh-l","o":"Latin","y":4,"bp":67,"m":"trankwil","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin tranquillus = calm, quiet","h":"TRANQUIL ends in -QUIL like QUILL — imagine writing peacefully with a quiet quill."},{"w":"treacherous","d":"dangerously unstable and unpredictable","p":"TREH-cher-uhs","o":"French","y":3,"bp":34,"m":"treacherous — trecherous","sy":"treh.cher.ah.s","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Old French trechier = to cheat","h":"TREACHEROUS has REACH inside — a traitor will REACH into your back to betray you."},{"w":"treachery","d":"betrayal of a trust","s":"The king's closest advisor shocked the court with his sudden treachery and betrayal.","p":"TREH-cher-ee","o":"French","y":3,"bp":33,"m":"treachary","sy":"treh.cher.iy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Old French trechier = to cheat","h":"TREACHERY: a TREACHER-ous ERY — remember the -ERY ending, like trickERY and knavERY."},{"w":"triad","d":"A group or set of three related people or things","s":"The story follows a triad of friends who solve mysteries together.","p":"TRY-ad","o":"Greek","y":4,"bp":70,"ps":"noun","r":"Greek trias, 'group of three,' from treis, 'three.'","h":"TRIad starts with TRI — think tricycle: three of anything.","nt":"vocab-NWFinal-2026-Junior"},{"w":"tricycle","d":"a vehicle with three wheels that is moved by foot pedals","s":"The toddler proudly pedaled her bright red tricycle up and down the driveway all afternoon.","p":"TRIH-sih-kuhl","o":"Latin","y":3,"bp":32,"m":"tricicle","sy":"trih.sih.kah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek tri=three + kyklos=circle/wheel","h":"A TRI-CYCLE has THREE wheels making CYCLES on the road—tri then cycle, plain as pie.","t":["vehicles"]},{"w":"trinity","d":"A group of three people or things; a set of three","s":"The coach called our three fastest runners the team's winning trinity.","p":"TRIH-nih-tee","o":"Latin","y":3,"bp":70,"ps":"noun","r":"Latin trinitas, 'the number three, a triad,' from trini, 'three each.'","h":"TRInity = a TRIo — three joined together as one group.","nt":"vocab-NWFinal-2026-Junior","vh":"group of"},{"w":"tuition","d":"Money paid for teaching or instruction, especially at a school","s":"Her parents saved for years to pay the college tuition.","p":"too-IH-shun","o":"Latin","y":3,"bp":70,"ps":"noun","r":"Latin tuitio, 'guardianship, protection,' from tueri, 'to watch over.'","h":"TUITION is the fee for tutoring — pay to be taught.","nt":"vocab-NWFinal-2026-Junior"},{"w":"typify","d":"To be a perfect example of something; to show its typical qualities","s":"Her kindness to new students typifies the friendly spirit of our school.","p":"TIH-pih-fy","o":"Latin","y":4,"bp":70,"ps":"verb","r":"From type (Greek typos, 'model, impression') + -fy, 'to make.'","h":"To TYPify is to be the TYPical example — the model case.","nt":"vocab-NWFinal-2026-Junior"},{"w":"tyrannical","d":"marked by unjust severity or arbitrary behavior","s":"The tyrannical class president canceled all school events without asking anyone's opinion, making every student furious.","p":"ter-A-nih-kuhl","o":"Greek","y":3,"bp":35,"m":"tyranical","sy":"ty.ran.ni.cal","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Greek tyrannos = absolute ruler, tyrant","h":"A TYRANT is TYRANNICAL—double N like a double dose of cruelty"},{"w":"tyranny","d":"Cruel and unfair rule by a leader with total power","s":"The colonists rebelled against the tyranny of the distant king.","p":"TEER-uh-nee","o":"Greek","y":3,"bp":80,"ps":"noun","r":"Greek tyrannos, 'absolute ruler' — rule by a tyrant.","h":"TYRANNY is a TYRANT's rule — think T. rex bossing everyone cruelly.","nt":"vocab-NWFinal-2026-Junior"},{"w":"ultimate","d":"the finest or most superior quality of its kind","s":"The ultimate in luxury.","p":"UH-ltuh-muht","o":"Latin","y":3,"bp":32,"m":"ultimite","sy":"ah.ltah.mah.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin ultimatus = final, last","h":"The ultiMATE is the greatest — your MATE who is the LAST word in excellence."},{"w":"ultimatum","d":"a final peremptory demand","s":"The coach gave the team an ultimatum: show up to every practice on time or lose your starting position before the championship game.","p":"uh-ltuh-MAY-tuhm","o":"Latin","y":3,"bp":34,"m":"ultimateum","sy":"ul.ti.ma.tum","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin ultimatus = last/final, from ultimus (farthest/last)","h":"An ultimatum is the ULTIMATE (last) demand — both start with ULTIM."},{"w":"ultra","d":"Going beyond the usual; extreme in degree","s":"He is ultra careful with his trading cards, keeping each in a sleeve.","p":"UL-truh","o":"Latin","y":3,"bp":60,"ps":"adjective","r":"Latin ultra, 'beyond, on the far side.'","h":"ULTRA means beyond the max — ultra-fast is faster than fast.","nt":"vocab-NWFinal-2026-Junior"},{"w":"ultrasonic","d":"having frequencies above those of audible sound","s":"The ultrasonic pest repeller emits sound waves that humans cannot hear but that drive mice away.","p":"uh-ltruh-SAH-nihk","o":"Latin","y":3,"bp":35,"m":"ultrasonnic","sy":"ah.ltrah.saa.nih.k","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin ultra = beyond + Greek sonos = sound","h":"ULTRASONic is BEYOND SOUND — one N in sonic, just like one eardrum can't even hear it.","vh":"pertaining to"},{"w":"unaffected","d":"undergoing no change when acted upon","s":"Entirely unaffected by each other's writings.","p":"uh-nuh-FEH-ktihd","o":"Latin","y":3,"bp":35,"m":"unafected","sy":"ah.nah.feh.ktih.d","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin afficere = to act upon","h":"Double-F: unAFFected — the AFFECT bounced off with both F's and left no mark."},{"w":"unalloyed","d":"free from admixture","s":"The children felt unalloyed joy when they arrived at the fair and discovered every ride was free that day, giving them hours of pure, uncomplicated happiness with absolutely nothing to worry about.","p":"uh-NA-loyd","o":"Latin","y":3,"bp":33,"m":"unaloyed","sy":"ah.nae.loy.d","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"French alloi = mixture of metals","h":"Double-L pure joy — unALLoyed happiness has double the L and zero impurities."},{"w":"unavailing","d":"producing no result or effect","s":"Despite hours of unavailing effort to restart the engine in the freezing cold, the stranded hikers finally accepted that they would need to call for outside help to get home.","p":"uh-nuh-VAY-lihng","o":"Latin","y":3,"bp":35,"m":"unavailng","sy":"ah.nah.vey.lih.ng","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin valere = to be strong/worthy","h":"Your efforts are unAVAILing when they AVAIL nothing — think of sailing with no wind."},{"w":"undervalue","d":"assign too low a value to","p":"UH-nder-va-lyoo","o":"Latin","y":3,"bp":35,"m":"undervalu","sy":"ah.nder.vae.lyuw","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin valere = be worth","h":"Don't underVALUE the E at the end — VALUE always ends in U-E."},{"w":"underworld","d":"The world of criminals, or the mythical land of the dead below the earth","s":"In Greek myths, Hades rules the underworld beneath the earth.","p":"UN-der-wurld","o":"Old English","y":3,"bp":65,"ps":"noun","r":"Old English under + weorold — the world beneath ours.","h":"The UNDERworld lies UNDER us — home of myths' dead or hidden criminals.","nt":"vocab-NWFinal-2026-Junior"},{"w":"unerring","d":"Always accurate; never making a mistake","s":"With unerring aim, she sank ten free throws in a row.","p":"un-EHR-ing","o":"Latin","y":4,"bp":75,"ps":"adjective","r":"Un- 'not' + err, from Latin errare, 'to wander, make a mistake.'","h":"UnERRing = never ERRs — zero errors, perfect every time.","nt":"vocab-NWFinal-2026-Junior"},{"w":"unilateral","d":"involving only one part or side","p":"yoo-nuh-LA-ter-uhl","o":"Latin","y":3,"bp":37,"m":"unilatteral","sy":"yuw.nah.lae.ter.ah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin unus = one + latus = side","h":"UNILATERAL: one LATER-AL side — one 't', one 'l' in later, keep it on one side."},{"w":"unlawful","d":"Against the law; not allowed by law","s":"Parking in front of a fire hydrant is unlawful in our town.","p":"un-LAW-ful","o":"Old English","y":2,"bp":60,"ps":"adjective","r":"Un- 'not' + Old English lagu, 'law' (borrowed from Norse) + -ful.","h":"UnLAWful breaks the LAW — illegal, plain and simple.","nt":"vocab-NWFinal-2026-Junior"},{"w":"unmindful","d":"Not paying attention; careless and forgetful of something","s":"Unmindful of the time, we played until the streetlights came on.","p":"un-MYND-ful","o":"Old English","y":3,"bp":65,"ps":"adjective","r":"Un- 'not' + Old English gemynd, 'memory, mind' + -ful.","h":"UnMINDful means your MIND isn't on it — not noticing or caring.","nt":"vocab-NWFinal-2026-Junior"},{"w":"unnecessary","d":"not necessary","s":"The teacher reminded students to avoid unnecessary details and stick to the main point.","p":"uh-NNEH-suh-seh-ree","o":"Latin","y":3,"bp":37,"m":"unneccessary","sy":"ah.nneh.sah.seh.riy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin 'necessarius' = unavoidable","h":"Unnecessary has one C and double S — 'Not necessary: one C, two S's, please.'"},{"w":"validate","d":"declare or make legally valid","s":"Before submitting the science fair project, the students needed to validate their hypothesis by conducting at least three separate experiments and carefully recording the results each time to ensure accuracy.","p":"VA-luh-dayt","o":"Latin","y":3,"bp":32,"m":"valllidate","sy":"vae.lah.dey.t","nt":"Open, vocab-NWFinal-2026-Junior","ps":"verb","r":"Latin validus = strong + -ate = to make","h":"To valiDATE is to give something a DATE stamp of approval — one L, one date.","t":["law"]},{"w":"valuation","d":"an appraisal of the value of something","s":"He set a high valuation on friendship.","p":"va-lyoo-AY-shuhn","o":"French","y":3,"bp":34,"m":"valuasion","sy":"vae.lyuw.ey.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"French valeur = value, from Latin valere = to be worth + -ation","h":"VALUATION ends in -ATION like estimation — both words are about sizing something up."},{"w":"vanquish","d":"To defeat or conquer completely","s":"The knight vowed to vanquish the dragon guarding the castle.","p":"VANG-kwish","o":"Latin","y":3,"bp":80,"ps":"verb","r":"Latin vincere, 'to conquer,' through Old French vainquir.","h":"VANquish makes the enemy VANish — total victory.","nt":"vocab-NWFinal-2026-Junior"},{"w":"vapor","d":"Tiny drops of moisture floating in the air, like mist, steam, or fog","s":"Vapor rose from the pot of soup bubbling on the stove.","p":"VAY-per","o":"Latin","y":2,"bp":65,"ps":"noun","r":"Latin vapor, 'steam, heat.'","h":"VAPOR is water gone airy — steam, mist, and fog.","nt":"vocab-NWFinal-2026-Junior"},{"w":"variable","d":"something that is likely to vary; something that is subject to variation","s":"The weather is one variable to be considered.","p":"VEH-ree-uh-buhl","o":"French","y":3,"bp":33,"m":"varable","sy":"veh.riy.ah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin variare = to change + -able","h":"VARIABLE: VARI+ABLE—it is ABLE to VARY, so keep both parts intact when you spell it."},{"w":"veer","d":"To change direction suddenly; to swerve","s":"The cyclist had to veer left to avoid the fallen branch.","p":"VEER","o":"French","y":3,"bp":75,"ps":"verb","r":"French virer, 'to turn' — used first for winds and ships changing course.","h":"VEER = swerVE — a sudden turn off your path.","nt":"vocab-NWFinal-2026-Junior"},{"w":"velocity","d":"distance travelled per unit time","s":"The science class measured the velocity of a rolling ball by timing how quickly it crossed a two-meter track.","p":"vuh-LAH-suh-tee","o":"Latin","y":3,"bp":33,"m":"velocety","sy":"vah.laa.sah.tiy","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin velox = swift","h":"VELOCITY is the state of being SWIFT — veloc + ity, never an E in the middle: V-E-L-O-C-I-T-Y.","t":["time"]},{"w":"venerable","d":"impressive by reason of age","s":"The venerable professor had taught at the university for fifty years and was loved by generations of students.","p":"VEH-ner-uh-buhl","o":"Latin","y":3,"bp":34,"m":"venereable","sy":"ven.er.a.ble","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin venerari = to worship, revere","h":"VENERABLE people deserve VENERATION — both share the root vener.","t":["logic"]},{"w":"venom","d":"Poison that some animals, like snakes, inject by biting or stinging","s":"A rattlesnake's venom flows through its fangs when it bites.","p":"VEH-num","o":"Latin","y":2,"bp":70,"ps":"noun","r":"Latin venenum, 'poison, magic potion.'","h":"VENOM is bite-poison — snakes and scorpions deliver it.","nt":"vocab-NWFinal-2026-Junior"},{"w":"verbiage","d":"overabundance of words","s":"The teacher asked Leon to cut the verbiage from his essay so the main argument would be clear and direct.","p":"VUR-bee-ihj","o":"French","y":1,"bp":40,"m":"verbage","sy":"ver.bi.age","nt":"Primary, vocab-NWFinal-2026-Junior","ps":"noun","r":"French verbier = to chatter, from Latin verbum = word","h":"Too many VERBs = VERBIAGE — too many words!","t":["wordwords"]},{"w":"verify","d":"To check and prove that something is true or correct","s":"The judge asked us to verify our answers before turning in the quiz.","p":"VEHR-ih-fy","o":"Latin","y":3,"bp":75,"ps":"verb","r":"Latin verus, 'true' + facere, 'to make' — to make sure it's true.","h":"VERify checks if it's VERY true — proof before you trust.","nt":"vocab-NWFinal-2026-Junior"},{"w":"viable","d":"Able to work or succeed; capable of living or growing","s":"Selling lemonade turned out to be a viable plan for raising club money.","p":"VY-uh-buhl","o":"French","y":4,"bp":75,"ps":"adjective","r":"French viable, from vie, 'life' (Latin vita) — able to live.","h":"VIable can surVIVE — a plan or seed with real life in it.","nt":"vocab-NWFinal-2026-Junior"},{"w":"vie","d":"To compete eagerly with others for something","s":"Twelve spellers will vie for the championship trophy on Saturday.","p":"VY","o":"French","y":4,"bp":80,"ps":"verb","r":"Shortened from envie, Old French envier, 'to challenge,' from Latin invitare.","h":"To VIE is to try for the prize — rivals vying to win.","nt":"vocab-NWFinal-2026-Junior","vh":"virtual reality"},{"w":"virtuous","d":"morally excellent","p":"VUR-choo-uhs","o":"Latin","y":3,"bp":32,"m":"virtueous","sy":"ver.chuw.ah.s","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin virtuosus = full of virtue","h":"VIRTUOUS = VIRTUE drops the 'e' and adds -OUS — no 'e' sneaking in before -ous."},{"w":"wavelet","d":"A small wave; a little ripple on water","s":"Tiny wavelets lapped against our toes at the edge of the lake.","p":"WAYV-let","o":"Old English","y":3,"bp":60,"ps":"noun","r":"Old English wafian, 'to wave' + -let, a French ending meaning 'small.'","h":"A waveLET is a LITTLE wave — -let means small, like piglet.","nt":"vocab-NWFinal-2026-Junior"},{"w":"wax","d":"To grow larger or stronger, as the moon does after a new moon","s":"We watched the moon wax bigger each night until it was full.","p":"WAKS","o":"Old English","y":3,"bp":70,"ps":"verb","r":"Old English weaxan, 'to grow, increase.'","h":"The moon WAXes as it maXes out — growing toward full.","nt":"vocab-NWFinal-2026-Junior"},{"w":"weak-kneed","d":"Lacking courage or determination; easily frightened or giving in","s":"Don't be weak-kneed on the diving board — take a breath and jump.","p":"WEEK-NEED","o":"Old English","y":3,"bp":65,"ps":"adjective","r":"From weak (Old Norse veikr) + knee (Old English cneow) — knees buckling from fear.","h":"WEAK-KNEED knees wobble in fear — no backbone, no courage.","nt":"vocab-NWFinal-2026-Junior"},{"w":"wearisome","d":"Causing tiredness or boredom; tiring and dull","s":"The wearisome car ride felt like it would never end.","p":"WEER-ee-sum","o":"Old English","y":3,"bp":70,"ps":"adjective","r":"Old English werig, 'tired' + -some, 'causing' — causing weariness.","h":"WEARIsome things make you WEARY — so boring you yawn.","nt":"vocab-NWFinal-2026-Junior"},{"w":"wee","d":"Very small; tiny","s":"A wee mouse darted under the kitchen cabinet.","p":"WEE","o":"Old English","y":2,"bp":60,"ps":"adjective","r":"Old English wæge, 'a small weight or amount,' kept alive in Scottish speech.","h":"WEE is teeny — a wee bit means just a tiny bit.","nt":"vocab-NWFinal-2026-Junior"},{"w":"wholly","d":"Completely; entirely; totally","s":"I am wholly convinced our team will win the quiz bowl.","p":"HOHL-lee","o":"Old English","y":3,"bp":65,"ps":"adverb","r":"From Old English hal, 'whole, entire' + -ly.","h":"WHOLly = the WHOLE way — one hundred percent.","nt":"vocab-NWFinal-2026-Junior"},{"w":"wince","d":"is to draw back or tense the body","p":"w-IH-n-s","o":"English","y":4,"bp":59,"m":"wints","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"verb","r":"Old French guencir = to turn aside","h":"You WINCE at the PINCH — WINCE ends in -NCE just like PRINCE and MINCE.","vh":"word processor"},{"w":"working-man","d":"A man who works for wages, especially doing physical labor","s":"Grandpa was a working-man who built houses for forty years.","p":"WUR-king-man","o":"Old English","y":2,"bp":55,"ps":"noun","r":"Old English weorc, 'work' + mann, 'person' — a laborer for pay.","h":"A WORKING-MAN earns by the sweat of his hands — a wage laborer.","nt":"vocab-NWFinal-2026-Junior"},{"w":"workmanship","d":"The skill and quality shown in making something","s":"The judges praised the fine workmanship of her hand-carved birdhouse.","p":"WURK-mun-ship","o":"Old English","y":3,"bp":70,"ps":"noun","r":"Old English weorc 'work' + mann 'person' + -scipe 'state or skill of.'","h":"WORKMANSHIP is how well the WORK was done — craft you can see.","nt":"vocab-NWFinal-2026-Junior"},{"w":"worm","d":"To move or wriggle slowly and sneakily, or to work into gradually","s":"He tried to worm his way to the front of the lunch line.","p":"WURM","o":"Old English","y":2,"bp":60,"ps":"verb","r":"Old English wyrm, 'serpent, crawling creature' — to move like one.","h":"To WORM is to wriggle like a worm — squeezing in sneakily.","nt":"vocab-NWFinal-2026-Junior"},{"w":"zoological","d":"is of or pertaining to zoology","s":"The zoological research team spent months in the rainforest documenting every species they encountered, from rare tree frogs to previously unrecorded insects, adding dozens of new entries to the scientific record.","p":"z-oo-l-AH-j-ih-k-uh-l","o":"English","y":4,"bp":68,"m":"zoologicial","nt":"Advanced, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Greek zoion = animal + logos = study","h":"ZOOLOGICAL = ZOO + LOGICAL—it's logical to study animals at the zoo: Z-O-O-L-O-G-I-C-A-L.","t":["animals"],"vh":"pertaining to .... .... .... .... .... .... .... ...."},{"w":"surname","d":"A person's family name or last name","s":"Write your surname first on the test, then your first name.","p":"SUR-naym","o":"French","y":3,"bp":70,"ps":"noun","r":"Old French sur- 'above, over' + nom 'name' — a name added over your given one.","h":"Your SURname is SURely shared by your family — the last name.","nt":"vocab-NWFinal-2026-Junior"},{"w":"susceptible","d":"(often followed by `of' or `to') yielding readily to or capable of","p":"suh-SEH-ptuh-buhl","o":"Latin","y":3,"bp":36,"m":"susceptable","sy":"sah.seh.ptah.bah.l","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin suscipere = to take up, susceptus = taken up","h":"susceptIBLE — end in -ible not -able; think 'I'll Be LEt in easily' — I-B-L-E for things easily taken up."},{"w":"sweep","d":"To clean a floor with a broom, or to move over an area quickly","s":"It's my job to sweep the kitchen floor after dinner.","p":"SWEEP","o":"Old English","y":2,"bp":55,"ps":"verb","r":"Old English swapan, 'to move swiftly, brush away.'","h":"SWEEP the floor in one SWooping motion of the broom.","nt":"vocab-NWFinal-2026-Junior"},{"w":"taboo","d":"Something forbidden by custom or society; not allowed to be done or discussed","s":"In some families, talking with your mouth full is strictly taboo.","p":"tuh-BOO","o":"English","y":3,"bp":75,"ps":"adjective","r":"From Tongan tabu, 'forbidden, sacred,' brought to English by Captain Cook.","h":"TABOO means 'don't you dare' — society's big forbidden no-no.","nt":"vocab-NWFinal-2026-Junior"},{"w":"tactician","d":"a person who is skilled at planning tactics","s":"The chess coach was a brilliant tactician who could see ten moves ahead and always outmaneuvered his opponents.","p":"ta-KTIH-shuhn","o":"Greek","y":3,"bp":33,"m":"tactision","sy":"tae.ktih.shah.n","nt":"Open, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek taktikos = fit for arranging","h":"A TACTICIAN is a TACTIC person — end with -IAN like a MUSICIAN who plans every move.","t":["character"]},{"w":"tally","d":"A count or record kept of points, votes, or things counted","s":"We kept a tally of goals on the whiteboard all season.","p":"TA-lee","o":"Latin","y":2,"bp":65,"ps":"noun","r":"Latin talea, 'stick' — counts were once notched on wooden sticks.","h":"A TALLY totals it up — tick marks counting the score.","nt":"vocab-NWFinal-2026-Junior"},{"w":"tangency","d":"The state of touching, especially of a line touching a curve at one point","s":"In math class we marked the point of tangency where the line touched the circle.","p":"TAN-jen-see","o":"Latin","y":4,"bp":65,"ps":"noun","r":"Latin tangere, 'to touch' + -ency, 'state of.'","h":"TANGency is the state of touching — a line kissing a circle once.","nt":"vocab-NWFinal-2026-Junior","vh":"state of"},{"w":"tangent","d":"A line that touches a curve at exactly one point without crossing it","s":"She drew a tangent that just touched the circle at a single point.","p":"TAN-jent","o":"Latin","y":4,"bp":70,"ps":"noun","r":"Latin tangens, 'touching,' from tangere, 'to touch.'","h":"A TANgent TAps the circle once — touch and go.","nt":"vocab-NWFinal-2026-Junior"},{"w":"tasteful","d":"Showing good judgment about what is attractive or appropriate","s":"The gym looked elegant with tasteful decorations for the awards night.","p":"TAYST-ful","o":"French","y":3,"bp":65,"ps":"adjective","r":"From Old French taster, 'to touch, sample' + -ful — full of good taste.","h":"TASTEful choices show good TASTE — classy, never gaudy.","nt":"vocab-NWFinal-2026-Junior"},{"w":"unprecedented","d":"having no precedent; novel","s":"An unprecedented expansion in population and industry.","p":"uh-NPREH-sih-deh-ntihd","o":"Latin","y":3,"bp":39,"m":"unprecidented","sy":"ah.npreh.sih.deh.ntih.d","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin praecedere = to go before","h":"unPRECEDented: no PRECEDE came before it — keep PRECE-D-E-N-T inside.","t":["poetry"]},{"w":"unsavory","d":"Unpleasant or morally offensive; disagreeable","s":"The story's unsavory villain cheated everyone in the village.","p":"un-SAY-vuh-ree","o":"French","y":4,"bp":75,"ps":"adjective","r":"Un- 'not' + savory, from Old French savoure, 'tasty' (Latin sapor, 'flavor').","h":"UnSAVORY leaves a bad taste — nasty food or a nasty character.","nt":"vocab-NWFinal-2026-Junior"},{"w":"unutterable","d":"too sacred to be uttered","p":"un-UT-er-uh-bul","o":"Latin","y":5,"bp":37,"sy":"un.ut.ter.able","ps":"adjective","r":"Latin: oinos (Latin)","h":"UN + UTTER + ABLE: 'utter' means to speak — unutterable means too great for words.","t":["religion"],"nt":"vocab-NWFinal-2026-Junior"},{"w":"unwarranted","d":"incapable of being justified or explained","s":"The principal agreed that the three-day suspension was unwarranted for such a minor rule violation and reduced the punishment to a single afternoon of after-school detention instead.","p":"uh-NWAW-ruh-ntihd","o":"Old French","y":3,"bp":36,"m":"unwaranted","sy":"ah.nwao.rah.ntih.d","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Old French warant = guarantee, protection","h":"UNWARRANTED has double R like WARRANT — a warrant has two R's, so does unwarranted."},{"w":"unwieldy","d":"Hard to handle, carry, or manage because of size, weight, or shape","s":"The unwieldy poster board kept flapping as I carried it to school.","p":"un-WEEL-dee","o":"Old English","y":4,"bp":75,"ps":"adjective","r":"Un- 'not' + Old English wieldan, 'to control, handle' — not handleable.","h":"UnWIELDy can't be WIELDed well — too big and awkward to carry.","nt":"vocab-NWFinal-2026-Junior"},{"w":"unwitting","d":"Not knowing or aware; done without realizing it","s":"He became an unwitting helper in the prank when he carried the box inside.","p":"un-WIH-ting","o":"Old English","y":4,"bp":75,"ps":"adjective","r":"Un- 'not' + Old English witan, 'to know' — not knowing.","h":"UnWITting means your WITs weren't in on it — clueless by accident.","nt":"vocab-NWFinal-2026-Junior"},{"w":"utmost","d":"The greatest or highest amount or degree possible","s":"Handle the science fair volcano with the utmost care.","p":"UT-mohst","o":"Old English","y":3,"bp":70,"ps":"adjective","r":"Old English utemest, 'outermost' — the farthest limit.","h":"UTMOST is the MOST possible — maxed all the way out.","nt":"vocab-NWFinal-2026-Junior"},{"w":"utopia","d":"a book written by Sir Thomas More (1516) describing the perfect society on an imaginary island","s":"In her story, the characters discover a utopia where there is no poverty, war, or pollution.","p":"yoo-TOH-pee-uh","o":"Latin","y":2,"bp":44,"m":"utopeia","sy":"yuw.tow.piy.ah","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Greek ou = not + topos = place","h":"UTOPIA is NO PLACE — Greek 'u' (not) + 'topia' (place); end it simply with '-ia', not '-eia'.","t":["landforms"]},{"w":"vacuum","d":"the absence of matter","s":"Astronauts must wear special suits in space because the vacuum of space has no air to breathe.","p":"VA-kyoom","o":"Latin","y":3,"bp":43,"sy":"vae.kyuw.m","nt":"Junior, vocab-NWFinal-2026-Junior","ps":"noun","r":"Latin 'vacuum' = empty space, neuter of 'vacuus' = empty, from 'vacare' = to be empty","h":"VACUUM has two U's — picture a U-shaped empty space inside another U"},{"w":"vainglorious","d":"feeling self-importance","s":"The vainglorious knight boasted about his victories so loudly that even his allies grew tired of listening.","p":"vayn-GLAWR-ee-uhs","o":"Latin","y":3,"bp":37,"m":"vaingloriuos","sy":"vayn.glawr.ee.uhs","nt":"Open, vocab-NWFinal-2026-Junior","ps":"adjective","r":"Latin vanus = empty + gloria = glory","h":"VAINGLORIOUS = VAIN + GLORY + OUS — someone so vain they bask in empty glory.","vh":".... .... .... .... .... .... .... .... .... .... .... .... .... ...."}]};
